const FOOTER_FIELD_KEYS = new Set([
  'subtotal_amount','discounts_amount','tax_amount','invoice_total','deposit','balance',
  'payment_method','payment_status'
]);
const BOTTOM_ANCHOR_FIELD_KEYS = new Set([
  'subtotal_amount','discounts_amount','tax_amount','invoice_total','deposit','balance',
  'payment_method','payment_status'
]);

function showTab(id){
  const sections = [els.docDashboard, els.extractedData, els.reports, els.findTextPanel, els.visualRunPanel];
  if(isSkinV2 && els.wizardManager){
    sections.push(els.wizardManager);
  }
  if(els.preconfiguredWizards){
    sections.push(els.preconfiguredWizards);
  }
  if(els.wizardExportPanel){
    sections.push(els.wizardExportPanel);
  }
  if(els.wizardDetailsPanel){
    sections.push(els.wizardDetailsPanel);
  }
  if(els.visionLearningPanel){
    sections.push(els.visionLearningPanel);
  }
  sections.forEach(sec => {
    if(sec) sec.style.display = sec.id === id ? 'block' : 'none';
  });
  els.tabs.forEach(btn => btn.classList.toggle('active', btn.dataset.target === id));
  if(id === 'wizard-manager'){
    renderWizardManagerList(state.activeWizardId);
  } else if(id === 'preconfigured-wizards'){
    renderPreconfiguredWizardList();
    loadPreconfiguredWizards();
  } else if(id === 'extracted-data'){
    syncExtractedWizardSelector();
    renderResultsTable();
    renderReports();
  } else if(id === 'vision-learning'){
    refreshLearningStats();
  }
  handleFindTextTab(id);
}

const viewerHome = {
  parent: els.viewer?.parentElement || null,
  nextSibling: els.viewer?.nextSibling || null
};

const debugFindTextAdapter = window.DebugFindTextAdapter?.createFindTextAdapter
  ? window.DebugFindTextAdapter.createFindTextAdapter()
  : null;
const debugVisualRunAdapter = window.DebugVisualRunAdapter?.createVisualRunAdapter
  ? window.DebugVisualRunAdapter.createVisualRunAdapter()
  : null;

function moveViewerToHost(host){
  if(!els.viewer || !host) return;
  if(els.viewer.parentElement !== host){
    host.appendChild(els.viewer);
  }
}

function restoreViewerHome(){
  if(!viewerHome.parent || !els.viewer) return;
  if(els.viewer.parentElement !== viewerHome.parent){
    viewerHome.parent.insertBefore(els.viewer, viewerHome.nextSibling);
  }
}

function handleFindTextTab(activeId){
  const isFindText = activeId === 'find-text';
  const isVisualRun = activeId === 'visual-run';
  const isLearning = activeId === 'vision-learning';
  if(!state.debugSandbox){
    state.debugSandbox = { findTextSession: null, visualRunSession: null };
  }
  if(isFindText){
    if(!state.debugSandbox.findTextSession && debugFindTextAdapter?.beginSession){
      state.debugSandbox.findTextSession = debugFindTextAdapter.beginSession();
    }
    moveViewerToHost(els.findTextViewerSlot);
    if(els.wizardSection) els.wizardSection.style.display = 'none';
  } else if(isVisualRun){
    moveViewerToHost(els.visualRunViewerSlot);
    if(els.wizardSection) els.wizardSection.style.display = 'none';
  } else if(isLearning){
    moveViewerToHost(els.learningViewerSlot);
    if(els.wizardSection) els.wizardSection.style.display = 'none';
    syncFeatureGraphLayerVisibilityUI();
  } else {
    // Leaving learning mode — clean up learning state if no session active
    if(state.learningActive && !_learningSession){
      state.learningActive = false;
      state.learningPendingBox = null;
    }
    if(state.debugSandbox.findTextSession && debugFindTextAdapter?.endSession){
      debugFindTextAdapter.endSession(state.debugSandbox.findTextSession);
      state.debugSandbox.findTextSession = null;
    }
    restoreViewerHome();
    syncFeatureGraphLayerVisibilityUI();
  }
  if(state.visualRun){
    const wasActive = !!state.visualRun.active;
    state.visualRun.active = isVisualRun;
    if(isVisualRun && !wasActive){
      prepareVisualRunContext();
    } else if(!isVisualRun && wasActive){
      restoreVisualRunContext();
    }
  }
}

function buildVisualRunField(){
  return {
    id: genId('field'),
    fieldType: 'static',
    name: '',
    order: 1,
    fieldKey: '',
    magicType: MAGIC_DATA_TYPE.ANY,
    magicDataType: MAGIC_DATA_TYPE.ANY,
    isGlobal: false
  };
}

function ensureVisualRunState(){
  if(!state.visualRun){
    state.visualRun = {
      active: false,
      wizardId: '',
      geometryId: DEFAULT_GEOMETRY_ID,
      field: null,
      template: null,
      fieldLocked: false,
      tokenSource: 'pdfjs',
      runBoxPx: null,
      runBoxCss: null,
      constellationBoxesPx: [],
      constellationBoxesCss: [],
      rawText: '',
      cleanedText: '',
      lastFile: null,
      configured: false,
      attempts: [],
      activeAttemptId: null,
      previousWizardId: null,
      previousGeometryId: null,
      previousSteps: null,
      previousStepIdx: 0,
      previousWizardComplete: false
    };
  }
  if(!state.visualRun.field){
    state.visualRun.field = buildVisualRunField();
  }
  if(!Array.isArray(state.visualRun.attempts)){
    state.visualRun.attempts = [];
  }
  if(!state.visualRun.activeAttemptId){
    state.visualRun.activeAttemptId = null;
  }
}

function setVisualRunStatus(message = ''){
  if(!els.visualRunStatus) return;
  els.visualRunStatus.textContent = message;
}

function createVisualRunAttemptId(){
  return `visualrun_${Date.now()}_${Math.random().toString(36).slice(2,8)}`;
}

function buildVisualRunAttemptDump(){
  const attempts = state.visualRun?.attempts || [];
  if(!attempts.length) return '(no attempts recorded)';
  try{
    return JSON.stringify({
      activeAttemptId: state.visualRun?.activeAttemptId || null,
      attempts
    }, null, 2);
  }catch(err){
    return `Attempt serialization failed: ${err?.message || err}`;
  }
}

function downloadVisualRunAttempts(){
  try{
    const text = buildVisualRunAttemptDump();
    const blob = new Blob([text], { type:'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `visual-run-attempts-${Date.now()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(()=>URL.revokeObjectURL(url), 1000);
  }catch(err){
    console.error('visual run attempt download failed', err);
    alert('Failed to download visual run attempt snapshot.');
  }
}

function recordVisualRunAttemptSnapshot(snapshot, { parentAttemptId = null } = {}){
  if(!snapshot || !state.visualRun) return null;
  const attempt = {
    ...snapshot,
    parentAttemptId: parentAttemptId || null
  };
  state.visualRun.attempts = [...(state.visualRun.attempts || []), clonePlain(attempt)];
  state.visualRun.activeAttemptId = attempt.attemptId;
  return attempt;
}

function renderVisualRunAttemptList(){
  if(!els.visualRunAttemptList) return;
  const attempts = state.visualRun?.attempts || [];
  if(!attempts.length){
    els.visualRunAttemptList.innerHTML = '<div class="sub">No attempts recorded yet.</div>';
    return;
  }
  const activeId = state.visualRun?.activeAttemptId;
  els.visualRunAttemptList.innerHTML = attempts.map(attempt => {
    const isActive = attempt.attemptId === activeId;
    const label = attempt.query?.raw ? `"${attempt.query.raw}"` : attempt.attemptId;
    const parent = attempt.parentAttemptId ? `branch of ${attempt.parentAttemptId}` : 'root';
    return `
      <div class="find-text-attempt-card ${isActive ? 'active' : ''}" data-attempt-id="${attempt.attemptId}">
        <div><strong>${label}</strong></div>
        <div class="sub">${attempt.source || 'unknown'} · ${parent}</div>
      </div>
    `;
  }).join('');
  els.visualRunAttemptList.querySelectorAll('.find-text-attempt-card').forEach(card => {
    card.addEventListener('click', () => {
      const attemptId = card.dataset.attemptId;
      if(!attemptId || !state.visualRun) return;
      state.visualRun.activeAttemptId = attemptId;
      renderVisualRunAttemptList();
      renderVisualRunAttemptSnapshot();
    });
  });
}

function renderVisualRunAttemptSnapshot(){
  if(!els.visualRunAttemptDetails) return;
  const attempts = state.visualRun?.attempts || [];
  const attempt = attempts.find(item => item.attemptId === state.visualRun?.activeAttemptId);
  if(!attempt){
    els.visualRunAttemptDetails.innerHTML = '<div class="sub">Select an attempt to view details.</div>';
    return;
  }
  const stage = attempt.stages || {};
  const cropPreview = stage.s5?.cropPreview;
  const cropMeta = stage.s5?.cropMeta || {};
  const cropErrors = cropMeta?.errors?.length ? `Errors: ${cropMeta.errors.join(', ')}` : 'Crop OK';
  els.visualRunAttemptDetails.innerHTML = `
    <div class="find-text-stage">
      <h5>S0 Search Input</h5>
      <div class="stage-meta">${attempt.source || 'unknown'} · ${attempt.matchMode || 'first'} · page ${attempt.page || 1}</div>
      <pre class="code">${JSON.stringify(stage.s0 || {}, null, 2)}</pre>
    </div>
    <div class="find-text-stage">
      <h5>S1 Candidate List</h5>
      <pre class="code">${JSON.stringify(stage.s1?.candidates || [], null, 2)}</pre>
    </div>
    <div class="find-text-stage">
      <h5>S2 Chosen Match</h5>
      <div class="stage-meta">${formatFindTextBox(stage.s2?.boxPx)}</div>
      <pre class="code">${JSON.stringify(stage.s2 || {}, null, 2)}</pre>
    </div>
    <div class="find-text-stage">
      <h5>S3 Constellation</h5>
      <pre class="code">${JSON.stringify(stage.s3 || {}, null, 2)}</pre>
    </div>
    <div class="find-text-stage">
      <h5>S4 Morphed Box</h5>
      <div class="stage-meta">${formatFindTextBox(stage.s4?.boxPx)}</div>
      <pre class="code">${JSON.stringify(stage.s4 || {}, null, 2)}</pre>
    </div>
    <div class="find-text-stage">
      <h5>S5 Crop Artifact</h5>
      <div class="stage-meta">${cropErrors}</div>
      ${cropPreview ? `<img src="${cropPreview}" alt="Crop preview" style="max-width:220px;border:1px solid var(--border);margin-bottom:8px;" />` : ''}
      <pre class="code">${JSON.stringify(cropMeta || {}, null, 2)}</pre>
    </div>
    <div class="find-text-stage">
      <h5>S6 Raw Extracted Text</h5>
      <pre class="code">${JSON.stringify(stage.s6 || {}, null, 2)}</pre>
    </div>
    <div class="find-text-stage">
      <h5>S7 Cleaned Text</h5>
      <pre class="code">${JSON.stringify(stage.s7 || {}, null, 2)}</pre>
    </div>
  `;
}

async function buildVisualRunAttemptSnapshot({ fieldSpec, result, tokens, page } = {}){
  if(!fieldSpec || !result || !tokens) return null;
  const attemptBox = result.boxPx || state.snappedPx;
  if(!attemptBox) return null;
  const visual = state.visualRun || {};
  const pageNum = attemptBox.page || page || fieldSpec.page || state.pageNum || 1;
  const vp = state.pageViewports[pageNum - 1] || state.viewport || { width: 1, height: 1 };
  const pageW = Math.max(1, Number(vp.width ?? vp.w ?? 1));
  const pageH = Math.max(1, Number(vp.height ?? vp.h ?? 1));
  const fieldLabel = visual.field?.name || fieldSpec.name || fieldSpec.fieldKey || 'visual run';
  const boxWithPage = { ...attemptBox, page: pageNum };
  const usedBoxPx = result.boxPx ? { ...result.boxPx, page: result.boxPx.page || pageNum } : boxWithPage;
  const constellationSnapshot = buildFindTextConstellationSnapshot({
    boxPx: boxWithPage,
    tokens,
    page: pageNum,
    pageW,
    pageH,
    constellationOverride: fieldSpec.keywordConstellation || null
  });
  const normBox = normalizeBox(usedBoxPx, pageW, pageH);
  const docId = state.currentFileId || state.currentFileName || state.currentFile?.name || '';
  const cropInfo = getOcrCropForSelection({
    docId,
    pageIndex: pageNum - 1,
    normBox
  });
  const cropPreview = cropInfo.cropBitmap?.toDataURL
    ? cropInfo.cropBitmap.toDataURL('image/png')
    : null;
  return {
    attemptId: createVisualRunAttemptId(),
    createdAt: new Date().toISOString(),
    documentId: docId,
    page: pageNum,
    source: 'visual-run',
    tokenSource: visual.tokenSource || 'pdfjs',
    query: {
      raw: fieldLabel,
      normalized: normalizeFindTextInput(fieldLabel)
    },
    matchMode: 'run',
    matchSource: 'visual-run',
    stages: {
      s0: {
        query: normalizeFindTextInput(fieldLabel),
        rawQuery: fieldLabel,
        tokenSource: visual.tokenSource || 'pdfjs'
      },
      s1: {
        candidates: []
      },
      s2: {
        chosenCandidateId: null,
        boxPx: clonePlain(boxWithPage)
      },
      s3: {
        constellation: constellationSnapshot.constellation,
        match: constellationSnapshot.match
      },
      s4: {
        boxPx: clonePlain(usedBoxPx),
        source: result.method || 'run'
      },
      s5: {
        cropMeta: cropInfo.meta,
        cropPreview
      },
      s6: {
        rawText: result.rawBeforeClean || result.raw || ''
      },
      s7: {
        cleanedText: result.value || '',
        correctedText: result.corrected || '',
        correctionsApplied: result.correctionsApplied || result.corrections || [],
        confidence: result.confidence ?? null
      }
    }
  };
}

function prepareVisualRunContext(){
  ensureVisualRunState();
  if(!state.debugSandbox){
    state.debugSandbox = { findTextSession: null, visualRunSession: null };
  }
  if(!state.debugSandbox.visualRunSession && debugVisualRunAdapter?.beginSession){
    state.debugSandbox.visualRunSession = debugVisualRunAdapter.beginSession();
  }
  if(state.visualRun.previousWizardId === null){
    state.visualRun.previousWizardId = state.activeWizardId;
    state.visualRun.previousGeometryId = state.activeGeometryId;
    state.visualRun.previousSteps = state.steps;
    state.visualRun.previousStepIdx = state.stepIdx;
    state.visualRun.previousWizardComplete = state.wizardComplete;
  }
  if(els.visualRunSourcePdf && !els.visualRunSourcePdf.checked && !els.visualRunSourceTess?.checked){
    els.visualRunSourcePdf.checked = true;
  }
  if(state.visualRun.template){
    activateVisualRunWizard();
  }
  renderVisualRunFieldRow();
  updateVisualRunPrompt();
  updateVisualRunOutputs();
  updateVisualRunControls();
  renderVisualRunAttemptList();
  renderVisualRunAttemptSnapshot();
}

function restoreVisualRunContext(){
  const visual = state.visualRun;
  if(!visual || visual.previousWizardId === null) return;
  if(state.debugSandbox?.visualRunSession && debugVisualRunAdapter?.endSession){
    debugVisualRunAdapter.endSession(state.debugSandbox.visualRunSession);
    state.debugSandbox.visualRunSession = null;
  }
  state.activeWizardId = visual.previousWizardId || state.activeWizardId;
  state.activeGeometryId = visual.previousGeometryId || state.activeGeometryId;
  state.steps = visual.previousSteps || state.steps;
  state.stepIdx = visual.previousStepIdx || 0;
  state.wizardComplete = visual.previousWizardComplete || false;
  if(visual.previousWizardId){
    ensureProfile(visual.previousWizardId, visual.previousGeometryId || null);
  }
  visual.previousWizardId = null;
  visual.previousGeometryId = null;
  visual.previousSteps = null;
  visual.previousStepIdx = 0;
  visual.previousWizardComplete = false;
}

function activateVisualRunWizard(){
  const visual = state.visualRun;
  if(!visual?.template) return;
  state.activeWizardId = visual.wizardId;
  state.activeGeometryId = visual.geometryId || DEFAULT_GEOMETRY_ID;
  state.profile = null;
  ensureProfile(visual.wizardId, visual.geometryId);
  state.steps = buildStepsFromTemplate(visual.template);
  state.stepIdx = 0;
  state.wizardComplete = false;
}

function updateVisualRunPrompt(){
  if(!els.visualRunPrompt) return;
  const step = state.steps?.[state.stepIdx] || null;
  els.visualRunPrompt.textContent = step?.prompt || 'Upload a document, then draw the field box.';
}

function renderVisualRunFieldRow(){
  if(!els.visualRunFieldRow) return;
  ensureVisualRunState();
  const visual = state.visualRun;
  const field = visual.field;
  els.visualRunFieldRow.innerHTML = '';
  let row = null;
  if(typeof BuilderFieldRow !== 'undefined' && typeof BuilderFieldRow.createFieldRow === 'function'){
    row = BuilderFieldRow.createFieldRow({
      field,
      index: 0,
      magicTypeOptions: MAGIC_DATA_TYPE,
      onDelete: () => {
        if(visual.fieldLocked) return;
        visual.field = buildVisualRunField();
        renderVisualRunFieldRow();
        updateVisualRunControls();
      },
      onChange: () => {
        if(els.visualRunFieldError) els.visualRunFieldError.style.display = 'none';
        updateVisualRunControls();
      },
      allowAreaType: false
    });
  }
  if(!row){
    row = document.createElement('div');
    row.className = 'custom-field-row';
    const nameInput = document.createElement('input');
    nameInput.value = field.name || '';
    nameInput.placeholder = 'Field name';
    nameInput.addEventListener('input', (e) => {
      field.name = e.target.value;
      if(els.visualRunFieldError) els.visualRunFieldError.style.display = 'none';
      updateVisualRunControls();
    });
    row.appendChild(nameInput);
  }
  const typeSelect = row.querySelector?.('.field-type');
  if(typeSelect){
    typeSelect.value = 'static';
    typeSelect.disabled = true;
    field.fieldType = 'static';
  }
  if(visual.fieldLocked){
    row.querySelectorAll('input, select, button').forEach(el => {
      if(el.classList.contains('delete-field-btn')) el.style.display = 'none';
      el.disabled = true;
    });
  }
  els.visualRunFieldRow.appendChild(row);
}

function updateVisualRunOutputs(){
  if(els.visualRunRawOutput) els.visualRunRawOutput.value = state.visualRun?.rawText || '';
  if(els.visualRunCleanedOutput) els.visualRunCleanedOutput.value = state.visualRun?.cleanedText || '';
}

function updateVisualRunControls(){
  ensureVisualRunState();
  const visual = state.visualRun;
  if(els.visualRunSaveFieldBtn){
    els.visualRunSaveFieldBtn.disabled = visual.fieldLocked;
    els.visualRunSaveFieldBtn.textContent = visual.fieldLocked ? 'Field saved' : 'Save Field';
  }
  const hasField = !!visual.template;
  const hasSource = !!(els.visualRunSourcePdf?.checked || els.visualRunSourceTess?.checked);
  const hasSelection = !!state.snappedPx;
  const hasFile = !!state.currentFileId;
  if(els.visualRunSaveExtractBtn){
    els.visualRunSaveExtractBtn.disabled = !(hasField && hasSource && hasSelection && hasFile);
  }
}

function setVisualRunTokenSource(source){
  const visual = state.visualRun;
  if(!visual) return;
  visual.tokenSource = source === 'tesseract' ? 'tesseract' : 'pdfjs';
  updateVisualRunControls();
}

async function getVisualRunTokens(pageNum){
  const visual = state.visualRun;
  const source = visual?.tokenSource || 'pdfjs';
  if(source === 'tesseract'){
    const tokens = await ensureTesseractTokensForPageWithBBox(pageNum);
    state.tokensByPage[pageNum] = tokens;
    return tokens;
  }
  return ensureTokensForPage(pageNum);
}

function normalizeTesseractTokensForPage(tokens = [], pageNum, options = {}){
  if(!Array.isArray(tokens) || !tokens.length) return [];
  const { scaleToCss = false } = options;
  const { scaleX = 1, scaleY = 1 } = getScaleFactors();
  const safeScaleX = scaleToCss && Number.isFinite(scaleX) && scaleX > 0 ? scaleX : 1;
  const safeScaleY = scaleToCss && Number.isFinite(scaleY) && scaleY > 0 ? scaleY : 1;
  const pageOffset = Number.isFinite(state.pageOffsets?.[pageNum - 1]) ? state.pageOffsets[pageNum - 1] : 0;
  return tokens.map(token => ({
    ...token,
    x: (token.x || 0) / safeScaleX,
    y: ((token.y || 0) - pageOffset) / safeScaleY,
    w: (token.w || 0) / safeScaleX,
    h: (token.h || 0) / safeScaleY,
    page: token.page || pageNum
  }));
}

function resolveVisualRunFieldSpec(){
  const fieldKey = state.visualRun?.template?.fields?.[0]?.fieldKey || '';
  const fields = state.profile?.fields || [];
  return fields.find(f => f.fieldKey === fieldKey) || fields[0] || null;
}

function buildVisualRunConstellationBoxes({ keywordConstellation, tokens, page, pageW, pageH, constellationMatch } = {}){
  if(!KeywordConstellation?.matchConstellation){
    return { boxesPx: [], match: null };
  }
  let match = constellationMatch || null;
  if(!match && keywordConstellation){
    const matched = KeywordConstellation.matchConstellation(keywordConstellation, tokens || [], {
      page,
      pageW,
      pageH,
      tolerance: keywordConstellation.tolerance
    });
    match = matched?.best || null;
  }
  const best = match;
  if(!best) return { boxesPx: [], match };
  const anchorToken = best.anchor || null;
  const supportTokens = (best.supportMatches || []).map(entry => entry?.token).filter(Boolean);
  const allTokens = [anchorToken, ...supportTokens].filter(Boolean);
  const boxesPx = allTokens.map(token => ({
    x: token.x,
    y: token.y,
    w: token.w,
    h: token.h,
    page: page || token.page || 1
  })).filter(isRenderableFindTextBox);
  return { boxesPx, match };
}

function toOverlayCssBox(boxPx){
  if(!boxPx) return null;
  const { scaleX = 1, scaleY = 1 } = getScaleFactors();
  return {
    x: boxPx.x / scaleX,
    y: boxPx.y / scaleY,
    w: boxPx.w / scaleX,
    h: boxPx.h / scaleY,
    page: boxPx.page
  };
}

function updateVisualRunOverlay({ boxPx, tokens, page, tokenSource, keywordConstellation, constellationMatch } = {}){
  const visual = state.visualRun;
  if(!visual) return;
  visual.runBoxPx = boxPx ? { ...boxPx } : null;
  visual.runBoxCss = boxPx ? toOverlayCssBox(boxPx) : null;
  visual.constellationBoxesPx = [];
  visual.constellationBoxesCss = [];
  if(Array.isArray(tokens) && tokens.length){
    const vp = state.pageViewports[page - 1] || state.viewport || {};
    const pageW = Math.max(1, Number(vp.width ?? vp.w ?? 1));
    const pageH = Math.max(1, Number(vp.height ?? vp.h ?? 1));
    const { boxesPx } = buildVisualRunConstellationBoxes({ keywordConstellation, tokens, page, pageW, pageH, constellationMatch });
    visual.constellationBoxesPx = boxesPx || [];
    visual.constellationBoxesCss = toFindTextConstellationCss(visual.constellationBoxesPx, { adjustForTesseract: tokenSource === 'tesseract' });
  }
  drawOverlay();
}

function clearVisualRunOverlays(){
  if(!state.visualRun) return;
  state.visualRun.runBoxPx = null;
  state.visualRun.runBoxCss = null;
  state.visualRun.constellationBoxesPx = [];
  state.visualRun.constellationBoxesCss = [];
  drawOverlay();
}

async function saveVisualRunField(){
  ensureVisualRunState();
  const visual = state.visualRun;
  const name = (visual.field?.name || '').trim();
  if(!name){
    if(els.visualRunFieldError) els.visualRunFieldError.style.display = 'block';
    return;
  }
  if(els.visualRunFieldError) els.visualRunFieldError.style.display = 'none';
  const baseField = {
    ...visual.field,
    id: visual.field.id || genId('field'),
    fieldType: 'static',
    name
  };
  const normalizedFields = normalizeTemplateFields([baseField]);
  const templateId = visual.wizardId || `visual-run-${Date.now()}`;
  const template = normalizeTemplate({
    id: templateId,
    wizardName: `Visual Run: ${name}`,
    documentTypeId: state.docType,
    version: PROFILE_VERSION,
    fields: normalizedFields
  });
  visual.template = template;
  visual.wizardId = template.id;
  visual.fieldLocked = true;
  visual.configured = false;
  activateVisualRunWizard();
  updateVisualRunPrompt();
  renderVisualRunFieldRow();
  updateVisualRunControls();
  setVisualRunStatus('Field saved. Upload a document and draw the box.');
}

async function captureVisualRunConfig(){
  const visual = state.visualRun;
  if(!visual?.template) return false;
  if(!state.snappedPx){
    alert('Draw a box first.');
    return false;
  }
  setWizardMode(ModeEnum.CONFIG);
  const step = state.steps?.[state.stepIdx] || null;
  if(!step){
    alert('No field configured.');
    return false;
  }
  const tokens = await getVisualRunTokens(state.pageNum);
  const tokensForExtraction = state.visualRun?.tokenSource === 'tesseract'
    ? normalizeTesseractTokensForPage(tokens, state.pageNum)
    : tokens;
  const res = await extractFieldValue(step, tokensForExtraction, state.viewport);
  let value = res.value || '';
  let raw = res.raw || '';
  let boxPx = res.boxPx || state.snappedPx;
  let confidence = res.confidence || 0;
  let corrections = res.correctionsApplied || res.corrections || [];
  let fieldTokens = res.tokens || [];
  if(!value && state.snappedText){
    value = (state.snappedText || '').trim();
    raw = raw || value;
  }

  const storedBoxPx = (isConfigMode() && step.type === 'static' && state.selectionPx)
    ? (state.selectionPx || boxPx)
    : boxPx;
  const vp = state.pageViewports[state.pageNum - 1] || state.viewport || { width: 1, height: 1 };
  const canvasW = (vp.width ?? vp.w) || 1;
  const canvasH = (vp.height ?? vp.h) || 1;
  const normBox = normalizeBox(storedBoxPx, canvasW, canvasH);
  const pct = { x0: normBox.x0n, y0: normBox.y0n, x1: normBox.x0n + normBox.wN, y1: normBox.y0n + normBox.hN };
  const rawBoxData = { x: storedBoxPx.x, y: storedBoxPx.y, w: storedBoxPx.w, h: storedBoxPx.h, canvasW, canvasH };
  const extras = {};
  if(step.type === 'static'){
    const keywordRelations = computeKeywordRelationsForConfig(step.fieldKey, storedBoxPx, normBox, state.pageNum, canvasW, canvasH);
    const keywordConstellation = (KeywordConstellation?.captureConstellation)
      ? KeywordConstellation.captureConstellation(step.fieldKey, storedBoxPx, normBox, state.pageNum, canvasW, canvasH, tokens, {})
      : null;
    const lm = captureRingLandmark(storedBoxPx);
    lm.anchorHints = ANCHOR_HINTS[step.fieldKey] || [];
    extras.landmark = lm;
    if(state.snappedLineMetrics){
      extras.lineMetrics = clonePlain(state.snappedLineMetrics);
    }
    extras.keywordRelations = keywordRelations || null;
    extras.keywordConstellation = keywordConstellation || null;
  } else if(step.type === 'column'){
    extras.column = buildColumnModel(step, pct, boxPx, tokens);
  }
  console.info('[visual-run][config] normalizeBox inputs', {
    storedBoxPx: clonePlain(storedBoxPx),
    canvasW,
    canvasH,
    viewport: clonePlain(vp),
    normBox: clonePlain(normBox)
  });
  applyEngineSelectionToProfile(state.profile, activeConfigEngine, { updateFields: true });
  upsertFieldInProfile(step, normBox, value, confidence, state.pageNum, extras, raw, corrections, fieldTokens, rawBoxData);
  const savedField = state.profile?.fields?.find(f => f.fieldKey === step.fieldKey) || null;
  console.info('[visual-run][config] saved field geometry', {
    fieldKey: step.fieldKey,
    bbox: clonePlain(savedField?.bbox || null),
    bboxPct: clonePlain(savedField?.bboxPct || null),
    rawBox: clonePlain(savedField?.rawBox || null)
  });
  visual.configured = true;
  return true;
}

async function runVisualRunExtraction(){
  const visual = state.visualRun;
  if(!visual?.template) return;
  setWizardMode(ModeEnum.RUN);
  ensureProfile(visual.wizardId, visual.geometryId);
  const fieldSpec = resolveVisualRunFieldSpec();
  if(!fieldSpec){
    alert('Unable to locate the field in the profile.');
    return;
  }
  console.info('[visual-run][run] loaded field geometry', {
    fieldKey: fieldSpec.fieldKey,
    bbox: clonePlain(fieldSpec.bbox || null),
    bboxPct: clonePlain(fieldSpec.bboxPct || null),
    rawBox: clonePlain(fieldSpec.rawBox || null)
  });
  const page = fieldSpec.page || state.pageNum || 1;
  state.pageNum = page;
  state.viewport = state.pageViewports[page - 1] || state.viewport;
  updatePageIndicator();
  state.matchPoints = [];
  const tokens = await getVisualRunTokens(page);
  const tokensForExtraction = visual.tokenSource === 'tesseract'
    ? normalizeTesseractTokensForPage(tokens, page)
    : tokens;
  const result = await extractFieldValue(fieldSpec, tokensForExtraction, state.viewport);
  const rawText = result.rawBeforeClean || result.raw || '';
  const cleanedText = result.value || '';
  visual.rawText = rawText;
  visual.cleanedText = cleanedText;
  updateVisualRunOutputs();
  updateVisualRunOverlay({
    boxPx: result.boxPx,
    tokens,
    page,
    tokenSource: visual.tokenSource,
    keywordConstellation: fieldSpec.keywordConstellation || null,
    constellationMatch: result.constellationMatch || null
  });
  const snapshot = await buildVisualRunAttemptSnapshot({
    fieldSpec,
    result,
    tokens: tokensForExtraction,
    page
  });
  const attempt = recordVisualRunAttemptSnapshot(snapshot, { parentAttemptId: null });
  if(attempt){
    renderVisualRunAttemptList();
    renderVisualRunAttemptSnapshot();
  }
  setVisualRunStatus('Run mode extraction complete.');
}

async function handleVisualRunSaveExtract(){
  const visual = state.visualRun;
  if(!visual?.template) return;
  const ok = await captureVisualRunConfig();
  if(!ok) return;
  await runVisualRunExtraction();
}

async function handleVisualRunFileChange(e){
  const file = e.target.files?.[0];
  if(!file) return;
  state.visualRun.lastFile = file;
  clearVisualRunOverlays();
  await openFile(file);
  updateVisualRunControls();
}

async function handleVisualRunNewFileChange(e){
  const file = e.target.files?.[0];
  if(!file) return;
  state.visualRun.lastFile = file;
  clearVisualRunOverlays();
  await openFile(file);
  if(state.visualRun?.template){
    await runVisualRunExtraction();
  }
}

function resetVisualRun(){
  const visual = state.visualRun;
  if(!visual) return;
  if(visual.wizardId){
    clearWizardArtifacts(state.username, state.docType, visual.wizardId);
  }
  visual.field = buildVisualRunField();
  visual.template = null;
  visual.wizardId = '';
  visual.fieldLocked = false;
  visual.configured = false;
  visual.rawText = '';
  visual.cleanedText = '';
  visual.lastFile = null;
  visual.tokenSource = 'pdfjs';
  visual.attempts = [];
  visual.activeAttemptId = null;
  clearVisualRunOverlays();
  state.profile = null;
  state.steps = [];
  state.stepIdx = 0;
  state.wizardComplete = false;
  setWizardMode(ModeEnum.CONFIG);
  resetDocArtifacts();
  if(els.pdfCanvas){
    const ctx = els.pdfCanvas.getContext('2d');
    ctx?.clearRect(0, 0, els.pdfCanvas.width, els.pdfCanvas.height);
  }
  if(els.imgCanvas){
    els.imgCanvas.removeAttribute('src');
  }
  if(els.visualRunRawOutput) els.visualRunRawOutput.value = '';
  if(els.visualRunCleanedOutput) els.visualRunCleanedOutput.value = '';
  if(els.visualRunFileInput) els.visualRunFileInput.value = '';
  if(els.visualRunNewFileInput) els.visualRunNewFileInput.value = '';
  if(els.visualRunSourcePdf) els.visualRunSourcePdf.checked = true;
  setVisualRunStatus('Visual Run reset.');
  renderVisualRunFieldRow();
  renderVisualRunAttemptList();
  renderVisualRunAttemptSnapshot();
  updateVisualRunPrompt();
  updateVisualRunControls();
}

