const modelSelect = document.getElementById('model-select');
if(modelSelect){
  modelSelect.addEventListener('change', ()=>{
    const val = modelSelect.value;
    let selectionLogged = false;
    if(!val){
      if(isSkinV2){
        alert('Select an existing wizard to run or create one in Wizard Manager.');
        showWizardManagerTab();
        populateModelSelect(undefined);
        selectionLogged = true;
      }
    } else if(val === DEFAULT_WIZARD_ID){
      if(isSkinV2){
        alert('Please create or choose a custom wizard in Wizard Manager.');
        showWizardManagerTab();
        populateModelSelect(undefined);
      } else {
        state.activeWizardId = DEFAULT_WIZARD_ID;
        state.activeGeometryId = DEFAULT_GEOMETRY_ID;
        state.profile = profileStore.loadProfile(state.username, state.docType, currentWizardId(), state.activeGeometryId);
        hydrateFingerprintsFromProfile(state.profile);
        alert('Default wizard selected.');
      }
    } else if(val.startsWith('custom:')){
      state.activeWizardId = val.replace('custom:','');
      state.activeGeometryId = DEFAULT_GEOMETRY_ID;
      state.profile = profileStore.loadProfile(state.username, state.docType, currentWizardId(), state.activeGeometryId);
      hydrateFingerprintsFromProfile(state.profile);
      if(isSkinV2){
        populateModelSelect(`custom:${state.activeWizardId}`);
      }
      alert('Custom wizard selected for run. Edit in Wizard Manager.');
    } else if(val.startsWith('model:')){
      const loaded = loadModelById(val.replace('model:',''));
      if(loaded?.wizardId){
        state.activeWizardId = loaded.wizardId;
      } else if(isSkinV2){
        state.activeWizardId = requireCustomWizard({ allowTemplateFallback: true, promptBuilder: false }) || state.activeWizardId || firstCustomWizardId();
        if(!state.activeWizardId){
          showWizardManagerTab();
        }
        populateModelSelect(state.activeWizardId ? `custom:${state.activeWizardId}` : undefined);
      }
      activateRunMode({ clearDoc: true });
      renderSavedFieldsTable();
      renderConfirmedTables();
      renderResultsTable();
      alert('Model selected. Drop files to auto-extract.');
    }
    if(!selectionLogged){
      logWizardSelection('change', resolveSelectedWizardContext());
    }
  });
}

async function handleFindTextFileChange(e){
  const f = e.target.files?.[0];
  if(!f) return;
  moveViewerToHost(els.findTextViewerSlot);
  state.selectionPx = null;
  state.selectionCss = null;
  state.findTextTessSelectionPx = null;
  state.findTextTessSelectionCss = null;
  state.findTextPdfSelectionsPx = [];
  state.findTextPdfSelectionsCss = [];
  state.findTextTessSelectionsPx = [];
  state.findTextTessSelectionsCss = [];
  state.findTextResults = { pdf: null, tess: null };
  clearFindTextConstellations();
  hideFindTextLearningPicker();
  clearFindTextInsights();
  resetFindTextStepper();
  state.findTextLearning.lastRun = null;
  state.findTextLearning.attempts = [];
  state.findTextLearning.activeAttemptId = null;
  state.findTextDebug = { pdf: null, tess: null, scale: null };
  renderFindTextDebug();
  renderFindTextAttemptList();
  renderFindTextAttemptSnapshot();
  setFindTextStatus('Loading document...');
  try{
    await openFile(f);
    setFindTextStatus('Document loaded. Enter text to highlight.');
    renderFindTextDebug();
    if(state.findTextLearning.lockEnabled && state.findTextLearning.lockedGeometry){
      setFindTextStatus('Document loaded. Applying locked geometry...');
      await runFindTextLockedGeometry();
    }
  } catch(err){
    console.error('Find text load failed', err);
    setFindTextStatus('Failed to load document. Try again.', 'error');
    renderFindTextDebug();
  }
}

async function handleFindTextSearch(){
  const query = normalizeFindTextInput(els.findTextInput?.value || '');
  if(!query){
    setFindTextStatus('Enter text to search.');
    return;
  }
  if(!state.currentFileId){
    setFindTextStatus('Upload a document first.', 'error');
    return;
  }
  const usePdf = els.findTextPdfToggle ? els.findTextPdfToggle.checked : true;
  const useTess = els.findTextTessToggle ? els.findTextTessToggle.checked : false;
  const findAll = els.findTextAllToggle ? els.findTextAllToggle.checked : false;
  const matchMode = els.findTextBestToggle?.checked ? 'best' : 'first';
  const includeCandidates = true;
  const learningEnabled = isFindTextLearningEnabled();
  const weights = getFindTextRankerWeights();
  const useRanker = learningEnabled && !!weights && matchMode === 'best';
  const rankerContext = { useRanker, weights, mode: matchMode };
  state.findTextLearning.enabled = learningEnabled;
  state.findTextLearning.lockEnabled = !!els.findTextLockToggle?.checked;
  if(!usePdf && !useTess){
    setFindTextStatus('Select PDF.js and/or Tesseract to search.', 'error');
    return;
  }
  setFindTextStatus(`Searching for "${query}"...`);
  state.selectionPx = null;
  state.selectionCss = null;
  state.findTextTessSelectionPx = null;
  state.findTextTessSelectionCss = null;
  state.findTextPdfSelectionsPx = [];
  state.findTextPdfSelectionsCss = [];
  state.findTextTessSelectionsPx = [];
  state.findTextTessSelectionsCss = [];
  state.findTextResults = { pdf: null, tess: null };
  clearFindTextConstellations();
  hideFindTextLearningPicker();
  resetFindTextStepper();
  state.findTextLearning.lastRun = null;
  state.findTextDebug = { pdf: null, tess: null, scale: null };
  let pdfResult = null;
  let tessResult = null;
  const statusBits = [];
  if(usePdf){
    if(findAll){
      pdfResult = await findTextOnPageAllOccurrences(query, {
        useTesseract: false,
        includeCandidates,
        rankerContext: { ...rankerContext, source: 'pdfjs' }
      });
      const count = pdfResult?.boxes?.length || 0;
      if(count){
        applyFindTextHighlights(pdfResult.boxes);
        state.findTextDebug.pdf = { boxesPx: pdfResult.boxes, matchSource: pdfResult.matchSource, tokens: pdfResult.tokens };
        statusBits.push(`PDF.js: ${count} match${count === 1 ? '' : 'es'} (page ${pdfResult.page})`);
      } else {
        const noTextLayer = pdfResult?.hasTextLayer === false;
        statusBits.push(`PDF.js: ${noTextLayer ? 'no text layer' : 'no match'}`);
        state.findTextDebug.pdf = { boxesPx: [], matchSource: pdfResult?.matchSource || null, tokens: pdfResult?.tokens || 0 };
      }
    } else {
      pdfResult = await findTextInDocument(query, {
        matchMode,
        includeCandidates,
        rankerContext
      });
      if(pdfResult?.box){
        applyFindTextHighlight(pdfResult.box);
        state.findTextDebug.pdf = { boxPx: pdfResult.box, matchSource: pdfResult.matchSource, tokens: pdfResult.tokens };
        statusBits.push(`PDF.js: page ${pdfResult.page}`);
      } else {
        const noTextLayer = pdfResult?.hasTextLayer === false;
        statusBits.push(`PDF.js: ${noTextLayer ? 'no text layer' : 'no match'}`);
        state.findTextDebug.pdf = { boxPx: null, matchSource: pdfResult?.matchSource || null, tokens: pdfResult?.tokens || 0 };
      }
    }
  }
  if(useTess){
    if(findAll){
      tessResult = await findTextOnPageAllOccurrences(query, {
        useTesseract: true,
        includeCandidates,
        rankerContext: { ...rankerContext, source: 'tesseract-bbox' }
      });
      const count = tessResult?.boxes?.length || 0;
      if(count){
        applyTesseractFindTextHighlights(tessResult.boxes);
        state.findTextDebug.tess = { boxesPx: tessResult.boxes, matchSource: tessResult.matchSource, tokens: tessResult.tokens };
        statusBits.push(`Tesseract: ${count} match${count === 1 ? '' : 'es'} (page ${tessResult.page})`);
      } else {
        statusBits.push('Tesseract: no match');
        state.findTextDebug.tess = { boxesPx: [], matchSource: tessResult?.matchSource || null, tokens: tessResult?.tokens || 0 };
      }
    } else {
      tessResult = await findTextInDocumentWithTesseract(query, {
        matchMode,
        includeCandidates,
        rankerContext
      });
      if(tessResult?.box){
        applyTesseractFindTextHighlight(tessResult.box);
        state.findTextDebug.tess = { boxPx: tessResult.box, matchSource: tessResult.matchSource, tokens: tessResult.tokens };
        statusBits.push(`Tesseract: page ${tessResult.page}`);
      } else {
        statusBits.push('Tesseract: no match');
        state.findTextDebug.tess = { boxPx: null, matchSource: tessResult?.matchSource || null, tokens: tessResult?.tokens || 0 };
      }
    }
  }
  const pdfHasMatch = findAll ? (pdfResult?.boxes?.length || 0) > 0 : !!pdfResult?.box;
  const tessHasMatch = findAll ? (tessResult?.boxes?.length || 0) > 0 : !!tessResult?.box;
  const hasMatches = pdfHasMatch || tessHasMatch;
  const learningEntries = learningEnabled
    ? collectFindTextLearningEntries({
      query,
      matchMode,
      findAll,
      useRanker,
      weights,
      pdfResult,
      tessResult
    })
    : [];
  if(learningEnabled){
    recordFindTextLearningRun(learningEntries);
    const totalCandidates = learningEntries.reduce((sum, entry) => sum + (entry.candidates?.length || 0), 0);
    const chosenId = learningEntries[0]?.chosenCandidateId || '<none>';
    console.info(`[find-text-learning] candidates=${totalCandidates} chosen=${chosenId} recorded=${learningEntries.length > 0}`);
  }
  const activeResult = (pdfHasMatch ? pdfResult : null) || (tessHasMatch ? tessResult : null);
  if(!hasMatches){
    setFindTextStatus(`No match found for "${query}". ${statusBits.join(' · ')}`, 'error');
    drawOverlay();
    renderFindTextDebug();
    return;
  }
  state.findTextResults = {
    pdf: pdfHasMatch
      ? { page: pdfResult.page || 1, boxes: findAll ? (pdfResult.boxes || []) : [pdfResult.box], tokenSource: pdfResult.tokenSource || 'pdfjs' }
      : null,
    tess: tessHasMatch
      ? { page: tessResult.page || 1, boxes: findAll ? (tessResult.boxes || []) : [tessResult.box], tokenSource: tessResult.tokenSource || 'tesseract' }
      : null
  };
  state.findTextActiveSources = { pdf: pdfHasMatch, tess: tessHasMatch };
  const activeSource = pdfHasMatch ? 'pdfjs' : (tessHasMatch ? 'tesseract' : null);
  const { page } = activeResult;
  state.pageNum = page;
  state.viewport = state.pageViewports[state.pageNum - 1] || state.viewport;
  updatePageIndicator();
  if(els.viewer && state.pageOffsets?.length){
    els.viewer.scrollTo({ top: state.pageOffsets[state.pageNum - 1], behavior: 'smooth' });
  }
  const entry = learningEntries.length
    ? (learningEntries.find(item => item.source === activeSource) || learningEntries[0])
    : null;
  const activeCandidates = entry?.candidates || activeResult?.candidates || [];
  const chosenBoxPx = activeSource === 'pdfjs'
    ? (findAll ? (pdfResult?.boxes?.[0] || null) : (pdfResult?.box || null))
    : (findAll ? (tessResult?.boxes?.[0] || null) : (tessResult?.box || null));
  const chosenCandidateId = entry?.chosenCandidateId || activeCandidates?.[0]?.id || null;
  const snapshot = await buildFindTextAttemptSnapshot({
    query,
    source: activeSource,
    tokenSource: activeResult?.tokenSource || activeSource,
    matchMode,
    matchSource: activeResult?.matchSource || null,
    candidates: activeCandidates,
    chosenCandidateId,
    chosenBoxPx
  });
  const attempt = recordFindTextAttemptSnapshot(snapshot);
  if(attempt){
    renderFindTextAttemptList();
    renderFindTextAttemptSnapshot();
    if(els.findTextLockToggle?.checked){
      state.findTextLearning.lockEnabled = true;
      updateFindTextLockStateFromAttempt(attempt);
    }
    await refreshFindTextStepperFromAttempt(attempt);
  } else if(learningEnabled && entry){
    await refreshFindTextStepperFromEntry(entry, chosenBoxPx);
  }
  await updateFindTextConstellations();
  setFindTextStatus(`Found "${query}". ${statusBits.join(' · ')}`);
  renderFindTextDebug();
}

