function getTesseractWordBBox(word){
  const bbox = word?.bbox || {};
  const x0 = Number.isFinite(bbox.x0) ? bbox.x0 : (Number.isFinite(bbox.x) ? bbox.x : 0);
  const y0 = Number.isFinite(bbox.y0) ? bbox.y0 : (Number.isFinite(bbox.y) ? bbox.y : 0);
  const x1 = Number.isFinite(bbox.x1) ? bbox.x1 : null;
  const y1 = Number.isFinite(bbox.y1) ? bbox.y1 : null;
  const width = Number.isFinite(bbox.width) ? bbox.width : (Number.isFinite(bbox.w) ? bbox.w : null);
  const height = Number.isFinite(bbox.height) ? bbox.height : (Number.isFinite(bbox.h) ? bbox.h : null);
  const xMax = Number.isFinite(x1) ? x1 : (Number.isFinite(width) ? x0 + width : x0);
  const yMax = Number.isFinite(y1) ? y1 : (Number.isFinite(height) ? y0 + height : y0);
  return {
    x: x0,
    y: y0,
    w: Math.max(0, xMax - x0),
    h: Math.max(0, yMax - y0)
  };
}

async function readImageTokensForPageWithBBox(pageNum, canvasEl=null){
  let canvas = canvasEl || getPdfBitmapCanvas(pageNum-1)?.canvas || null;

  // Run-mode PDF fallback: if the main pdfCanvas was never rendered (run mode
  // skips renderAllPages for speed) and we still have a loaded PDF document,
  // render the requested page to a temporary off-screen canvas so Tesseract
  // receives valid pixel data instead of a blank/missing source.
  if(!canvas && !state.isImage && state.pdf){
    try {
      const page = await state.pdf.getPage(pageNum);
      const vp = state.pageViewports[pageNum-1] || page.getViewport({ scale: BASE_PDF_SCALE });
      const tmp = document.createElement('canvas');
      tmp.width = vp.width;
      tmp.height = vp.height;
      await page.render({ canvasContext: tmp.getContext('2d'), viewport: vp }).promise;
      canvas = tmp;
      logStaticDebug(`ocr-fallback-render page=${pageNum}`, { w: tmp.width, h: tmp.height });
    } catch(renderErr){
      console.warn('OCR fallback: on-demand PDF page render failed', renderErr);
      logStaticDebug(`ocr-fallback-render-failed page=${pageNum}`, { error: renderErr?.message || renderErr });
    }
  }

  // Last resort for images: use the img element
  if(!canvas){ canvas = els.imgCanvas; }
  if(!canvas){ return []; }

  // Guard: skip Tesseract if source is clearly unreadable (0×0 canvas, or
  // <img> without a loaded src).  Prevents "Error attempting to read image".
  const isImg = canvas.tagName === 'IMG';
  if(isImg && (!canvas.src || !canvas.naturalWidth)){
    logStaticDebug(`ocr-skip-invalid-img page=${pageNum}`, { src: !!canvas.src, naturalWidth: canvas.naturalWidth });
    return [];
  }
  if(!isImg && (canvas.width <= 0 || canvas.height <= 0)){
    logStaticDebug(`ocr-skip-empty-canvas page=${pageNum}`, { w: canvas.width, h: canvas.height });
    return [];
  }

  const opts = { tessedit_pageseg_mode: 6, oem: 1 };
  // Tesseract.js returns bounding boxes in the image's natural/intrinsic pixel
  // coordinate space.  When the image is displayed at a scaled-down size (e.g.
  // capped at 980px width), the viewport uses the display dimensions.  We must
  // scale Tesseract coords into the display coordinate space so they match.
  let coordScale = 1;
  if(canvas === els.imgCanvas && canvas.naturalWidth && canvas.width){
    coordScale = canvas.width / canvas.naturalWidth;
    // coordScale < 1 means img wider than 980px → Tesseract coords are larger than viewport
  }
  try{
    const { data } = await TesseractRef.recognize(canvas, 'eng', opts);
    const tokens = (data.words || []).map(w => {
      const raw = w.text.trim();
      if(!raw) return null;
      const { text: corrected, corrections } = applyOcrCorrections(raw);
      const bbox = getTesseractWordBBox(w);
      const sx = bbox.x * coordScale;
      const sy = bbox.y * coordScale;
      const sw = bbox.w * coordScale;
      const sh = bbox.h * coordScale;
      // OCR trace hook: token-time corrections from full-page Tesseract.
      traceTokenCorrection({
        raw,
        corrected,
        corrections,
        source: 'tesseract_fullpage',
        pageIndex: pageNum - 1,
        box: { x: sx, y: sy, w: sw, h: sh, page: pageNum }
      });
      return {
        raw,
        corrected,
        text: corrected,
        correctionsApplied: corrections,
        confidence: (w.confidence || 0) / 100,
        x: sx,
        y: sy,
        w: sw,
        h: sh,
        page: pageNum
      };
    }).filter(Boolean);
    logStaticDebug(`full-page-ocr-bboxfix page=${pageNum}`, { tokens: tokens.length, meanConf: tokens.reduce((s,t)=>s+t.confidence,0)/(tokens.length||1) });
    return tokens;
  } catch(err){
    console.warn('Full-page OCR bbox fix failed', err);
    logStaticDebug(`full-page-ocr-bboxfix-failed page=${pageNum}`, { error: err?.message || err });
    return [];
  }
}

async function ensureTesseractTokensForPageWithBBox(pageNum, canvasEl=null){
  if(state.tessTokensByPageBBox?.[pageNum]) return state.tessTokensByPageBBox[pageNum];
  const tokens = await readImageTokensForPageWithBBox(pageNum, canvasEl);
  if(!state.tessTokensByPageBBox) state.tessTokensByPageBBox = {};
  state.tessTokensByPageBBox[pageNum] = tokens;
  return tokens;
}

async function resolveExtractionTokensForField({ pageNum, preferredEngine = 'auto', mode = 'run' } = {}){
  const page = Math.max(1, Number(pageNum) || 1);
  const enginePref = String(preferredEngine || 'auto').toLowerCase();
  const wantTesseract = enginePref === 'tesseract' || enginePref === 'tesseract-bbox';
  const wantPdf = enginePref === 'pdfjs';
  const modeLabel = mode || (isRunMode() ? 'run' : (isConfigMode() ? 'config' : 'unknown'));

  const buildResult = (tokens, engineUsed, tokenSource, resolverReason, fallbackFrom = null) => ({
    page,
    tokens: Array.isArray(tokens) ? tokens : [],
    engineUsed,
    tokenSource,
    resolverReason,
    fallbackFrom,
    tokenCount: Array.isArray(tokens) ? tokens.length : 0,
    mode: modeLabel
  });

  if(wantTesseract){
    const tessTokens = await ensureTesseractTokensForPageWithBBox(page);
    const normalized = normalizeTesseractTokensForPage(tessTokens, page);
    return buildResult(normalized, 'tesseract', 'tesseract-bbox', 'preferred_tesseract');
  }

  if(wantPdf){
    const pdfTokens = await ensureTokensForPage(page);
    const sourceInfo = getTokenSourceInfoForPage(page);
    const tokenSource = sourceInfo.acroTokenCount > 0 && sourceInfo.pdfTokenCount === 0 ? 'acroform' : 'pdfjs';
    const engineUsed = tokenSource === 'acroform' ? 'acroform' : 'pdfjs';
    const reason = tokenSource === 'acroform' ? 'preferred_pdfjs_with_acroform_overlay' : 'preferred_pdfjs';
    return buildResult(pdfTokens, engineUsed, tokenSource, reason);
  }

  const pdfTokens = await ensureTokensForPage(page);
  const sourceInfo = getTokenSourceInfoForPage(page);
  if(Array.isArray(pdfTokens) && pdfTokens.length){
    const tokenSource = sourceInfo.acroTokenCount > 0 && sourceInfo.pdfTokenCount === 0 ? 'acroform' : 'pdfjs';
    const engineUsed = tokenSource === 'acroform' ? 'acroform' : 'pdfjs';
    const reason = tokenSource === 'acroform' ? 'acroform_tokens_available' : 'pdf_tokens_available';
    return buildResult(pdfTokens, engineUsed, tokenSource, reason);
  }

  if(sourceInfo.acroTokenCount > 0){
    const acroTokens = Array.isArray(state.acroTokensByPage?.[page]) ? state.acroTokensByPage[page] : [];
    return buildResult(acroTokens, 'acroform', 'acroform', 'acroform_tokens_available_without_pdf_text', 'pdfjs');
  }

  const tessTokens = await ensureTesseractTokensForPageWithBBox(page);
  const normalized = normalizeTesseractTokensForPage(tessTokens, page);
  return buildResult(normalized, 'tesseract', 'tesseract-bbox', 'pdf_empty_tokens_fallback', 'pdfjs');
}

function isRenderableFindTextBox(box){
  return !!(box && Number.isFinite(box.w) && Number.isFinite(box.h) && box.w > 0 && box.h > 0);
}

async function findTextInDocumentWithTesseractBBoxFix(query, options = {}){
  const { matchMode = 'first' } = options || {};
  const normalized = normalizeFindTextInput(query);
  if(!normalized) return null;
  const totalPages = state.numPages || 1;
  for(let page=1; page<=totalPages; page++){
    const tokens = await ensureTesseractTokensForPageWithBBox(page);
    if(!tokens.length) continue;
    let box = findTextMatchInTokens(tokens, normalized, { mode: matchMode });
    let matchSource = box ? 'tokens' : null;
    if(!box){
      box = findLandmark(tokens, { text: normalized, strategy: 'exact' }, state.pageViewports[page-1] || state.viewport);
      matchSource = box ? 'landmark-exact' : matchSource;
    }
    if(!box){
      box = findLandmark(tokens, { text: normalized, strategy: 'fuzzy', threshold: 0.86 }, state.pageViewports[page-1] || state.viewport);
      matchSource = box ? 'landmark-fuzzy' : matchSource;
    }
    if(box){
      box.page = box.page || page;
      return {
        box,
        page,
        matchSource,
        tokens: tokens.length,
        tokenSource: 'tesseract-bbox',
        hasTextLayer: true
      };
    }
  }
  return null;
}

async function waitForFindTextSearchToSettle(query){
  const searchText = `Searching for "${query}"`;
  for(let i=0; i<120; i++){
    const status = els.findTextStatus?.textContent || '';
    if(!status.includes(searchText)) return;
    await new Promise(resolve => setTimeout(resolve, 100));
  }
}

async function applyTesseractBBoxFixForFindText(query){
  const normalized = normalizeFindTextInput(query);
  if(!normalized || !state.currentFileId) return;
  if(els.findTextAllToggle?.checked) return;
  const matchMode = els.findTextBestToggle?.checked ? 'best' : 'first';
  await waitForFindTextSearchToSettle(normalized);
  const existingBox = state.findTextDebug?.tess?.boxPx;
  const existingBoxes = state.findTextDebug?.tess?.boxesPx || [];
  if(isRenderableFindTextBox(existingBox) || existingBoxes.some(isRenderableFindTextBox)) return;
  const result = await findTextInDocumentWithTesseractBBoxFix(normalized, { matchMode });
  if(result && isRenderableFindTextBox(result.box)){
    applyTesseractFindTextHighlight(result.box);
    state.findTextDebug.tess = { boxPx: result.box, matchSource: `${result.matchSource || 'tokens'}-bboxfix`, tokens: result.tokens };
    state.findTextResults = {
      ...(state.findTextResults || {}),
      tess: { page: result.page || 1, boxes: [result.box], tokenSource: result.tokenSource || 'tesseract-bbox' }
    };
    state.findTextActiveSources = { ...(state.findTextActiveSources || {}), tess: true };
    await updateFindTextConstellations();
    patchFindTextStatusForTesseract(normalized, result.page);
    renderFindTextDebug();
  }
}

function queueTesseractBBoxFix(){
  const useTess = els.findTextTessToggle ? els.findTextTessToggle.checked : false;
  if(!useTess) return;
  const query = normalizeFindTextInput(els.findTextInput?.value || '');
  if(!query) return;
  applyTesseractBBoxFixForFindText(query);
}

