    if(_learningSession.annotationCount() === 0){
      alert('Draw at least one box before saving.');
      return;
    }
    const record = _learningSession.finalize({
      imageId: state.currentFileId || ('img-' + Date.now()),
      imageName: _learningFileName
    });
