/* ====================== End Vision Learning Mode ==================== */

/* ====================== Graph Learning (WFG2 / WFG3) ======================= */

const _wfg2 = window.WrokitFeatureGraph2 || null;
const _wfg3 = window.WrokitFeatureGraph3 || null;
const _wfg2Store = _wfg2?.createAttemptStore ? _wfg2.createAttemptStore(localStorage) : null;
const _wfg2PresetStore = _wfg2?.createPresetStore ? _wfg2.createPresetStore(localStorage) : null;
const _wfg3Store = _wfg3?.createAttemptStore ? _wfg3.createAttemptStore(localStorage) : null;
const _wfg3PresetStore = _wfg3?.createPresetStore ? _wfg3.createPresetStore(localStorage) : null;
function _getActiveAttemptStore(){ return getGraphLearningEngineType() === 'wfg3' ? _wfg3Store : _wfg2Store; }
function _getActivePresetStore(){ return getGraphLearningEngineType() === 'wfg3' ? _wfg3PresetStore : _wfg2PresetStore; }
const _glStore = window.GraphLearningStore || null;
const _glTrainingStore = _glStore?.createGraphTrainingStore ? _glStore.createGraphTrainingStore(localStorage) : null;
const _glFamilyStore = _glStore?.createGraphFamilyStore ? _glStore.createGraphFamilyStore(localStorage) : null;
const _gsStore = window.GroupingSupervisionStore || null;
const _groupingSupervision = _gsStore?.createGroupingSupervisionStore ? _gsStore.createGroupingSupervisionStore(localStorage) : null;

function graphLearningStatus(msg){
  var text = msg || '';
  if(els.graphLearningStatus) els.graphLearningStatus.textContent = text;
  if(els.graphLearningStatusWfg3) els.graphLearningStatusWfg3.textContent = text;
}

function getGraphLearningEngineType(){
  var key = String(state.graphLearning?.engineType || 'wfg2').toLowerCase();
  return key === 'wfg3' ? 'wfg3' : 'wfg2';
}

function getGraphLearningEngine(){
  var engineType = getGraphLearningEngineType();
  if(engineType === 'wfg3' && _wfg3) return _wfg3;
  return _wfg2;
}

function graphLearningEngineLabel(){
  return getGraphLearningEngineType() === 'wfg3' ? 'WFG3' : 'WFG2';
}

function syncGraphLearningPipelineModeUI(){
  var modeSelect = document.getElementById('graph-learning-pipeline-mode');
  var modeInfo = document.getElementById('graph-learning-pipeline-info');
  if(!modeSelect) return;
  var isWfg3 = getGraphLearningEngineType() === 'wfg3';
  var current = String(modeSelect.value || 'partition');
  if(isWfg3){
    modeSelect.innerHTML = '' +
      '<option value="partition">A–F Full Pipeline (Partition + Grouping)</option>' +
      '<option value="partition_only">A–E Partition Only (No Group Merging)</option>';
    if(current !== 'partition' && current !== 'partition_only') current = 'partition';
    modeSelect.value = current;
    if(modeInfo){
      modeInfo.textContent = current === 'partition_only'
        ? 'Runs WFG3 through Stage E only. Group outputs are intentionally disabled.'
        : 'Runs WFG3 Stages A–F: boundary evidence → tokens → chains → partition → grouping.';
    }
  } else {
    modeSelect.innerHTML = '' +
      '<option value="partition">Partition-Only (Color-First)</option>' +
      '<option value="structural">Structural-Only (Legacy)</option>' +
      '<option value="hybrid">Hybrid (Partition + Structural Refinement)</option>' +
      '<option value="combined">Combined View</option>';
    if(!modeSelect.querySelector('option[value="' + current + '"]')) current = 'partition';
    modeSelect.value = current;
    if(modeInfo){
      var modeDescriptions = {
        partition: 'Non-overlapping color-first partition is the primary segmentation.',
        structural: 'Legacy grid-based structural region growing (overlapping regions possible).',
        hybrid: 'Partition first, then structural refinement enriches partition regions.',
        combined: 'Both partition and structural run; partition is authoritative.'
      };
      modeInfo.textContent = modeDescriptions[current] || '';
    }
  }
  if(state.graphLearning?.params){
    state.graphLearning.params.pipelineMode = modeSelect.value;
  }
}

function syncGraphLearningEngineUI(){
  var isWfg3 = getGraphLearningEngineType() === 'wfg3';
  if(els.graphLearningEngineSelect){
    els.graphLearningEngineSelect.value = getGraphLearningEngineType();
  }
  syncGraphLearningPipelineModeUI();
  if(els.graphLearningLegacyLayerControls){
    els.graphLearningLegacyLayerControls.style.display = isWfg3 ? 'none' : '';
  }
  if(els.graphLearningWfg3LayerControls){
    els.graphLearningWfg3LayerControls.style.display = isWfg3 ? '' : 'none';
  }
  if(els.graphLearningEngineCaption){
    if(isWfg3){
      els.graphLearningEngineCaption.textContent = 'WFG3 Pipeline (Stages A\u2013H) — full 8-stage pipeline: evidence \u2192 tokens \u2192 graph \u2192 partition \u2192 groups \u2192 structure [browser-native]';
    } else {
      els.graphLearningEngineCaption.textContent = graphLearningEngineLabel() + ' Compiled Graph — all evidence layers combined into final structural output';
    }
  }
  var wfg3SeedingSection = document.getElementById('graph-learning-wfg3-seeding-section');
  if(wfg3SeedingSection) wfg3SeedingSection.style.display = isWfg3 ? '' : 'none';
  if(isWfg3) wfg3SyncSeedingControls(state.graphLearning.params || null);
}

/** Read the WFG3 seeding controls and apply their values to params in-place. */
function wfg3ApplySeedingControls(params){
  var modeEl = document.getElementById('wfg3-seeding-mode');
  var staggerEl = document.getElementById('wfg3-seeding-staggered');
  var refineEl = document.getElementById('wfg3-seeding-refinement');
  if(modeEl) params.tokenSeedingMode = modeEl.value;
  if(staggerEl) params.seedStaggeredPass = staggerEl.checked;
  if(refineEl) params.seedRefinementEnabled = refineEl.checked;

  // Scaffold-specific controls (only meaningful when mode = uniform_scaffold)
  if(params.tokenSeedingMode === 'uniform_scaffold'){
    var spacingEl = document.getElementById('wfg3-scaffold-spacing');
    var scaffStaggerEl = document.getElementById('wfg3-scaffold-staggered');
    var snapEl = document.getElementById('wfg3-scaffold-snap');
    var gateEl = document.getElementById('wfg3-scaffold-gate');
    if(spacingEl) params.scaffoldSpacingPx = parseInt(spacingEl.value, 10) || 12;
    if(scaffStaggerEl) params.scaffoldStaggered = scaffStaggerEl.checked;
    if(snapEl) params.scaffoldSnapEnabled = snapEl.checked;
    if(gateEl) params.scaffoldEvidenceGateMin = parseFloat(gateEl.value) || 0.04;
  }
}

/** Sync the WFG3 seeding controls from a params object (or engine defaults). */
function wfg3SyncSeedingControls(params){
  var engine = getGraphLearningEngine();
  var src = params || (engine ? engine.DEFAULT_PARAMS : null);
  if(!src) return;
  var modeEl = document.getElementById('wfg3-seeding-mode');
  var staggerEl = document.getElementById('wfg3-seeding-staggered');
  var refineEl = document.getElementById('wfg3-seeding-refinement');
  if(modeEl) modeEl.value = src.tokenSeedingMode || 'tile_min_coverage';
  if(staggerEl) staggerEl.checked = !!src.seedStaggeredPass;
  if(refineEl) refineEl.checked = !!src.seedRefinementEnabled;

  // Scaffold-specific controls
  var spacingEl = document.getElementById('wfg3-scaffold-spacing');
  var spacingVal = document.getElementById('wfg3-scaffold-spacing-val');
  var scaffStaggerEl = document.getElementById('wfg3-scaffold-staggered');
  var snapEl = document.getElementById('wfg3-scaffold-snap');
  var gateEl = document.getElementById('wfg3-scaffold-gate');
  var gateVal = document.getElementById('wfg3-scaffold-gate-val');
  if(spacingEl){ spacingEl.value = src.scaffoldSpacingPx || 12; if(spacingVal) spacingVal.textContent = spacingEl.value; }
  if(scaffStaggerEl) scaffStaggerEl.checked = src.scaffoldStaggered !== false;
  if(snapEl) snapEl.checked = src.scaffoldSnapEnabled !== false;
  if(gateEl){ gateEl.value = src.scaffoldEvidenceGateMin || 0.04; if(gateVal) gateVal.textContent = parseFloat(gateEl.value).toFixed(2); }

  // Show/hide scaffold controls panel
  _wfg3ToggleScaffoldControls(src.tokenSeedingMode);
}

/** Toggle visibility of scaffold-specific controls based on selected mode. */
function _wfg3ToggleScaffoldControls(mode){
  var scaffoldPanel = document.getElementById('wfg3-scaffold-controls');
  if(scaffoldPanel) scaffoldPanel.style.display = (mode === 'uniform_scaffold') ? '' : 'none';
}

function graphLearningSessionId(){
  if(!state.graphLearning.sessionId) state.graphLearning.sessionId = getGraphLearningEngineType() + 'sess-' + Date.now().toString(36);
  return state.graphLearning.sessionId;
}

function renderGraphLearningPresetStatus(){
  if(!els.graphLearningPresetStatus) return;
  var _ps = _getActivePresetStore();
  const preset = _ps?.get ? _ps.get() : null;
  if(!preset){
    els.graphLearningPresetStatus.textContent = 'Preset: none saved';
    state.graphLearning.activePreset = null;
    return;
  }
  const stamp = preset.savedAt ? new Date(preset.savedAt).toLocaleString() : 'unknown time';
  els.graphLearningPresetStatus.textContent = 'Preset: ' + (preset.name || (graphLearningEngineLabel() + ' Baseline')) + ' (saved ' + stamp + ')';
  state.graphLearning.activePreset = preset;
}

function updateGraphLearningPresetButtons(){
  if(els.graphLearningSavePresetBtn) els.graphLearningSavePresetBtn.disabled = !state.graphLearning?.params;
  var _psBt = _getActivePresetStore();
  if(els.graphLearningLoadPresetBtn) els.graphLearningLoadPresetBtn.disabled = !_psBt?.get || !_psBt.get();
}

function graphLearningSaveCurrentPreset(opts){
  var engine = getGraphLearningEngine();
  var _psSave = _getActivePresetStore();
  if(!_psSave || !engine || !state.graphLearning?.params) return null;
  const gl = state.graphLearning;
  const previous = _psSave.get();
  const saved = _psSave.save({
    presetId: previous?.presetId || (getGraphLearningEngineType() + '-baseline'),
    name: previous?.name || (graphLearningEngineLabel() + ' Baseline'),
    createdAt: previous?.createdAt || null,
    params: engine.copyParams(gl.params),
    sourceAttemptId: gl.lastAttemptId || null,
    sourceResult: opts?.sourceResult || null,
    sourceFileName: gl.fileName || null
  });
  renderGraphLearningPresetStatus();
  updateGraphLearningPresetButtons();
  return saved;
}

function graphLearningLoadPresetIntoSession(){
  var engine = getGraphLearningEngine();
  var _psLoad = _getActivePresetStore();
  if(!_psLoad || !engine) return null;
  const preset = _psLoad.get();
  if(!preset?.params) return null;
  state.graphLearning.params = engine.copyParams(preset.params);
  state.graphLearning.activePreset = preset;
  updateGraphLearningPresetButtons();
  return preset;
}

function renderGraphLearningAttemptHistory(){
  var _asHist = _getActiveAttemptStore();
  if(!els.graphLearningAttempts || !_asHist) return;
  const rows = _asHist.getAll().slice().reverse().slice(0, 50);
  if(!rows.length){
    els.graphLearningAttempts.innerHTML = '<p class="sub" style="color:var(--muted);">No attempts yet.</p>';
    return;
  }
  els.graphLearningAttempts.innerHTML = rows.map(function(r){
    const tags = (r.feedbackTags || []).join(', ');
    const verdict = r.result === 'good' ? '<span style="color:#2a7;font-weight:700;">GOOD</span>' : '<span style="color:#c44;font-weight:700;">BAD</span>';
    return '<div style="padding:6px 0;border-bottom:1px solid var(--border,#eee);">' +
      verdict + ' <strong>#' + r.attemptNumber + '</strong> ' + (r.fileName || r.fileId || '') +
      ' <span class="sub" style="color:var(--muted);">(' + new Date(r.timestamp).toLocaleTimeString() + ')</span>' +
      '<div class="sub" style="color:var(--muted);">regions=' + (r.summary?.regionCount || 0) + ', edges=' + (r.summary?.edgeCount || 0) + (tags ? ', tags=' + tags : '') + '</div>' +
      '</div>';
  }).join('');
}

function getGraphLearningLayerFlags(){
  var isWfg3 = getGraphLearningEngineType() === 'wfg3';
  return {
    compiled: !!(document.getElementById('graph-learning-show-compiled') || {}).checked,
    regions: !!els.graphLearningShowRegions?.checked,
    adjacency: !!els.graphLearningShowAdjacency?.checked,
    debug: !!els.graphLearningShowDebug?.checked,
    colorEvidence: !!(document.getElementById('graph-learning-show-color-evidence') || {}).checked,
    closureEvidence: !!(document.getElementById('graph-learning-show-closure-evidence') || {}).checked,
    partition: !!(document.getElementById('graph-learning-show-wfg2-partition') || {}).checked,
    sharedBoundaries: !!(document.getElementById('graph-learning-show-wfg2-shared-boundaries') || {}).checked,
    regionOrder: !!(document.getElementById('graph-learning-show-region-order') || {}).checked,
    confidence: !!(document.getElementById('graph-learning-show-confidence') || {}).checked,
    colorPartition: !!(document.getElementById('graph-learning-show-color-partition') || {}).checked,
    nocolourBinary: !!(document.getElementById('graph-learning-show-nocolour-binary') || {}).checked,
    nocolourComponents: !!(document.getElementById('graph-learning-show-nocolour-components') || {}).checked,
    nocolourClusters: !!(document.getElementById('graph-learning-show-nocolour-clusters') || {}).checked,
    wfg3Tokens: isWfg3 ? !!els.graphLearningShowWfg3Tokens?.checked : false,
    wfg3Chains: isWfg3 ? !!els.graphLearningShowWfg3Chains?.checked : false,
    wfg3AtomicRegions: isWfg3 ? !!els.graphLearningShowWfg3AtomicRegions?.checked : false,
    wfg3Groups: isWfg3 ? !!els.graphLearningShowWfg3Groups?.checked : false,
    wfg3GroupBoundaries: isWfg3 ? !!els.graphLearningShowWfg3GroupBoundaries?.checked : false,
    wfg3EdgeBinary: isWfg3 ? !!els.graphLearningShowWfg3EdgeBinary?.checked : false,
    wfg3PartitionOverlay: isWfg3 ? !!els.graphLearningShowWfg3Partition?.checked : false,
    wfg3SharedBoundaries: isWfg3 ? !!els.graphLearningShowWfg3SharedBoundaries?.checked : false,
    wfg3TokenConfidenceHeatmap: isWfg3 ? !!(document.getElementById('graph-learning-show-wfg3-debug') || {}).checked : false,
    wfg3ColorEvidence: isWfg3 ? !!(document.getElementById('graph-learning-show-wfg3-color-evidence') || {}).checked : false,
    wfg3ClosureEvidence: isWfg3 ? !!(document.getElementById('graph-learning-show-wfg3-closure-evidence') || {}).checked : false
  };
}

function syncGraphLearningCanvases(){
  const gl = state.graphLearning;
  const surf = gl.normalizedSurface;
  const base = els.graphLearningBaseCanvas;
  const overlay = els.graphLearningOverlayCanvas;
  if(!surf || !base || !overlay) return null;
  if(base.width !== surf.width || base.height !== surf.height){
    base.width = surf.width;
    base.height = surf.height;
  }
  if(overlay.width !== surf.width || overlay.height !== surf.height){
    overlay.width = surf.width;
    overlay.height = surf.height;
  }
  // Fit-to-view: scale CSS display size so the full surface is visible
  // without scrolling, while keeping the drawing buffer at full resolution.
  const container = base.parentElement;
  const maxW = (container && container.clientWidth > 0) ? container.clientWidth : surf.width;
  const maxH = Math.round(window.innerHeight * 0.65);
  const fitScale = Math.min(maxW / surf.width, maxH / surf.height, 1);
  const cssW = Math.round(surf.width * fitScale) + 'px';
  const cssH = Math.round(surf.height * fitScale) + 'px';
  base.style.width = cssW;
  base.style.height = cssH;
  overlay.style.width = cssW;
  overlay.style.height = cssH;
  return { base, overlay, width: surf.width, height: surf.height };
}

function renderGraphLearningBaseSurface(){
  const synced = syncGraphLearningCanvases();
  if(!synced) return;
  const gl = state.graphLearning;
  const surf = gl.normalizedSurface;
  const ctx = synced.base.getContext('2d', { willReadFrequently: true });
  const out = new Uint8ClampedArray(surf.width * surf.height * 4);
  const hasColor = surf.rgb && surf.rgb.r;
  for(let i = 0, j = 0; i < surf.gray.length; i++, j += 4){
    if(hasColor){
      out[j] = surf.rgb.r[i] || 0;
      out[j + 1] = surf.rgb.g[i] || 0;
      out[j + 2] = surf.rgb.b[i] || 0;
    } else {
      const v = surf.gray[i] || 0;
      out[j] = v;
      out[j + 1] = v;
      out[j + 2] = v;
    }
    out[j + 3] = 255;
  }
  ctx.putImageData(new ImageData(out, surf.width, surf.height), 0, 0);
}

function paintGraphLearningOverlay(ctx){
  const gl = state.graphLearning;
  const flags = getGraphLearningLayerFlags();
  const nodes = gl.graph?.nodes || [];
  const idMap = new Map(nodes.map(n => [n.id, n]));
  const artf = gl.graph?.artifacts || {};
  const nSize = gl.graph?.normalizedSize || {};

  // ── Evidence layers (diagnostic) ──

  if(flags.colorEvidence && artf.colorBoundaryMap && nSize.width > 0 && nSize.height > 0){
    const cMap = artf.colorBoundaryMap;
    const mw = nSize.width, mh = nSize.height;
    const imgData = ctx.createImageData(mw, mh);
    const d = imgData.data;
    for(let i = 0, j = 0; i < cMap.length; i++, j += 4){
      const v = cMap[i];
      if(v > 0.01){
        d[j] = 255; d[j + 1] = Math.round(255 * (1 - v)); d[j + 2] = 0;
        d[j + 3] = Math.round(40 + v * 160);
      }
    }
    ctx.putImageData(imgData, 0, 0);
  }

  if(flags.closureEvidence && artf.closureMap && nSize.width > 0 && nSize.height > 0){
    const clMap = artf.closureMap;
    const mw = nSize.width, mh = nSize.height;
    const imgData = ctx.createImageData(mw, mh);
    const d = imgData.data;
    for(let i = 0, j = 0; i < clMap.length; i++, j += 4){
      if(clMap[i]){ d[j] = 0; d[j + 1] = 180; d[j + 2] = 255; d[j + 3] = 110; }
    }
    ctx.putImageData(imgData, 0, 0);
  }

  // ── Compiled Graph: unified final structural output ──
  // Combines shape fills + contour strokes + adjacency into one
  // coherent view representing the compiled result of all evidence layers.
  if(flags.compiled){
    const hues = [210, 150, 30, 330, 270, 60, 180, 0, 120, 300];

    // Pass 1: Filled regions (contour-following shapes, boosted visibility)
    for(let i = 0; i < nodes.length; i++){
      const node = nodes[i];
      const c = node.contour || [];
      if(c.length < 3) continue;
      const hue = hues[i % hues.length];
      const alpha = 0.22 + (node.closureScore || 0) * 0.10 + (node.surfaceUniformity || 0) * 0.08;
      ctx.fillStyle = 'hsla(' + hue + ',65%,50%,' + alpha.toFixed(2) + ')';
      ctx.beginPath();
      ctx.moveTo(c[0].x, c[0].y);
      for(let j = 1; j < c.length; j++) ctx.lineTo(c[j].x, c[j].y);
      ctx.closePath();
      ctx.fill();
    }

    // Pass 2: Contour strokes — dual-stroke (dark outline + colored inner) for contrast
    for(const node of nodes){
      const c = node.contour || [];
      if(c.length < 3) continue;
      const colorConf = node.colorConfidence || 0;
      // Outer dark stroke for contrast on any background
      ctx.strokeStyle = 'rgba(0,0,0,0.5)';
      ctx.lineWidth = (node.closureScore > 0.4 ? 3.5 : 2.8) + 1.5;
      ctx.beginPath();
      ctx.moveTo(c[0].x, c[0].y);
      for(let i = 1; i < c.length; i++) ctx.lineTo(c[i].x, c[i].y);
      ctx.closePath();
      ctx.stroke();
      // Inner colored stroke
      if(colorConf > 0.3){
        ctx.strokeStyle = 'rgba(233,30,99,' + (0.75 + colorConf * 0.25).toFixed(2) + ')';
      } else {
        ctx.strokeStyle = 'rgba(0,180,160,1.0)';
      }
      ctx.lineWidth = node.closureScore > 0.4 ? 3.5 : 2.8;
      ctx.beginPath();
      ctx.moveTo(c[0].x, c[0].y);
      for(let i = 1; i < c.length; i++) ctx.lineTo(c[i].x, c[i].y);
      ctx.closePath();
      ctx.stroke();
    }

    // Pass 3: Adjacency edges (thicker, more visible)
    for(const e of gl.graph?.edges || []){
      const a = idMap.get(e.from), b = idMap.get(e.to);
      if(!a || !b) continue;
      ctx.strokeStyle = 'rgba(255,152,0,0.75)';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(a.center?.x || 0, a.center?.y || 0);
      ctx.lineTo(b.center?.x || 0, b.center?.y || 0);
      ctx.stroke();
    }
  }

  // ── Optional standalone layers ──

  if(flags.regions){
    for(const node of nodes){
      const b = node.bbox || {};
      ctx.fillStyle = flags.compiled ? 'rgba(121,134,203,0.08)' : 'rgba(121,134,203,0.25)';
      ctx.strokeStyle = 'rgba(63,81,181,0.95)';
      ctx.lineWidth = 1.8;
      ctx.fillRect(b.x || 0, b.y || 0, b.w || 0, b.h || 0);
      ctx.strokeRect(b.x || 0, b.y || 0, b.w || 0, b.h || 0);
    }
  }

  if(flags.adjacency && !flags.compiled){
    for(const e of gl.graph?.edges || []){
      const a = idMap.get(e.from), b = idMap.get(e.to);
      if(!a || !b) continue;
      ctx.strokeStyle = 'rgba(255,152,0,0.9)';
      ctx.lineWidth = 1.8;
      ctx.beginPath();
      ctx.moveTo(a.center?.x || 0, a.center?.y || 0);
      ctx.lineTo(b.center?.x || 0, b.center?.y || 0);
      ctx.stroke();
    }
  }

  // ── Partition overlay: per-pixel region coloring ──
  if(flags.partition && artf.partitionLabelMap && nSize.width > 0 && nSize.height > 0){
    const lblMap = artf.partitionLabelMap;
    const mw = nSize.width, mh = nSize.height;
    const imgData = ctx.createImageData(mw, mh);
    const d = imgData.data;
    const pHues = [210, 30, 150, 330, 60, 270, 180, 0, 120, 300, 45, 195, 285, 75, 345];
    for(var pi = 0, pj = 0; pi < lblMap.length; pi++, pj += 4){
      var lbl = lblMap[pi];
      if(lbl < 0) continue;
      var hue = pHues[lbl % pHues.length];
      // HSL to RGB inline (boosted saturation for visibility)
      var hp = hue / 60;
      var c1 = 0.50, x1 = c1 * (1 - Math.abs(hp % 2 - 1));
      var rp = 0, gp = 0, bp = 0;
      if(hp < 1){ rp = c1; gp = x1; }
      else if(hp < 2){ rp = x1; gp = c1; }
      else if(hp < 3){ gp = c1; bp = x1; }
      else if(hp < 4){ gp = x1; bp = c1; }
      else if(hp < 5){ rp = x1; bp = c1; }
      else { rp = c1; bp = x1; }
      d[pj] = Math.round((rp + 0.40) * 255);
      d[pj + 1] = Math.round((gp + 0.40) * 255);
      d[pj + 2] = Math.round((bp + 0.40) * 255);
      d[pj + 3] = 100; // increased alpha for clear region visibility
    }
    ctx.putImageData(imgData, 0, 0);
  }

  // ── Shared boundaries overlay (dual-stroke: dark outer + bright inner) ──
  if(flags.sharedBoundaries && artf.partitionSharedBoundaries && nSize.width > 0 && nSize.height > 0){
    var sbMap = artf.partitionSharedBoundaries;
    var sbW = nSize.width, sbH = nSize.height;
    var sbImg = ctx.createImageData(sbW, sbH);
    var sbD = sbImg.data;
    // Dilate boundary by 1px for thickness, then draw dark outer + bright inner
    var sbDilated = new Uint8Array(sbMap.length);
    for(var sby = 0; sby < sbH; sby++){
      for(var sbx = 0; sbx < sbW; sbx++){
        var sbIdx = sby * sbW + sbx;
        if(sbMap[sbIdx]){
          for(var sdy = -1; sdy <= 1; sdy++){
            for(var sdx = -1; sdx <= 1; sdx++){
              var snx = sbx + sdx, sny = sby + sdy;
              if(snx >= 0 && snx < sbW && sny >= 0 && sny < sbH){
                sbDilated[sny * sbW + snx] = sbMap[sny * sbW + snx] ? 2 : (sbDilated[sny * sbW + snx] || 1);
              }
            }
          }
        }
      }
    }
    for(var sbi = 0, sbj = 0; sbi < sbDilated.length; sbi++, sbj += 4){
      if(sbDilated[sbi] === 2){
        // Core boundary pixel: bright yellow
        sbD[sbj] = 255; sbD[sbj + 1] = 240; sbD[sbj + 2] = 0; sbD[sbj + 3] = 230;
      } else if(sbDilated[sbi] === 1){
        // Dilated outer pixel: dark outline for contrast
        sbD[sbj] = 30; sbD[sbj + 1] = 30; sbD[sbj + 2] = 0; sbD[sbj + 3] = 200;
      }
    }
    ctx.putImageData(sbImg, 0, 0);
  }

  // ── Region order overlay ──
  if(flags.regionOrder){
    ctx.font = 'bold 11px IBM Plex Mono, monospace';
    ctx.fillStyle = 'rgba(0,100,200,0.95)';
    for(var roi = 0; roi < nodes.length; roi++){
      var rn = nodes[roi];
      var order = rn.commitOrder !== undefined ? rn.commitOrder : roi;
      ctx.fillText('#' + order, (rn.center?.x || 0) - 8, (rn.center?.y || 0) + 14);
    }
  }

  // ── Confidence overlay ──
  if(flags.confidence){
    ctx.font = '10px IBM Plex Mono, monospace';
    for(var ci = 0; ci < nodes.length; ci++){
      var cn = nodes[ci];
      var conf = cn.confidence !== undefined ? cn.confidence : (cn.closureScore || 0);
      var confPct = (conf * 100).toFixed(0);
      ctx.fillStyle = conf > 0.6 ? 'rgba(46,125,50,0.9)' : conf > 0.3 ? 'rgba(245,127,23,0.9)' : 'rgba(211,47,47,0.9)';
      ctx.fillText(confPct + '%', (cn.center?.x || 0) + 2, (cn.center?.y || 0) - 12);
    }
  }

  if(flags.debug){
    ctx.fillStyle = 'rgba(244,67,54,0.95)';
    ctx.font = '10px IBM Plex Mono, monospace';
    for(let i = 0; i < nodes.length; i++){
      const n = nodes[i];
      const closureLabel = n.closureScore > 0.01 ? ' c' + (n.closureScore * 100).toFixed(0) : '';
      const colorLabel = n.colorConfidence > 0.01 ? ' C' + (n.colorConfidence * 100).toFixed(0) : '';
      const uniformLabel = n.surfaceUniformity > 0.01 ? ' u' + (n.surfaceUniformity * 100).toFixed(0) : '';
      ctx.fillText(String(i + 1) + closureLabel + colorLabel + uniformLabel, (n.center?.x || 0) + 2, (n.center?.y || 0) - 2);
    }
  }

  // ═══ NOCOLOUR Fallback Debug Layers ═══
  // Binary layer: shows the thresholded B/W image used by fallback
  if(flags.nocolourBinary && artf.nocolourDebug?.binaryLayer && nSize.width > 0 && nSize.height > 0){
    var ncBin = artf.nocolourDebug.binaryLayer;
    var ncW = nSize.width, ncH = nSize.height;
    var ncBinImg = ctx.createImageData(ncW, ncH);
    var ncBinD = ncBinImg.data;
    for(var nbi = 0, nbj = 0; nbi < ncBin.length; nbi++, nbj += 4){
      if(ncBin[nbi]){
        ncBinD[nbj] = 60; ncBinD[nbj + 1] = 20; ncBinD[nbj + 2] = 120; ncBinD[nbj + 3] = 140;
      }
    }
    ctx.putImageData(ncBinImg, 0, 0);
  }

  // Micro-components: shows individual connected components with distinct colors
  if(flags.nocolourComponents && artf.nocolourDebug?.components && artf.nocolourDebug?.componentLabel && nSize.width > 0 && nSize.height > 0){
    var ncCompLabel = artf.nocolourDebug.componentLabel;
    var ncCompW = nSize.width, ncCompH = nSize.height;
    var ncCompImg = ctx.createImageData(ncCompW, ncCompH);
    var ncCompD = ncCompImg.data;
    var ncCompHues = [0, 40, 80, 120, 160, 200, 240, 280, 320, 20, 60, 100, 140, 180, 220, 260, 300, 340];
    for(var nci = 0, ncj = 0; nci < ncCompLabel.length; nci++, ncj += 4){
      var ncLbl = ncCompLabel[nci];
      if(ncLbl < 0) continue;
      var ncHue = ncCompHues[ncLbl % ncCompHues.length];
      // Simple HSL→RGB for overlay
      var ncHp = ncHue / 60;
      var ncC = 0.6, ncX = ncC * (1 - Math.abs(ncHp % 2 - 1));
      var ncRp = 0, ncGp = 0, ncBp = 0;
      if(ncHp < 1){ ncRp = ncC; ncGp = ncX; }
      else if(ncHp < 2){ ncRp = ncX; ncGp = ncC; }
      else if(ncHp < 3){ ncGp = ncC; ncBp = ncX; }
      else if(ncHp < 4){ ncGp = ncX; ncBp = ncC; }
      else if(ncHp < 5){ ncRp = ncX; ncBp = ncC; }
      else { ncRp = ncC; ncBp = ncX; }
      ncCompD[ncj] = Math.round((ncRp + 0.3) * 255);
      ncCompD[ncj + 1] = Math.round((ncGp + 0.3) * 255);
      ncCompD[ncj + 2] = Math.round((ncBp + 0.3) * 255);
      ncCompD[ncj + 3] = 120;
    }
    ctx.putImageData(ncCompImg, 0, 0);
  }

  // Clustered regions: shows final NOCOLOUR clusters (only when fallback is active)
  if(flags.nocolourClusters && artf.nocolourFallbackActive && artf.partitionLabelMap && nSize.width > 0 && nSize.height > 0){
    var ncClustLbl = artf.partitionLabelMap;
    var ncClW = nSize.width, ncClH = nSize.height;
    var ncClImg = ctx.createImageData(ncClW, ncClH);
    var ncClD = ncClImg.data;
    var ncClPalette = [
      [0, 200, 120], [200, 60, 60], [60, 120, 220], [220, 180, 40],
      [160, 40, 200], [40, 200, 200], [200, 120, 60], [100, 200, 60],
      [200, 60, 160], [60, 60, 200], [200, 200, 60], [60, 200, 60]
    ];
    for(var ncCi = 0, ncCj = 0; ncCi < ncClustLbl.length; ncCi++, ncCj += 4){
      var ncCl = ncClustLbl[ncCi];
      if(ncCl < 0) continue;
      var ncCol = ncClPalette[ncCl % ncClPalette.length];
      ncClD[ncCj] = ncCol[0]; ncClD[ncCj + 1] = ncCol[1]; ncClD[ncCj + 2] = ncCol[2];
      ncClD[ncCj + 3] = 100;
    }
    ctx.putImageData(ncClImg, 0, 0);
  }

  // ═══ Color Partition: Master Segmentation View ═══
  // Dedicated layer that makes each detected region immediately identifiable.
  // High-contrast fills, thick boundaries, centered labels with background.
  if(flags.colorPartition && artf.partitionLabelMap && nSize.width > 0 && nSize.height > 0){
    var cpLblMap = artf.partitionLabelMap;
    var cpSbMap = artf.partitionSharedBoundaries;
    var cpW = nSize.width, cpH = nSize.height;

    // 20 maximally-separated high-saturation colors (hand-picked for distinctness)
    var cpPalette = [
      [230,  25,  75], [ 60, 180,  75], [255, 225,  25], [  0, 130, 200],
      [245, 130,  48], [145,  30, 180], [ 70, 240, 240], [240,  50, 230],
      [210, 245,  60], [250, 190, 212], [  0, 128, 128], [220, 190, 255],
      [170, 110,  40], [255, 250, 200], [128,   0,   0], [170, 255, 195],
      [128, 128,   0], [255, 215, 180], [  0,   0, 128], [128, 128, 128]
    ];

    // Pass 1: Per-pixel region fill (high alpha for solid distinct colors)
    var cpImg = ctx.createImageData(cpW, cpH);
    var cpD = cpImg.data;
    for(var cpi = 0, cpj = 0; cpi < cpLblMap.length; cpi++, cpj += 4){
      var cpLbl = cpLblMap[cpi];
      if(cpLbl < 0) continue;
      var cpCol = cpPalette[cpLbl % cpPalette.length];
      cpD[cpj]     = cpCol[0];
      cpD[cpj + 1] = cpCol[1];
      cpD[cpj + 2] = cpCol[2];
      cpD[cpj + 3] = 160; // strong fill — regions are immediately distinguishable
    }

    // Pass 2: Thick boundaries (3px via dilation) — dark high-contrast lines
    if(cpSbMap){
      // Build boundary set with 1-pixel dilation for thickness
      var cpBoundary = new Uint8Array(cpLblMap.length);
      for(var byi = 0; byi < cpH; byi++){
        for(var bxi = 0; bxi < cpW; bxi++){
          var bIdx = byi * cpW + bxi;
          if(cpSbMap[bIdx]){
            // Mark this pixel and neighbors within 1px radius
            for(var dy = -1; dy <= 1; dy++){
              for(var dx = -1; dx <= 1; dx++){
                var nx = bxi + dx, ny = byi + dy;
                if(nx >= 0 && nx < cpW && ny >= 0 && ny < cpH){
                  cpBoundary[ny * cpW + nx] = 1;
                }
              }
            }
          }
        }
      }
      for(var bi = 0, bj = 0; bi < cpBoundary.length; bi++, bj += 4){
        if(cpBoundary[bi]){
          cpD[bj] = 20; cpD[bj + 1] = 20; cpD[bj + 2] = 30; cpD[bj + 3] = 220;
        }
      }
    }

    ctx.putImageData(cpImg, 0, 0);

    // Pass 3: Region labels — centered in each region with background pill
    ctx.save();
    var cpFontSize = Math.max(11, Math.min(16, Math.round(Math.min(cpW, cpH) / 40)));
    ctx.font = 'bold ' + cpFontSize + 'px IBM Plex Mono, monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    for(var li = 0; li < nodes.length; li++){
      var ln = nodes[li];
      var lx = ln.center?.x || 0;
      var ly = ln.center?.y || 0;
      var labelText = 'P' + String(ln.partitionId);
      var tm = ctx.measureText(labelText);
      var pillW = tm.width + 10;
      var pillH = cpFontSize + 6;
      // Background pill (dark with slight transparency)
      ctx.fillStyle = 'rgba(10, 10, 20, 0.82)';
      ctx.beginPath();
      var pillR = 4;
      var px0 = lx - pillW / 2, py0 = ly - pillH / 2;
      var px1 = lx + pillW / 2, py1 = ly + pillH / 2;
      ctx.moveTo(px0 + pillR, py0);
      ctx.lineTo(px1 - pillR, py0);
      ctx.quadraticCurveTo(px1, py0, px1, py0 + pillR);
      ctx.lineTo(px1, py1 - pillR);
      ctx.quadraticCurveTo(px1, py1, px1 - pillR, py1);
      ctx.lineTo(px0 + pillR, py1);
      ctx.quadraticCurveTo(px0, py1, px0, py1 - pillR);
      ctx.lineTo(px0, py0 + pillR);
      ctx.quadraticCurveTo(px0, py0, px0 + pillR, py0);
      ctx.closePath();
      ctx.fill();
      // White text
      ctx.fillStyle = '#ffffff';
      ctx.fillText(labelText, lx, ly + 1);
    }
    ctx.restore();
  }
}

function renderGraphLearningViewer(){
  const synced = syncGraphLearningCanvases();
  if(!synced) return;
  renderGraphLearningBaseSurface();
  const octx = synced.overlay.getContext('2d');
  octx.clearRect(0, 0, synced.width, synced.height);
  paintGraphLearningOverlay(octx);
}

function clearGraphLearningViewer(){
  const base = els.graphLearningBaseCanvas;
  const overlay = els.graphLearningOverlayCanvas;
  if(base){ const bctx = base.getContext('2d'); bctx.clearRect(0, 0, base.width || 1, base.height || 1); base.style.width = ''; base.style.height = ''; }
  if(overlay){ const octx = overlay.getContext('2d'); octx.clearRect(0, 0, overlay.width || 1, overlay.height || 1); overlay.style.width = ''; overlay.style.height = ''; }
}

function graphLearningCaptureAttempt(result, feedback){
  var _asCap = _getActiveAttemptStore();
  if(!_asCap || !state.graphLearning.graph) return;
  const gl = state.graphLearning;
  const attempt = {
    attemptId: getGraphLearningEngineType() + 'a-' + Date.now().toString(36),
    sessionId: graphLearningSessionId(),
    attemptNumber: gl.attemptNumber,
    fileId: gl.fileId,
    fileName: gl.fileName,
    normalized: gl.normalizedSurface ? { width: gl.normalizedSurface.width, height: gl.normalizedSurface.height, source: gl.normalizedSurface.source } : null,
    generatedGraph: { engine: gl.graph.engine, version: gl.graph.version, pipelineMode: gl.graph.pipelineMode, nodes: gl.graph.nodes, edges: gl.graph.edges, artifacts: gl.graph.artifacts, partition: gl.graph.partition ? { regionCount: gl.graph.partition.regionCount } : null },
    generationParameters: { ...(gl.params || {}) },
    result,
    feedbackTags: Array.isArray(feedback?.tags) ? feedback.tags : [],
    rating: Number(feedback?.rating || 0) || null,
    timestamp: new Date().toISOString(),
    previousAttemptId: gl.lastAttemptId || null,
    summary: { regionCount: gl.graph.nodes?.length || 0, edgeCount: gl.graph.edges?.length || 0 }
  };
  _asCap.addAttempt(attempt);
  gl.lastAttemptId = attempt.attemptId;
  renderGraphLearningAttemptHistory();
  renderGraphLearningPresetStatus();
  updateGraphLearningPresetButtons();
}

function graphLearningRunGeneration(opts){
  var engine = getGraphLearningEngine();
  if(!engine || !state.graphLearning.normalizedSurface) return;
  const gl = state.graphLearning;
  if(opts?.feedback) gl.params = engine.adaptParametersFromFeedback(gl.params || engine.DEFAULT_PARAMS, opts.feedback);
  if(!gl.params) gl.params = engine.copyParams(engine.DEFAULT_PARAMS);
  gl.graph = engine.generateFeatureGraph(gl.normalizedSurface, gl.params);
  var wfg3PartitionOnly = gl.graph?.engine === 'wfg3' && gl.graph?.pipelineMode === 'partition_only';
  // Compute grouped graph from partition result
  if(engine.computeGroupedGraph && gl.graph?.partition && !wfg3PartitionOnly){
    var _partResult = { nodes: gl.graph.nodes, edges: gl.graph.edges, adjacency: gl.graph.partition.adjacency, labelMap: gl.graph.artifacts?.partitionLabelMap, sharedBoundaries: gl.graph.artifacts?.partitionSharedBoundaries, regionMeans: gl.graph.artifacts?.partitionRegionMeans, regionCount: gl.graph.partition.regionCount };
    var _supConstraints = { merges: [], keeps: [] };
    if(_groupingSupervision && gl.supervisionSessionId){
      _supConstraints = _groupingSupervision.buildConstraints(gl.supervisionSessionId);
    }
    var _nw = gl.graph.normalizedSize.width, _nh = gl.graph.normalizedSize.height;
    gl.groupedGraph = engine.computeGroupedGraph(_partResult, { width: _nw, height: _nh, mergeThreshold: gl.mergeThreshold, supervisionConstraints: _supConstraints });
    // Build fused label map for grouped partition-style rendering
    if(engine.buildGroupedLabelMap && gl.groupedGraph){
      var _fused = engine.buildGroupedLabelMap(gl.graph.artifacts.partitionLabelMap, gl.groupedGraph, gl.graph.nodes);
      gl.groupedLabelMap = _fused ? _fused.groupedLabelMap : null;
      gl.groupedBoundaries = (_fused && engine.computeSharedBoundaries) ? engine.computeSharedBoundaries(_fused.groupedLabelMap, _nw, _nh) : null;
    }
  } else { gl.groupedGraph = null; gl.groupedLabelMap = null; gl.groupedBoundaries = null; }
  gl.attemptNumber = (gl.attemptNumber || 0) + 1;
  // Enable all feedback buttons
  if(els.graphLearningGoodBtn) els.graphLearningGoodBtn.disabled = false;
  if(els.graphLearningBadBtn) els.graphLearningBadBtn.disabled = false;
  if(els.graphLearningRegenerateBtn) els.graphLearningRegenerateBtn.disabled = false;
  if(els.graphLearningTooFewBtn) els.graphLearningTooFewBtn.disabled = false;
  if(els.graphLearningTooManyBtn) els.graphLearningTooManyBtn.disabled = false;
  updateGraphLearningPresetButtons();
  // Compute and store graph fingerprint for change detection
  var _OLE = window.ObjectLearningEngine;
  var surfSize = gl.normalizedSurface ? { width: gl.normalizedSurface.width, height: gl.normalizedSurface.height } : { width: 1, height: 1 };
  var graphStats = _OLE?.computeGraphStats ? _OLE.computeGraphStats(gl.graph, surfSize) : null;
  if(_glStore?.computeGraphFingerprint && graphStats){
    gl._prevFingerprint = gl._currentFingerprint || null;
    gl._currentFingerprint = _glStore.computeGraphFingerprint(graphStats);
  }
  const artf = gl.graph?.artifacts || {};
  const prm = gl.params || {};
  const modeTag = ', mode:' + (gl.graph?.pipelineMode || 'partition');
  const partTag = gl.graph?.partition ? ', partition:' + (gl.graph.partition.regionCount || 0) + ' regions' : '';
  const colorTag = artf.colorBoundaryActive ? ', color:on' : ', color:off';
  const closureTag = artf.closureActive ? ', closure:on(' + (artf.enclosedRegionCount || 0) + ' enclosed)' : '';
  const calTag = artf.colorBoundaryActive ? ', ΔE floor=' + (prm.colorDistFloor ?? '?') + ' γ=' + ((prm.colorDistGamma ?? 0).toFixed(1)) + ' unif=' + ((prm.surfaceUniformityBias ?? 0).toFixed(2)) : '';
  const nocolourTag = artf.nocolourFallbackActive ? ', NOCOLOUR:on(thresh=' + (artf.nocolourDebug?.threshold ?? '?') + ', comps=' + (artf.nocolourDebug?.componentCount ?? '?') + ', clusters=' + (artf.nocolourDebug?.clusterCount ?? '?') + ')' : '';
  if(gl.graph?.engine === 'wfg3'){
    graphLearningStatus('WFG3 A\u2013H attempt ' + gl.attemptNumber + ': ' +
      (artf.wfg3_tokenCount || 0) + ' tokens, ' +
      (artf.wfg3_chainCount || 0) + ' chains, ' +
      (artf.wfg3_regionCount || 0) + ' regions, ' +
      (wfg3PartitionOnly ? 'grouping:off' : ('groups:' + (artf.wfg3_groupCount || 0))) + ', ' +
      (artf.wfg3_structureEdgeCount || 0) + ' struct edges, ' +
      'backend: ' + (artf.wfg3_backend || '?') + '.');
  } else {
    graphLearningStatus(graphLearningEngineLabel() + ' attempt ' + gl.attemptNumber + ': ' + (gl.graph?.nodes?.length || 0) + ' regions, ' + (gl.graph?.edges?.length || 0) + ' edges' + modeTag + partTag + colorTag + closureTag + calTag + nocolourTag + '.');
  }
  renderGraphLearningViewer();
}

function graphLearningCaptureGray(page){
  // For images, capture at full natural resolution so the entire image is
  // included.  ensureGrayCanvas/getPageGrayImageData use the scaled display
  // width which clips large images.  PDFs are fine via the normal path.
  const src = getActiveDisplaySurfaceNode();
  if(!src) return null;
  const isImg = state.isImage && src.tagName === 'IMG';
  if(!isImg){
    // PDF path: capture gray + try to get RGBA for color evidence
    const base = getPageGrayImageData(page);
    if(!base) return base;
    // Try to also capture RGBA from the PDF canvas
    try {
      const pdfC = els.pdfCanvas;
      if(pdfC && pdfC.width > 0 && pdfC.height > 0){
        const pctx = pdfC.getContext('2d', { willReadFrequently: true });
        const praw = pctx.getImageData(0, 0, pdfC.width, pdfC.height);
        base.rgba = praw.data;
      }
    } catch(e){ /* color not available for PDF, proceed with gray only */ }
    return base;
  }
  const w = src.naturalWidth || src.width;
  const h = src.naturalHeight || src.height;
  if(w <= 0 || h <= 0) return null;
  const tmp = document.createElement('canvas');
  tmp.width = w; tmp.height = h;
  const ctx = tmp.getContext('2d', { willReadFrequently: true });
  ctx.drawImage(src, 0, 0);
  const raw = ctx.getImageData(0, 0, w, h);
  const n = w * h;
  const gray = new Uint8Array(n);
  const r = new Uint8Array(n);
  const g = new Uint8Array(n);
  const b = new Uint8Array(n);
  for(let i = 0, j = 0; i < raw.data.length; i += 4, j++){
    r[j] = raw.data[i];
    g[j] = raw.data[i + 1];
    b[j] = raw.data[i + 2];
    gray[j] = Math.round(0.299 * r[j] + 0.587 * g[j] + 0.114 * b[j]);
  }
  return { gray, r, g, b, width: w, height: h };
}

async function graphLearningOpenFile(file){
  var engine = getGraphLearningEngine();
  if(!file || !engine) return;
  const gl = state.graphLearning;
  gl.active = true;
  gl.fileName = file.name || 'untitled';
  gl.fileId = getGraphLearningEngineType() + 'file-' + Date.now().toString(36);
  gl.attemptNumber = 0;
  gl.lastAttemptId = null;
  gl.latestFeedback = null;
  gl.graph = null;
  gl.normalizedSurface = null;
  gl.triedVariants = [];
  gl.currentVariantLabel = 'baseline';
  gl.currentStrategy = 'initial';
  gl.docFeatures = null;
  gl._prevFingerprint = null;
  gl._currentFingerprint = null;
  gl.baselineParams = null;
  clearGraphLearningViewer();
  graphLearningStatus('Loading file…');
  state.selectedEngineType = ENGINE_KIND.WROKIT_VISION;
  try {
    await openFile(file);
  } catch(err){
    console.error('[' + graphLearningEngineLabel() + '][GraphLearning] openFile failed', err);
    clearGraphLearningViewer();
    graphLearningStatus('Could not load this file for Graph Learning.');
    return;
  }
  const page = state.pageNum || 1;
  const img = graphLearningCaptureGray(page);
  if(!img || !img.width || !img.height){
    clearGraphLearningViewer();
    graphLearningStatus('File loaded but no render surface was available.');
    return;
  }
  gl.normalizedSurface = engine.normalizeVisualInput(img, { maxSide: 1300 });
  if(!gl.normalizedSurface){
    clearGraphLearningViewer();
    graphLearningStatus('Normalization failed for this file.');
    return;
  }

  // Extract document features for training and family lookup
  if(_glStore?.extractDocumentFeatures){
    gl.docFeatures = _glStore.extractDocumentFeatures(gl.normalizedSurface);
  }

  // Determine starting params: learned family > preset > defaults
  let startSource = 'defaults';
  const loadedPreset = graphLearningLoadPresetIntoSession();
  if(!loadedPreset) gl.params = engine.copyParams(engine.DEFAULT_PARAMS);
  else startSource = 'preset';

  // Try learned family match (overrides preset if confident)
  if(_glFamilyStore && gl.docFeatures?.valid){
    const match = _glFamilyStore.findBestFamily(gl.docFeatures);
    if(match && match.similarity >= 0.60){
      gl.params = engine.copyParams(match.family.avgParams);
      startSource = 'family-match (sim=' + match.similarity.toFixed(2) + ')';
      var famLabel = document.getElementById('graph-learning-family-match');
      if(famLabel) famLabel.textContent = 'Starting from learned family (similarity ' + (match.similarity * 100).toFixed(0) + '%)';
    }
  }

  gl.baselineParams = engine.copyParams(gl.params);
  gl.triedVariants = ['baseline'];
  gl.currentVariantLabel = 'baseline';
  gl.currentStrategy = startSource;

  renderGraphLearningBaseSurface();
  graphLearningRunGeneration();
  graphLearningUpdateTrainingBar();
  graphLearningUpdateRegenCount();
  if(loadedPreset && startSource === 'preset'){
    graphLearningStatus('Loaded preset "' + (loadedPreset.name || (graphLearningEngineLabel() + ' Baseline')) + '" and generated attempt ' + gl.attemptNumber + '.');
  } else if(startSource.startsWith('family')){
    graphLearningStatus('Auto-selected learned family params. Attempt ' + gl.attemptNumber + '.');
  }
}

