function graphLearningRecomputeGroupedGraph(){
  var gl = state.graphLearning;
  var engine = getGraphLearningEngine();
  if(!engine?.computeGroupedGraph || !gl.graph?.partition || !gl.graph?.artifacts?.partitionLabelMap) return;
  var partResult = { nodes: gl.graph.nodes, edges: gl.graph.edges, adjacency: gl.graph.partition.adjacency, labelMap: gl.graph.artifacts.partitionLabelMap, sharedBoundaries: gl.graph.artifacts.partitionSharedBoundaries, regionMeans: gl.graph.artifacts.partitionRegionMeans, regionCount: gl.graph.partition.regionCount };
  var supConstraints = { merges: [], keeps: [] };
  if(_groupingSupervision && gl.supervisionSessionId){
    supConstraints = _groupingSupervision.buildConstraints(gl.supervisionSessionId);
  }
  var nw = gl.graph.normalizedSize.width, nh = gl.graph.normalizedSize.height;
  gl.groupedGraph = engine.computeGroupedGraph(partResult, { width: nw, height: nh, mergeThreshold: gl.mergeThreshold, supervisionConstraints: supConstraints });
  // Build fused label map for grouped partition-style rendering
  if(engine.buildGroupedLabelMap && gl.groupedGraph){
    var fused = engine.buildGroupedLabelMap(gl.graph.artifacts.partitionLabelMap, gl.groupedGraph, gl.graph.nodes);
    gl.groupedLabelMap = fused ? fused.groupedLabelMap : null;
    gl.groupedBoundaries = (fused && engine.computeSharedBoundaries) ? engine.computeSharedBoundaries(fused.groupedLabelMap, nw, nh) : null;
  }
  if(typeof gl.refreshSelectionInspector === 'function') gl.refreshSelectionInspector();
}

function graphLearningDisplayGroupId(groupId, groupedGraph){
  if(!groupId) return '—';
  var groups = groupedGraph?.groups || [];
  for(var gi = 0; gi < groups.length; gi++){
    if(groups[gi].id === groupId) return 'G' + String(gi + 1);
  }
  return groupId;
}

function graphLearningUpdateGroupingInfo(){
  var bar = document.getElementById('graph-learning-grouping-info');
  if(!bar) return;
  var gl = state.graphLearning;
  var gg = gl.groupedGraph;
  if(!gg){ bar.style.display = 'none'; return; }
  bar.style.display = '';
  var gCountEl = document.getElementById('graph-learning-group-count');
  if(gCountEl) gCountEl.textContent = gg.groups ? gg.groups.length : 0;
  // Supervision stats
  if(_groupingSupervision && gl.supervisionSessionId){
    var labels = _groupingSupervision.getBoundaryLabelsForSession(gl.supervisionSessionId);
    var clusters = _groupingSupervision.getClusterAnnotationsForSession(gl.supervisionSessionId);
    var mergeCount = labels.filter(function(l){ return l.label === 'merge'; }).length;
    var keepCount = labels.filter(function(l){ return l.label === 'keep'; }).length;
    var blCount = document.getElementById('graph-learning-boundary-label-count');
    var mlCount = document.getElementById('graph-learning-merge-label-count');
    var klCount = document.getElementById('graph-learning-keep-label-count');
    var clCount = document.getElementById('graph-learning-cluster-count');
    if(blCount) blCount.textContent = labels.length;
    if(mlCount) mlCount.textContent = mergeCount;
    if(klCount) klCount.textContent = keepCount;
    if(clCount) clCount.textContent = clusters.length;
  }
}

// Supervision mode buttons
(function(){
  var boundaryBtn = document.getElementById('graph-learning-boundary-mode-btn');
  var lassoBtn = document.getElementById('graph-learning-lasso-mode-btn');
  var offBtn = document.getElementById('graph-learning-supervision-off-btn');
  var modeLabel = document.getElementById('graph-learning-supervision-mode-label');
  var interactionCanvas = document.getElementById('graph-learning-interaction-canvas');

  function setMode(mode){
    state.graphLearning.supervisionMode = mode;
    if(boundaryBtn) boundaryBtn.style.fontWeight = mode === 'boundary' ? '700' : '';
    if(lassoBtn) lassoBtn.style.fontWeight = mode === 'lasso' ? '700' : '';
    if(modeLabel) modeLabel.textContent = mode === 'boundary' ? 'Click a boundary between regions to label merge/keep' : mode === 'lasso' ? 'Draw a lasso around fragments to group them' : 'No supervision mode active';
    if(interactionCanvas) interactionCanvas.style.cursor = mode === 'boundary' ? 'crosshair' : mode === 'lasso' ? 'crosshair' : 'default';
    if(interactionCanvas) interactionCanvas.style.pointerEvents = mode ? 'auto' : 'none';
    // Clear lasso state on mode switch
    state.graphLearning.lassoPoints = [];
    state.graphLearning.lassoActive = false;
    state.graphLearning.selectedBoundary = null;
    renderGraphLearningViewer();
  }

  if(boundaryBtn) boundaryBtn.addEventListener('click', function(){ setMode(state.graphLearning.supervisionMode === 'boundary' ? null : 'boundary'); });
  if(lassoBtn) lassoBtn.addEventListener('click', function(){ setMode(state.graphLearning.supervisionMode === 'lasso' ? null : 'lasso'); });
  if(offBtn) offBtn.addEventListener('click', function(){ setMode(null); });

  // Enable supervision buttons when graph is available
  var origRunGen = graphLearningRunGeneration;
  graphLearningRunGeneration = function(opts){
    origRunGen(opts);
    if(boundaryBtn) boundaryBtn.disabled = false;
    if(lassoBtn) lassoBtn.disabled = false;
    if(offBtn) offBtn.disabled = false;
    // Register supervision session
    var gl = state.graphLearning;
    if(_groupingSupervision && !gl.supervisionSessionId){
      gl.supervisionSessionId = _groupingSupervision.registerSession({
        fileId: gl.fileId,
        fileName: gl.fileName,
        engineParams: gl.params,
        surfaceSize: gl.normalizedSurface ? { width: gl.normalizedSurface.width, height: gl.normalizedSurface.height } : {},
        atomicRegionCount: gl.graph?.nodes?.length || 0,
        pipelineMode: gl.graph?.pipelineMode || 'partition'
      });
    }
    graphLearningUpdateGroupingInfo();
  };
})();

// Clear supervision data button
(function(){
  var btn = document.getElementById('graph-learning-clear-supervision-btn');
  if(!btn) return;
  btn.addEventListener('click', function(){
    if(!confirm('Clear all grouping supervision data (boundary labels, cluster annotations)?')) return;
    if(_groupingSupervision) _groupingSupervision.clear();
    state.graphLearning.supervisionSessionId = null;
    graphLearningRecomputeGroupedGraph();
    graphLearningUpdateGroupingInfo();
    renderGraphLearningViewer();
    graphLearningStatus('Grouping supervision data cleared.');
  });
})();

/* ── Interaction Canvas: boundary clicks + lasso drawing ──────────── */

(function(){
  var interactionCanvas = document.getElementById('graph-learning-interaction-canvas');
  if(!interactionCanvas) return;

  function canvasToSurface(e){
    var rect = interactionCanvas.getBoundingClientRect();
    var gl = state.graphLearning;
    var surf = gl.normalizedSurface;
    if(!surf) return null;
    var scaleX = surf.width / rect.width;
    var scaleY = surf.height / rect.height;
    return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
  }

  function findClosestBoundary(pt){
    var gl = state.graphLearning;
    var gg = gl.groupedGraph;
    if(!gg?.boundaryScores || !gl.graph?.nodes) return null;
    var nodes = gl.graph.nodes;
    var nodeById = {};
    for(var i = 0; i < nodes.length; i++) nodeById[nodes[i].id] = nodes[i];
    var bestDist = 30; // max click distance in surface pixels
    var bestEntry = null;
    for(var j = 0; j < gg.boundaryScores.length; j++){
      var bs = gg.boundaryScores[j];
      var nA = nodeById[bs.nodeIdA], nB = nodeById[bs.nodeIdB];
      if(!nA || !nB) continue;
      // Midpoint of the two centers = boundary location
      var mx = ((nA.center?.x || 0) + (nB.center?.x || 0)) / 2;
      var my = ((nA.center?.y || 0) + (nB.center?.y || 0)) / 2;
      var d = Math.sqrt((pt.x - mx) * (pt.x - mx) + (pt.y - my) * (pt.y - my));
      if(d < bestDist){ bestDist = d; bestEntry = bs; }
    }
    return bestEntry;
  }

  function findNodesInLasso(lassoPoints){
    var gl = state.graphLearning;
    if(!gl.graph?.nodes || lassoPoints.length < 3) return [];
    var nodes = gl.graph.nodes;
    var result = [];
    for(var i = 0; i < nodes.length; i++){
      var cx = nodes[i].center?.x || 0, cy = nodes[i].center?.y || 0;
      if(pointInPolygon(cx, cy, lassoPoints)) result.push(nodes[i]);
    }
    return result;
  }

  function pointInPolygon(x, y, poly){
    var inside = false;
    for(var i = 0, j = poly.length - 1; i < poly.length; j = i++){
      var xi = poly[i].x, yi = poly[i].y;
      var xj = poly[j].x, yj = poly[j].y;
      if(((yi > y) !== (yj > y)) && (x < (xj - xi) * (y - yi) / (yj - yi) + xi)){
        inside = !inside;
      }
    }
    return inside;
  }

  interactionCanvas.addEventListener('mousedown', function(e){
    var gl = state.graphLearning;
    if(!gl.supervisionMode) return;
    var pt = canvasToSurface(e);
    if(!pt) return;

    if(gl.supervisionMode === 'lasso'){
      gl.lassoActive = true;
      gl.lassoPoints = [pt];
      return;
    }
  });

  interactionCanvas.addEventListener('mousemove', function(e){
    var gl = state.graphLearning;
    if(!gl.supervisionMode) return;
    var pt = canvasToSurface(e);
    if(!pt) return;

    if(gl.supervisionMode === 'lasso' && gl.lassoActive){
      gl.lassoPoints.push(pt);
      renderGraphLearningViewer();
      return;
    }

    if(gl.supervisionMode === 'boundary'){
      // Highlight nearest boundary
      var boundary = findClosestBoundary(pt);
      gl.selectedBoundary = boundary;
      renderGraphLearningViewer();
    }
  });

  interactionCanvas.addEventListener('mouseup', function(e){
    var gl = state.graphLearning;
    if(!gl.supervisionMode) return;
    var pt = canvasToSurface(e);
    if(!pt) return;

    if(gl.supervisionMode === 'lasso' && gl.lassoActive){
      gl.lassoActive = false;
      if(gl.lassoPoints.length < 5) { gl.lassoPoints = []; renderGraphLearningViewer(); return; }
      // Find nodes inside lasso
      var enclosed = findNodesInLasso(gl.lassoPoints);
      if(enclosed.length < 2){ gl.lassoPoints = []; renderGraphLearningViewer(); return; }
      // Find adjacency pairs within the enclosed set
      var encIds = new Set(enclosed.map(function(n){ return n.id; }));
      var adjPairs = [];
      var edges = gl.graph?.edges || [];
      for(var ei = 0; ei < edges.length; ei++){
        if(encIds.has(edges[ei].from) && encIds.has(edges[ei].to)){
          adjPairs.push({ from: edges[ei].from, to: edges[ei].to });
        }
      }
      if(adjPairs.length > 0 && _groupingSupervision && gl.supervisionSessionId){
        _groupingSupervision.addClusterAnnotation({
          sessionId: gl.supervisionSessionId,
          memberNodeIds: enclosed.map(function(n){ return n.id; }),
          adjacencyPairs: adjPairs,
          boundingBox: null
        });
        graphLearningRecomputeGroupedGraph();
        graphLearningUpdateGroupingInfo();
        graphLearningStatus('Cluster annotation saved: ' + enclosed.length + ' regions, ' + adjPairs.length + ' merge pairs.');
      }
      gl.lassoPoints = [];
      renderGraphLearningViewer();
      return;
    }

    if(gl.supervisionMode === 'boundary'){
      var boundary = findClosestBoundary(pt);
      if(!boundary) return;
      // Toggle: if not labeled, label as merge; if merge, switch to keep; if keep, switch to merge
      var existingLabels = _groupingSupervision && gl.supervisionSessionId ? _groupingSupervision.getBoundaryLabelsForSession(gl.supervisionSessionId) : [];
      var key = boundary.nodeIdA < boundary.nodeIdB ? boundary.nodeIdA + '|' + boundary.nodeIdB : boundary.nodeIdB + '|' + boundary.nodeIdA;
      var existing = null;
      for(var li = existingLabels.length - 1; li >= 0; li--){
        var lk = existingLabels[li].nodeIdA < existingLabels[li].nodeIdB ? existingLabels[li].nodeIdA + '|' + existingLabels[li].nodeIdB : existingLabels[li].nodeIdB + '|' + existingLabels[li].nodeIdA;
        if(lk === key){ existing = existingLabels[li]; break; }
      }
      var newLabel = (!existing || existing.label === 'keep') ? 'merge' : 'keep';
      if(_groupingSupervision && gl.supervisionSessionId){
        _groupingSupervision.addBoundaryLabel({
          sessionId: gl.supervisionSessionId,
          nodeIdA: boundary.nodeIdA,
          nodeIdB: boundary.nodeIdB,
          partitionIdA: boundary.partitionIdA,
          partitionIdB: boundary.partitionIdB,
          label: newLabel,
          features: boundary.features || {}
        });
        graphLearningRecomputeGroupedGraph();
        graphLearningUpdateGroupingInfo();
        graphLearningStatus('Boundary labeled: ' + newLabel + ' (' + boundary.nodeIdA + ' ↔ ' + boundary.nodeIdB + ', score=' + (boundary.score || 0).toFixed(2) + ')');
      }
      renderGraphLearningViewer();
    }
  });

  // Sync interaction canvas size
  var origSync = syncGraphLearningCanvases;
  syncGraphLearningCanvases = function(){
    var result = origSync();
    if(!result) return result;
    if(interactionCanvas){
      if(interactionCanvas.width !== result.width) interactionCanvas.width = result.width;
      if(interactionCanvas.height !== result.height) interactionCanvas.height = result.height;
      var base = result.base;
      interactionCanvas.style.width = base.style.width;
      interactionCanvas.style.height = base.style.height;
      // Ensure pointer events are set correctly
      interactionCanvas.style.pointerEvents = state.graphLearning.supervisionMode ? 'auto' : 'none';
    }
    return result;
  };
})();

/* ── Helper: draw rounded rect path (compatibility fallback for roundRect) ── */
function _glRoundRectPath(ctx, x, y, w, h, r){
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + r);
  ctx.lineTo(x + w, y + h - r);
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  ctx.lineTo(x + r, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - r);
  ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y);
  ctx.closePath();
}

/* ── Grouped graph overlay painting (injected into paintGraphLearningOverlay) ── */

var _origPaintOverlay = paintGraphLearningOverlay;
paintGraphLearningOverlay = function(ctx){
  var gl = state.graphLearning;
  var viewMode = gl.viewMode || 'atomic';

  var gg = gl.groupedGraph;
  var showDebugBoxes = !!(document.getElementById('graph-learning-show-grouped-overlay') || {}).checked;
  var showScores = !!(document.getElementById('graph-learning-show-merge-scores') || {}).checked;
  var nodes = gl.graph?.nodes || [];
  var nodeById = {};
  for(var ni = 0; ni < nodes.length; ni++) nodeById[nodes[ni].id] = nodes[ni];
  var nSize = gl.graph?.normalizedSize || {};
  var cpW = nSize.width || 0, cpH = nSize.height || 0;

  // ═══ Grouped / Corrected view: render fused regions in partition style ═══
  if((viewMode === 'grouped' || viewMode === 'both') && gl.groupedLabelMap && gg && cpW > 0 && cpH > 0){

    // In "both" mode, draw the raw partition first (via original overlay), then the grouped on top
    if(viewMode === 'both'){
      // Draw raw partition first at reduced opacity (original overlay handles this)
      _origPaintOverlay(ctx);
      // Dim the raw partition layer
      ctx.fillStyle = 'rgba(255,255,255,0.45)';
      ctx.fillRect(0, 0, ctx.canvas.width, ctx.canvas.height);
    }

    // 20 maximally-separated high-saturation colors (same palette as raw partition)
    var cpPalette = [
      [230,  25,  75], [ 60, 180,  75], [255, 225,  25], [  0, 130, 200],
      [245, 130,  48], [145,  30, 180], [ 70, 240, 240], [240,  50, 230],
      [210, 245,  60], [250, 190, 212], [  0, 128, 128], [220, 190, 255],
      [170, 110,  40], [255, 250, 200], [128,   0,   0], [170, 255, 195],
      [128, 128,   0], [255, 215, 180], [  0,   0, 128], [128, 128, 128]
    ];

    var gLblMap = gl.groupedLabelMap;
    var gBndMap = gl.groupedBoundaries;

    // Build fused partition image on a temp canvas, then composite onto main
    var _fusedTmp = document.createElement('canvas');
    _fusedTmp.width = cpW; _fusedTmp.height = cpH;
    var _fusedCtx = _fusedTmp.getContext('2d');
    var cpImg = _fusedCtx.createImageData(cpW, cpH);
    var cpD = cpImg.data;
    for(var cpi = 0, cpj = 0; cpi < gLblMap.length; cpi++, cpj += 4){
      var cpLbl = gLblMap[cpi];
      if(cpLbl < 0) continue;
      var cpCol = cpPalette[cpLbl % cpPalette.length];
      cpD[cpj]     = cpCol[0];
      cpD[cpj + 1] = cpCol[1];
      cpD[cpj + 2] = cpCol[2];
      cpD[cpj + 3] = 160;
    }

    // Thick boundaries (only between different groups) — dark lines
    if(gBndMap){
      var cpBoundary = new Uint8Array(gLblMap.length);
      for(var byi = 0; byi < cpH; byi++){
        for(var bxi = 0; bxi < cpW; bxi++){
          var bIdx = byi * cpW + bxi;
          if(gBndMap[bIdx]){
            for(var dy = -1; dy <= 1; dy++){
              for(var dx = -1; dx <= 1; dx++){
                var nx = bxi + dx, ny = byi + dy;
                if(nx >= 0 && nx < cpW && ny >= 0 && ny < cpH){
                  cpBoundary[ny * cpW + nx] = 1;
                }
              }
            }
          }
        }
      }
      for(var bi = 0, bj = 0; bi < cpBoundary.length; bi++, bj += 4){
        if(cpBoundary[bi]){
          cpD[bj] = 20; cpD[bj + 1] = 20; cpD[bj + 2] = 30; cpD[bj + 3] = 220;
        }
      }
    }

    _fusedCtx.putImageData(cpImg, 0, 0);
    ctx.drawImage(_fusedTmp, 0, 0);

    // Pass 3: Group labels — one label per group, centered
    ctx.save();
    var gFontSize = Math.max(11, Math.min(16, Math.round(Math.min(cpW, cpH) / 40)));
    ctx.font = 'bold ' + gFontSize + 'px IBM Plex Mono, monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    for(var gi = 0; gi < gg.groups.length; gi++){
      var group = gg.groups[gi];
      var gcx = group.center?.x || 0, gcy = group.center?.y || 0;
      var gLabelText = 'G' + String(gi + 1);
      var gTm = ctx.measureText(gLabelText);
      var gPillW = gTm.width + 10;
      var gPillH = gFontSize + 6;
      ctx.fillStyle = 'rgba(10, 10, 20, 0.82)';
      ctx.beginPath();
      _glRoundRectPath(ctx, gcx - gPillW / 2, gcy - gPillH / 2, gPillW, gPillH, 4);
      ctx.fill();
      ctx.fillStyle = '#ffffff';
      ctx.fillText(gLabelText, gcx, gcy + 1);
    }
    ctx.restore();

  } else {
    // Raw partition mode (atomic): call original overlay as-is
    _origPaintOverlay(ctx);
  }

  // ── Region selection highlight (composited on top) ──
  if(gl.selectedRegions && gl.selectedRegions.size > 0 && gl.graph?.artifacts?.partitionLabelMap && cpW > 0 && cpH > 0){
    var selLblMap = gl.graph.artifacts.partitionLabelMap;
    var selPids = new Set();
    for(var sni = 0; sni < nodes.length; sni++){
      if(gl.selectedRegions.has(nodes[sni].id)){
        selPids.add(nodes[sni].partitionId);
      }
    }
    if(selPids.size > 0){
      // Use a temp canvas so putImageData doesn't destroy existing overlay
      var _selTmp = document.createElement('canvas');
      _selTmp.width = cpW; _selTmp.height = cpH;
      var _selCtx = _selTmp.getContext('2d');
      var selImg = _selCtx.createImageData(cpW, cpH);
      var selD = selImg.data;
      for(var si = 0, sj = 0; si < selLblMap.length; si++, sj += 4){
        if(selPids.has(selLblMap[si])){
          selD[sj] = 0; selD[sj + 1] = 200; selD[sj + 2] = 255; selD[sj + 3] = 80;
        }
      }
      // Border around selected regions (dilated 2px)
      for(var sy2 = 0; sy2 < cpH; sy2++){
        for(var sx2 = 0; sx2 < cpW; sx2++){
          var si2 = sy2 * cpW + sx2;
          if(!selPids.has(selLblMap[si2])) continue;
          var isBorder = false;
          if(sx2 > 0 && !selPids.has(selLblMap[si2 - 1])) isBorder = true;
          else if(sx2 < cpW - 1 && !selPids.has(selLblMap[si2 + 1])) isBorder = true;
          else if(sy2 > 0 && !selPids.has(selLblMap[si2 - cpW])) isBorder = true;
          else if(sy2 < cpH - 1 && !selPids.has(selLblMap[si2 + cpW])) isBorder = true;
          if(isBorder){
            for(var bdy = -2; bdy <= 2; bdy++){
              for(var bdx = -2; bdx <= 2; bdx++){
                var bnx = sx2 + bdx, bny = sy2 + bdy;
                if(bnx >= 0 && bnx < cpW && bny >= 0 && bny < cpH){
                  var bni = (bny * cpW + bnx) * 4;
                  selD[bni] = 0; selD[bni + 1] = 220; selD[bni + 2] = 255; selD[bni + 3] = 200;
                }
              }
            }
          }
        }
      }
      _selCtx.putImageData(selImg, 0, 0);
      ctx.drawImage(_selTmp, 0, 0);
    }
  }

  // ── Advanced Debug: group bounding boxes (behind toggle) ──
  if(gg && showDebugBoxes && (viewMode === 'grouped' || viewMode === 'both')){
    var gHues = [20, 160, 280, 60, 200, 340, 100, 240, 0, 140, 300, 80, 220];
    for(var dgi = 0; dgi < gg.groups.length; dgi++){
      var dGroup = gg.groups[dgi];
      if(dGroup.isSingleton) continue;
      var dHue = gHues[dgi % gHues.length];
      var db = dGroup.bbox;
      ctx.strokeStyle = 'hsla(' + dHue + ',80%,55%,0.7)';
      ctx.lineWidth = 2;
      ctx.setLineDash([6, 4]);
      ctx.strokeRect(db.x, db.y, db.w, db.h);
      ctx.setLineDash([]);
    }
  }

  // ── Advanced Debug: merge scores ──
  if(gg && showScores && gg.boundaryScores){
    var msFontSize = 12;
    ctx.font = 'bold ' + msFontSize + 'px IBM Plex Mono, monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    for(var dsi = 0; dsi < gg.boundaryScores.length; dsi++){
      var dbs = gg.boundaryScores[dsi];
      var dnA = nodeById[dbs.nodeIdA], dnB = nodeById[dbs.nodeIdB];
      if(!dnA || !dnB) continue;
      var dmx = ((dnA.center?.x || 0) + (dnB.center?.x || 0)) / 2;
      var dmy = ((dnA.center?.y || 0) + (dnB.center?.y || 0)) / 2;
      var dScorePct = (dbs.score * 100).toFixed(0);
      var dIsMerge = dbs.score >= gl.mergeThreshold;
      var dTm = ctx.measureText(dScorePct);
      var dPillW = dTm.width + 10;
      var dPillH = msFontSize + 6;
      ctx.fillStyle = dIsMerge ? 'rgba(20,100,20,0.85)' : 'rgba(160,30,30,0.85)';
      ctx.beginPath();
      _glRoundRectPath(ctx, dmx - dPillW / 2, dmy - dPillH / 2, dPillW, dPillH, 3);
      ctx.fill();
      ctx.strokeStyle = dIsMerge ? 'rgba(80,200,80,0.9)' : 'rgba(255,80,80,0.9)';
      ctx.lineWidth = 1.2;
      ctx.stroke();
      ctx.fillStyle = '#ffffff';
      ctx.fillText(dScorePct, dmx, dmy + 1);
    }
    ctx.textAlign = 'start';
    ctx.textBaseline = 'alphabetic';
  }

  // ── Advanced Debug: supervision boundary labels (M/K markers) ──
  if(gl.supervisionMode === 'boundary' && _groupingSupervision && gl.supervisionSessionId){
    var labels = _groupingSupervision.getBoundaryLabelsForSession(gl.supervisionSessionId);
    var pairLabels = {};
    for(var li2 = 0; li2 < labels.length; li2++){
      var lbl = labels[li2];
      var lKey = lbl.nodeIdA < lbl.nodeIdB ? lbl.nodeIdA + '|' + lbl.nodeIdB : lbl.nodeIdB + '|' + lbl.nodeIdA;
      pairLabels[lKey] = lbl;
    }
    for(var pk in pairLabels){
      var pl = pairLabels[pk];
      var plA = nodeById[pl.nodeIdA], plB = nodeById[pl.nodeIdB];
      if(!plA || !plB) continue;
      var plMx = ((plA.center?.x || 0) + (plB.center?.x || 0)) / 2;
      var plMy = ((plA.center?.y || 0) + (plB.center?.y || 0)) / 2;
      ctx.beginPath();
      ctx.arc(plMx, plMy, 10, 0, Math.PI * 2);
      ctx.fillStyle = pl.label === 'merge' ? 'rgba(30,140,40,0.92)' : 'rgba(200,35,35,0.92)';
      ctx.fill();
      ctx.font = 'bold 14px IBM Plex Mono, monospace';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = '#ffffff';
      ctx.fillText(pl.label === 'merge' ? 'M' : 'K', plMx, plMy + 1);
      ctx.textAlign = 'start';
      ctx.textBaseline = 'alphabetic';
    }
  }

  // ── Advanced Debug: selected boundary highlight ──
  if(gl.selectedBoundary && gl.supervisionMode === 'boundary'){
    var sb = gl.selectedBoundary;
    var sbA = nodeById[sb.nodeIdA], sbB = nodeById[sb.nodeIdB];
    if(sbA && sbB){
      var sbMx = ((sbA.center?.x || 0) + (sbB.center?.x || 0)) / 2;
      var sbMy = ((sbA.center?.y || 0) + (sbB.center?.y || 0)) / 2;
      ctx.beginPath();
      ctx.arc(sbMx, sbMy, 12, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,235,59,0.5)';
      ctx.fill();
      ctx.strokeStyle = 'rgba(255,140,0,1.0)';
      ctx.lineWidth = 2;
      ctx.stroke();
    }
  }

  // ── Advanced Debug: lasso drawing ──
  if(gl.supervisionMode === 'lasso' && gl.lassoPoints && gl.lassoPoints.length > 1){
    ctx.beginPath();
    ctx.moveTo(gl.lassoPoints[0].x, gl.lassoPoints[0].y);
    for(var lpi = 1; lpi < gl.lassoPoints.length; lpi++){
      ctx.lineTo(gl.lassoPoints[lpi].x, gl.lassoPoints[lpi].y);
    }
    ctx.strokeStyle = 'rgba(33,150,243,0.95)';
    ctx.lineWidth = 2.5;
    ctx.setLineDash([6, 4]);
    ctx.stroke();
    ctx.setLineDash([]);
    if(gl.lassoPoints.length > 2){
      ctx.closePath();
      ctx.fillStyle = 'rgba(33,150,243,0.12)';
      ctx.fill();
    }
  }
};

/* ── WFG3-specific overlay rendering (intercepts when WFG3 engine is active) ── */

var _wfg3HighVisibilityMode = true; // ON by default — exaggerated debug style

var _priorPaintOverlay = paintGraphLearningOverlay;
paintGraphLearningOverlay = function(ctx){
  var gl = state.graphLearning;
  if(!gl.graph || gl.graph.engine !== 'wfg3'){
    return _priorPaintOverlay(ctx);
  }

  var artf = gl.graph.artifacts || {};
  var nSize = gl.graph.normalizedSize || {};
  var W = nSize.width || 0, H = nSize.height || 0;
  if(W === 0 || H === 0) return;
  var N = W * H;
  var flags = getGraphLearningLayerFlags();
  var tokens = artf.wfg3_tokens || [];
  var hv = _wfg3HighVisibilityMode;

  // ── Helper: dilate a pixel mask to make it thicker ──
  function dilateMask(src, w, h, radius) {
    var out = new Uint8Array(w * h);
    for(var y = 0; y < h; y++){
      for(var x = 0; x < w; x++){
        if(src[y * w + x] > 0){
          for(var dy = -radius; dy <= radius; dy++){
            for(var dx = -radius; dx <= radius; dx++){
              var ny2 = y + dy, nx2 = x + dx;
              if(ny2 >= 0 && ny2 < h && nx2 >= 0 && nx2 < w){
                out[ny2 * w + nx2] = 255;
              }
            }
          }
        }
      }
    }
    return out;
  }

  // ── Layer 1: Edge binary overlay (dilated for visibility) ──
  if(flags.wfg3EdgeBinary && artf.wfg3_edgeBinary){
    var eb = artf.wfg3_edgeBinary;
    var ebThick = hv ? dilateMask(eb, W, H, 1) : eb;
    var edgeData = ctx.createImageData(W, H);
    var ed = edgeData.data;
    for(var i = 0, j = 0; i < N; i++, j += 4){
      if(ebThick[i] > 0){
        ed[j] = 0; ed[j+1] = 255; ed[j+2] = 100; ed[j+3] = hv ? 200 : 100;
      }
    }
    ctx.putImageData(edgeData, 0, 0);
  }

  // ── Layer 2: LAB delta heatmap ──
  if(flags.wfg3ColorEvidence && artf.wfg3_labDelta){
    var labD = artf.wfg3_labDelta;
    var maxD = 0;
    for(var li = 0; li < N; li++) if(labD[li] > maxD) maxD = labD[li];
    if(maxD < 1) maxD = 1;
    var labImg = ctx.createImageData(W, H);
    var ld = labImg.data;
    for(var lj = 0, lk = 0; lj < N; lj++, lk += 4){
      var v = labD[lj] / maxD;
      if(v > 0.02){
        ld[lk]   = Math.round(v * 255);
        ld[lk+1] = Math.round((1 - Math.abs(v - 0.5) * 2) * 200);
        ld[lk+2] = Math.round((1 - v) * 255);
        ld[lk+3] = hv ? Math.round(100 + v * 180) : Math.round(40 + v * 140);
      }
    }
    ctx.putImageData(labImg, 0, 0);
  }

  // ── Layer 3: Gradient magnitude ──
  if(flags.wfg3ClosureEvidence && artf.wfg3_gradMag){
    var gm = artf.wfg3_gradMag;
    var maxG = 0;
    for(var gi = 0; gi < N; gi++) if(gm[gi] > maxG) maxG = gm[gi];
    if(maxG < 1) maxG = 1;
    var gradImg = ctx.createImageData(W, H);
    var gd = gradImg.data;
    for(var gj = 0, gk = 0; gj < N; gj++, gk += 4){
      var gv = gm[gj] / maxG;
      if(gv > 0.03){
        gd[gk] = 255; gd[gk+1] = 255; gd[gk+2] = 0;
        gd[gk+3] = hv ? Math.round(gv * 220) : Math.round(gv * 120);
      }
    }
    ctx.putImageData(gradImg, 0, 0);
  }

  // ── Layer 6: Region partition coloring (Stage E) ──
  if(flags.wfg3PartitionOverlay && artf.wfg3_labelMap){
    var lm = artf.wfg3_labelMap;
    var rc = artf.wfg3_regionCount || 0;
    if(rc > 0){
      var regionColors = [];
      for(var rci = 0; rci <= rc; rci++){
        regionColors.push((rci * 137.508) % 360);
      }
      var partImg = ctx.createImageData(W, H);
      var pd = partImg.data;
      var partAlpha = hv ? 120 : 55;
      var sat = hv ? 0.85 : 0.6;
      var rC2 = sat; // at l=0.5, chroma = sat
      var rm2 = 0.5 - rC2 / 2;
      for(var pj = 0, pk = 0; pj < N; pj++, pk += 4){
        var rl = lm[pj];
        if(rl > 0){
          var rh = regionColors[rl] || 0;
          var rX2 = rC2 * (1 - Math.abs(((rh / 60) % 2) - 1));
          var rr1, rg1, rb1;
          var rhs = (rh / 60) | 0;
          if(rhs === 0){ rr1 = rC2; rg1 = rX2; rb1 = 0; }
          else if(rhs === 1){ rr1 = rX2; rg1 = rC2; rb1 = 0; }
          else if(rhs === 2){ rr1 = 0; rg1 = rC2; rb1 = rX2; }
          else if(rhs === 3){ rr1 = 0; rg1 = rX2; rb1 = rC2; }
          else if(rhs === 4){ rr1 = rX2; rg1 = 0; rb1 = rC2; }
          else { rr1 = rC2; rg1 = 0; rb1 = rX2; }
          pd[pk]   = Math.round((rr1 + rm2) * 255);
          pd[pk+1] = Math.round((rg1 + rm2) * 255);
          pd[pk+2] = Math.round((rb1 + rm2) * 255);
          pd[pk+3] = partAlpha;
        }
      }
      ctx.putImageData(partImg, 0, 0);
    }
  }

  // ── Layer 7: Region boundaries (Stage E) — dilated bright yellow ──
  if(flags.wfg3AtomicRegions && artf.wfg3_regionBoundaries){
    var rb = artf.wfg3_regionBoundaries;
    var rbThick = hv ? dilateMask(rb, W, H, 1) : rb;
    var rbImg = ctx.createImageData(W, H);
    var rbd = rbImg.data;
    for(var rbi = 0, rbj = 0; rbi < N; rbi++, rbj += 4){
      if(rbThick[rbi] > 0){
        rbd[rbj] = 255; rbd[rbj+1] = 255; rbd[rbj+2] = 0; rbd[rbj+3] = hv ? 240 : 140;
      }
    }
    ctx.putImageData(rbImg, 0, 0);
  }

  // ── Layer 8: Group boundaries (Stage F) — dilated thick bright cyan ──
  if(flags.wfg3GroupBoundaries && artf.wfg3_groupBoundaries){
    var gb = artf.wfg3_groupBoundaries;
    var gbThick = hv ? dilateMask(gb, W, H, 2) : gb;
    var gbImg = ctx.createImageData(W, H);
    var gbd = gbImg.data;
    for(var gbi = 0, gbj = 0; gbi < N; gbi++, gbj += 4){
      if(gbThick[gbi] > 0){
        gbd[gbj] = 0; gbd[gbj+1] = 255; gbd[gbj+2] = 255; gbd[gbj+3] = 255;
      }
    }
    ctx.putImageData(gbImg, 0, 0);
  }

  // ── Layer 9: Chain mask (Stage D) — rendered as thick magenta lines ──
  if(flags.wfg3Chains && artf.wfg3_chainMask){
    var cm = artf.wfg3_chainMask;
    var cmThick = hv ? dilateMask(cm, W, H, 2) : dilateMask(cm, W, H, 1);
    var cmImg = ctx.createImageData(W, H);
    var cmd = cmImg.data;
    for(var cmi = 0, cmj = 0; cmi < N; cmi++, cmj += 4){
      if(cmThick[cmi] > 0){
        cmd[cmj] = 255; cmd[cmj+1] = 0; cmd[cmj+2] = 255; cmd[cmj+3] = hv ? 240 : 180;
      }
    }
    ctx.putImageData(cmImg, 0, 0);
  }

  // ── Layer 9b: Bridge edges (Stage D Pass 2) — dotted cyan lines ──
  if(flags.wfg3Chains && artf.wfg3_bridgeEdgeList && artf.wfg3_bridgeEdgeList.length > 0){
    ctx.save();
    ctx.strokeStyle = hv ? 'rgba(0,255,255,0.9)' : 'rgba(0,220,220,0.7)';
    ctx.lineWidth = hv ? 3 : 1.5;
    ctx.setLineDash(hv ? [6, 4] : [3, 2]);
    ctx.lineCap = 'round';
    var bEdges = artf.wfg3_bridgeEdgeList;
    for(var bei = 0; bei < bEdges.length; bei++){
      var be = bEdges[bei];
      ctx.beginPath();
      ctx.moveTo(be.fromX, be.fromY);
      ctx.lineTo(be.toX, be.toY);
      ctx.stroke();
    }
    ctx.setLineDash([]);
    ctx.restore();
  }

  // ── Layer 4: Boundary tokens — spatially balanced subset, reduced glyph size ──
  // Selection: spatial grid ensures even coverage across the image regardless of
  // token array order. The underlying token array is NOT modified.
  // Rendering mode is one of:
  //   "all (N)"                    — every token drawn
  //   "balanced M/N"               — one best-confidence token per grid cell
  var _tokenRenderMode = '';
  if(flags.wfg3Tokens && tokens.length > 0){
    var DISPLAY_LIMIT = 800;
    var displayTokens;
    if(tokens.length <= DISPLAY_LIMIT){
      displayTokens = tokens;
      _tokenRenderMode = 'all (' + tokens.length + ')';
    } else {
      // Partition image into ~DISPLAY_LIMIT cells; pick highest-confidence token per cell.
      var tcols = Math.max(1, Math.round(Math.sqrt(DISPLAY_LIMIT * W / (H || 1))));
      var trows = Math.max(1, Math.round(DISPLAY_LIMIT / tcols));
      var tcellW = W / tcols, tcellH = H / trows;
      var tgrid = new Array(tcols * trows).fill(null);
      for(var si = 0; si < tokens.length; si++){
        var st = tokens[si];
        var sc = Math.min(Math.floor(st.x / tcellW), tcols - 1);
        var sr = Math.min(Math.floor(st.y / tcellH), trows - 1);
        var sk = sr * tcols + sc;
        if(!tgrid[sk] || st.confidence > tgrid[sk].confidence) tgrid[sk] = st;
      }
      displayTokens = tgrid.filter(Boolean);
      _tokenRenderMode = 'balanced ' + displayTokens.length + '/' + tokens.length;
    }

    // Glyph dimensions ~25% smaller than original high-vis values
    var armLen = 10;   // tangent half-length (was 14)
    var normLen = 9;   // normal arm length (was 12)
    var haloW = 5;     // dark outline width (was 7)
    var tangentW = 3;  // (was 4)
    var normalW = 3.5; // (was 4.5)
    var antiW = 2;     // (was 3)
    var dotR = 3;      // arrowhead dot radius (was 4)
    var centerR = 2;   // center marker radius (was 3)

    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    for(var ti = 0; ti < displayTokens.length; ti++){
      var tok = displayTokens[ti];
      var alpha = hv ? 1.0 : (0.35 + tok.confidence * 0.65);

      var tx0 = tok.x - tok.tangentX * armLen;
      var ty0 = tok.y - tok.tangentY * armLen;
      var tx1 = tok.x + tok.tangentX * armLen;
      var ty1 = tok.y + tok.tangentY * armLen;
      var nxEnd = tok.x + tok.normalX * normLen;
      var nyEnd = tok.y + tok.normalY * normLen;
      var anxEnd = tok.x - tok.normalX * normLen * 0.5;
      var anyEnd = tok.y - tok.normalY * normLen * 0.5;

      // ─ Dark halo pass ─
      ctx.strokeStyle = 'rgba(0,0,0,0.85)';

      ctx.lineWidth = tangentW + haloW;
      ctx.beginPath(); ctx.moveTo(tx0, ty0); ctx.lineTo(tx1, ty1); ctx.stroke();

      ctx.lineWidth = normalW + haloW;
      ctx.beginPath(); ctx.moveTo(tok.x, tok.y); ctx.lineTo(nxEnd, nyEnd); ctx.stroke();

      ctx.lineWidth = antiW + haloW;
      ctx.beginPath(); ctx.moveTo(tok.x, tok.y); ctx.lineTo(anxEnd, anyEnd); ctx.stroke();

      // ─ Color pass: tangent (hot yellow) ─
      ctx.strokeStyle = 'rgba(255,255,0,' + alpha.toFixed(2) + ')';
      ctx.lineWidth = tangentW;
      ctx.beginPath(); ctx.moveTo(tx0, ty0); ctx.lineTo(tx1, ty1); ctx.stroke();

      // ─ Color pass: normal (electric green) ─
      ctx.strokeStyle = 'rgba(0,255,0,' + alpha.toFixed(2) + ')';
      ctx.lineWidth = normalW;
      ctx.beginPath(); ctx.moveTo(tok.x, tok.y); ctx.lineTo(nxEnd, nyEnd); ctx.stroke();

      // Arrowhead dot with halo
      ctx.fillStyle = 'rgba(0,0,0,0.85)';
      ctx.beginPath(); ctx.arc(nxEnd, nyEnd, dotR + 2, 0, 6.283); ctx.fill();
      ctx.fillStyle = 'rgba(0,255,0,' + alpha.toFixed(2) + ')';
      ctx.beginPath(); ctx.arc(nxEnd, nyEnd, dotR, 0, 6.283); ctx.fill();

      // ─ Color pass: anti-normal (bright red) ─
      ctx.strokeStyle = 'rgba(255,0,0,' + alpha.toFixed(2) + ')';
      ctx.lineWidth = antiW;
      ctx.beginPath(); ctx.moveTo(tok.x, tok.y); ctx.lineTo(anxEnd, anyEnd); ctx.stroke();

      // ─ Center crosshair marker ─
      if(centerR > 0){
        ctx.fillStyle = 'rgba(0,0,0,0.9)';
        ctx.beginPath(); ctx.arc(tok.x, tok.y, centerR + 1.5, 0, 6.283); ctx.fill();
        ctx.fillStyle = 'rgba(255,255,255,0.95)';
        ctx.beginPath(); ctx.arc(tok.x, tok.y, centerR, 0, 6.283); ctx.fill();
      }
    }
  }

  // ── Layer 5: Confidence heatmap (debug) — large filled squares ──
  if(flags.wfg3TokenConfidenceHeatmap && tokens.length > 0){
    var pixSz = hv ? 5 : 2;
    var halfPx = pixSz / 2;
    for(var ci = 0; ci < tokens.length; ci++){
      var ct = tokens[ci];
      var conf = ct.confidence;
      var cr2 = conf < 0.5 ? 255 : Math.round(255 * (1 - conf) * 2);
      var cg2 = conf > 0.5 ? 255 : Math.round(255 * conf * 2);
      // Black outline
      ctx.fillStyle = 'rgba(0,0,0,0.8)';
      ctx.fillRect(ct.x - halfPx - 1, ct.y - halfPx - 1, pixSz + 2, pixSz + 2);
      ctx.fillStyle = 'rgba(' + cr2 + ',' + cg2 + ',0,0.9)';
      ctx.fillRect(ct.x - halfPx, ct.y - halfPx, pixSz, pixSz);
    }
  }

  // ── Layer 10: Structure graph (Stage G) — nodes + typed edges ──
  if(flags.compiled && artf.wfg3_structureGraph){
    var sg = artf.wfg3_structureGraph;
    var sgNodes = sg.nodes;
    var sgEdges = sg.edges;

    // Edge type → color (bright, distinct)
    var sgTypeColor = {
      adjacent:               hv ? 'rgba(255,165,0,0.9)'  : 'rgba(255,165,0,0.5)',
      containment:            hv ? 'rgba(255,0,0,0.9)'    : 'rgba(255,0,0,0.5)',
      alignment_horizontal:   hv ? 'rgba(0,200,255,0.9)'  : 'rgba(0,200,255,0.5)',
      alignment_vertical:     hv ? 'rgba(180,0,255,0.9)'  : 'rgba(180,0,255,0.5)',
      support:                hv ? 'rgba(0,255,128,0.9)'   : 'rgba(0,255,128,0.5)',
      repetition:             hv ? 'rgba(255,255,0,0.9)'   : 'rgba(255,255,0,0.5)'
    };
    var sgEdgeW = hv ? 3.5 : 1.5;
    var sgNodeR = hv ? 7 : 4;
    var sgLabelFont = hv ? 'bold 12px monospace' : '10px monospace';

    ctx.lineCap = 'round';

    // Draw edges
    for(var sei = 0; sei < sgEdges.length; sei++){
      var se = sgEdges[sei];
      var srcN = sgNodes[se.src];
      var dstN = sgNodes[se.dst];
      if(!srcN || !dstN) continue;

      // Dark halo
      ctx.strokeStyle = 'rgba(0,0,0,0.7)';
      ctx.lineWidth = sgEdgeW + 3;
      ctx.beginPath(); ctx.moveTo(srcN.cx, srcN.cy); ctx.lineTo(dstN.cx, dstN.cy); ctx.stroke();

      // Colored edge
      ctx.strokeStyle = sgTypeColor[se.type] || 'rgba(200,200,200,0.6)';
      ctx.lineWidth = sgEdgeW;
      ctx.beginPath(); ctx.moveTo(srcN.cx, srcN.cy); ctx.lineTo(dstN.cx, dstN.cy); ctx.stroke();
    }

    // Draw nodes
    for(var nid in sgNodes){
      var sn = sgNodes[nid];
      // Halo
      ctx.fillStyle = 'rgba(0,0,0,0.8)';
      ctx.beginPath(); ctx.arc(sn.cx, sn.cy, sgNodeR + 2, 0, 6.283); ctx.fill();
      // Node
      ctx.fillStyle = hv ? 'rgba(0,255,255,1)' : 'rgba(0,255,255,0.8)';
      ctx.beginPath(); ctx.arc(sn.cx, sn.cy, sgNodeR, 0, 6.283); ctx.fill();
      // Label
      ctx.font = sgLabelFont;
      ctx.fillStyle = 'rgba(0,0,0,0.9)';
      ctx.fillText('G' + nid, sn.cx + sgNodeR + 2 + 1, sn.cy + 4 + 1);
      ctx.fillStyle = '#fff';
      ctx.fillText('G' + nid, sn.cx + sgNodeR + 2, sn.cy + 4);
    }

    // Edge type legend (bottom-left)
    if(hv){
      var legendTypes = ['adjacent','containment','alignment_horizontal','alignment_vertical','support','repetition'];
      var legendLabels = ['Adjacent','Containment','Align-H','Align-V','Support','Repetition'];
      var lgX = 8, lgY = H - 10 - legendTypes.length * 16;
      ctx.fillStyle = 'rgba(0,0,0,0.85)';
      ctx.fillRect(lgX - 4, lgY - 14, 130, legendTypes.length * 16 + 10);
      ctx.font = 'bold 10px monospace';
      for(var lgi = 0; lgi < legendTypes.length; lgi++){
        var ly = lgY + lgi * 16;
        ctx.fillStyle = sgTypeColor[legendTypes[lgi]];
        ctx.fillRect(lgX, ly, 12, 10);
        ctx.fillStyle = '#fff';
        ctx.fillText(legendLabels[lgi], lgX + 16, ly + 9);
      }
    }
  }

  // ── Atomic region outlines/labels (Stage E) ──
  if(flags.wfg3AtomicRegions && Array.isArray(gl.graph.nodes) && gl.graph.nodes.length){
    ctx.save();
    ctx.lineWidth = hv ? 1.8 : 1.2;
    ctx.strokeStyle = 'rgba(255,255,255,0.9)';
    ctx.fillStyle = 'rgba(0,0,0,0.85)';
    ctx.font = 'bold 10px "IBM Plex Mono", monospace';
    for(var ari = 0; ari < gl.graph.nodes.length; ari++){
      var an = gl.graph.nodes[ari];
      var ab = an?.bbox || {};
      if(!(ab.w > 0 && ab.h > 0)) continue;
      ctx.strokeRect(ab.x, ab.y, ab.w, ab.h);
      ctx.fillRect(ab.x, ab.y - 11, 26, 11);
      ctx.fillStyle = 'rgba(255,255,255,0.95)';
      ctx.fillText('R' + String(an.id), ab.x + 2, ab.y - 2);
      ctx.fillStyle = 'rgba(0,0,0,0.85)';
    }
    ctx.restore();
  }

  // ── Group overlay (Stage F grouped label map + group ids) ──
  if(flags.wfg3Groups && gl.groupedGraph?.labelMap){
    var gMap = gl.groupedGraph.labelMap;
    var gCount = gl.groupedGraph.groupCount || 0;
    if(gCount > 0){
      var gImg = ctx.createImageData(W, H);
      var gData = gImg.data;
      for(var gi2 = 0, gj2 = 0; gi2 < N; gi2++, gj2 += 4){
        var glbl = gMap[gi2];
        if(glbl > 0){
          var gh = (glbl * 97.113) % 360;
          var gs = 0.65, glt = 0.5;
          var gc = (1 - Math.abs(2 * glt - 1)) * gs;
          var gx = gc * (1 - Math.abs(((gh / 60) % 2) - 1));
          var gm3 = glt - gc / 2;
          var gr1 = 0, gg1 = 0, gb1 = 0;
          var ghs = (gh / 60) | 0;
          if(ghs === 0){ gr1 = gc; gg1 = gx; }
          else if(ghs === 1){ gr1 = gx; gg1 = gc; }
          else if(ghs === 2){ gg1 = gc; gb1 = gx; }
          else if(ghs === 3){ gg1 = gx; gb1 = gc; }
          else if(ghs === 4){ gr1 = gx; gb1 = gc; }
          else { gr1 = gc; gb1 = gx; }
          gData[gj2] = Math.round((gr1 + gm3) * 255);
          gData[gj2 + 1] = Math.round((gg1 + gm3) * 255);
          gData[gj2 + 2] = Math.round((gb1 + gm3) * 255);
          gData[gj2 + 3] = hv ? 72 : 55;
        }
      }
      ctx.putImageData(gImg, 0, 0);
    }
  }

  if(flags.wfg3SharedBoundaries && artf.partitionSharedBoundaries){
    var wb = artf.partitionSharedBoundaries;
    var wbImg = ctx.createImageData(W, H);
    var wbd = wbImg.data;
    for(var wbi = 0, wbj = 0; wbi < N; wbi++, wbj += 4){
      if(wb[wbi]){
        wbd[wbj] = 255; wbd[wbj + 1] = 255; wbd[wbj + 2] = 255; wbd[wbj + 3] = hv ? 200 : 120;
      }
    }
    ctx.putImageData(wbImg, 0, 0);
  }


  // ── WFG3 info badge ──
  ctx.save();
  var badge = 'WFG3 A\u2013H';
  if(hv) badge += ' [HIGH VIS]';
  var backend = artf.wfg3_backend || '?';
  var info = badge + '  |  ' + (artf.wfg3_tokenCount || 0) + ' tok  |  ' +
    (artf.wfg3_chainCount || 0) + ' chains  |  ' +
    (artf.wfg3_regionCount || 0) + ' rgn  |  ' +
    (artf.wfg3_groupCount || 0) + ' grp  |  ' +
    (artf.wfg3_structureEdgeCount || 0) + ' struct  |  ' + backend;

  // Build seed strategy line
  var prm = gl.params || {};
  var seedMode = prm.tokenSeedingMode || 'tile_min_coverage';
  var seedModeLabels = {
    'tile_min_coverage': 'TileMinCov',
    'global_stride': 'GlobalStride',
    'uniform_scaffold': 'UniformScaffold',
    'structured_contour': 'StructuredContour'
  };
  var seedInfo = 'seed: ' + (seedModeLabels[seedMode] || seedMode);
  if(seedMode === 'uniform_scaffold'){
    seedInfo += '  |  spacing=' + (prm.scaffoldSpacingPx || 12) + 'px';
    if(prm.scaffoldStaggered) seedInfo += '  |  staggered';
    if(prm.scaffoldSnapEnabled) seedInfo += '  |  snap';
    seedInfo += '  |  gate=' + (prm.scaffoldEvidenceGateMin != null ? prm.scaffoldEvidenceGateMin : 0.04);
  } else if(seedMode === 'structured_contour'){
    seedInfo += '  |  minComp=' + (prm.structuredContourMinCompSize || 10) + 'px';
    seedInfo += '  |  arcStep=' + (prm.structuredContourArcStep || 8) + 'px';
    seedInfo += '  |  curvBoost=' + (prm.structuredContourCurvatureBoost != null ? prm.structuredContourCurvatureBoost : 2.0);
  } else {
    if(prm.seedStaggeredPass) seedInfo += '  |  staggered';
    if(prm.seedRefinementEnabled) seedInfo += '  |  corridor-refine';
    if(seedMode === 'tile_min_coverage'){
      seedInfo += '  |  tile=' + (prm.seedTileSizePx || 64) + 'px';
      seedInfo += '  |  min=' + (prm.seedMinPerTile || 2) + ' max=' + (prm.seedMaxPerTile || 40);
    }
  }

  ctx.font = 'bold 13px "IBM Plex Mono", monospace';
  var tw = ctx.measureText(info).width;
  var sw = ctx.measureText(seedInfo).width;
  var maxW = Math.max(tw, sw);
  var bx = 6, by = 6, bw = maxW + 20, bh = 50;
  ctx.fillStyle = 'rgba(0,0,0,0.92)';
  ctx.beginPath();
  _glRoundRectPath(ctx, bx, by, bw, bh, 5);
  ctx.fill();
  ctx.strokeStyle = hv ? '#00ff00' : '#4fc3f7';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  _glRoundRectPath(ctx, bx, by, bw, bh, 5);
  ctx.stroke();
  ctx.fillStyle = hv ? '#00ff00' : '#4fc3f7';
  ctx.fillText(info, bx + 10, by + 19);
  ctx.font = '12px "IBM Plex Mono", monospace';
  ctx.fillStyle = hv ? '#88ff88' : '#90caf9';
  ctx.fillText(seedInfo + (_tokenRenderMode ? '  |  tok: ' + _tokenRenderMode : ''), bx + 10, by + 38);
  ctx.restore();
};

