/* ═══ Region Selection + Merge/Separate Editing Model ═══ */

(function(){
  var selectBtn = document.getElementById('graph-learning-region-select-btn');
  var mergeBtn = document.getElementById('graph-learning-merge-selected-btn');
  var separateBtn = document.getElementById('graph-learning-separate-selected-btn');
  var clearSelBtn = document.getElementById('graph-learning-clear-selection-btn');
  var selectionInfo = document.getElementById('graph-learning-selection-info');
  var selectionAtomicIds = document.getElementById('graph-learning-selection-atomic-ids');
  var selectionGroupIds = document.getElementById('graph-learning-selection-group-ids');
  var selectionGroupMembers = document.getElementById('graph-learning-selection-group-members');
  var selectionGroupSize = document.getElementById('graph-learning-selection-group-size');
  var selectionType = document.getElementById('graph-learning-selection-type');
  var selectionActionPreview = document.getElementById('graph-learning-selection-action-preview');
  var interactionCanvas = document.getElementById('graph-learning-interaction-canvas');

  function formatPidList(values){
    if(!values || values.length === 0) return '—';
    return '[' + values.join(', ') + ']';
  }

  function buildGroupingInspectorData(gl){
    var nodes = gl.graph?.nodes || [];
    var gg = gl.groupedGraph;
    var nodeById = {};
    for(var ni = 0; ni < nodes.length; ni++) nodeById[nodes[ni].id] = nodes[ni];
    var groupIndexById = {};
    var groupPidMembersById = {};
    if(gg?.groups){
      for(var gi = 0; gi < gg.groups.length; gi++){
        var grp = gg.groups[gi];
        groupIndexById[grp.id] = gi;
        var pids = [];
        for(var mi = 0; mi < (grp.atomicMembers || []).length; mi++){
          var mNode = nodeById[grp.atomicMembers[mi]];
          if(mNode && mNode.partitionId !== undefined) pids.push(mNode.partitionId);
        }
        groupPidMembersById[grp.id] = pids.sort(function(a, b){ return a - b; });
      }
    }
    return { nodeById: nodeById, groupIndexById: groupIndexById, groupPidMembersById: groupPidMembersById };
  }

  function updateSelectionUI(){
    var gl = state.graphLearning;
    var count = gl.selectedRegions ? gl.selectedRegions.size : 0;
    if(mergeBtn) mergeBtn.disabled = count < 2;
    if(separateBtn) separateBtn.disabled = count < 2;
    if(clearSelBtn) clearSelBtn.disabled = count === 0;
    if(selectionInfo){
      if(!gl.regionSelectActive){
        selectionInfo.textContent = 'Click "Select Regions" to begin editing';
      } else if(count === 0){
        selectionInfo.textContent = 'Click regions to select them';
      } else {
        selectionInfo.textContent = count + ' region' + (count !== 1 ? 's' : '') + ' selected';
      }
    }

    var inspector = buildGroupingInspectorData(gl);
    var selectedNodeIds = gl.selectedRegions ? Array.from(gl.selectedRegions) : [];
    var selectedPids = [];
    var selectedGroupIds = new Set();
    for(var i = 0; i < selectedNodeIds.length; i++){
      var node = inspector.nodeById[selectedNodeIds[i]];
      if(!node) continue;
      selectedPids.push(node.partitionId);
      var gId = gl.groupedGraph?.membership ? gl.groupedGraph.membership[node.id] : null;
      if(gId) selectedGroupIds.add(gId);
    }
    selectedPids.sort(function(a, b){ return a - b; });
    var selectedGroupList = Array.from(selectedGroupIds);
    var groupLabels = selectedGroupList.map(function(gid){
      var idx = inspector.groupIndexById[gid];
      return idx !== undefined ? 'G' + String(idx + 1) : gid;
    });

    var memberSummaries = [];
    var uniqueGroupSizes = new Set();
    for(var gsi = 0; gsi < groupLabels.length; gsi++){
      var rawGroupId = selectedGroupList[gsi];
      var gm = inspector.groupPidMembersById[rawGroupId] || [];
      uniqueGroupSizes.add(gm.length);
      memberSummaries.push(groupLabels[gsi] + ': ' + formatPidList(gm));
    }

    var selType = 'none';
    if(selectedPids.length === 1){
      if(groupLabels.length === 1){
        var oneRaw = selectedGroupList[0];
        var oneMembers = inspector.groupPidMembersById[oneRaw] || [];
        selType = oneMembers.length > 1 ? 'single member of multi-region group' : 'single atomic region (singleton group)';
      } else {
        selType = 'single atomic region';
      }
    } else if(selectedPids.length > 1){
      selType = groupLabels.length <= 1 ? 'multiple atomic regions from same group' : 'multiple atomic regions from different groups';
    }

    var preview = 'Select one or more atomic regions.';
    if(selectedPids.length === 1){
      preview = 'Merge Selected needs at least 2 selected atomic regions.';
    } else if(selectedPids.length > 1){
      preview = groupLabels.length <= 1
        ? 'Separate Selected will add keep constraints between adjacent selected atomic regions.'
        : 'Merge Selected will add merge constraints across adjacent selected atomic regions.';
    }

    if(selectionAtomicIds) selectionAtomicIds.textContent = formatPidList(selectedPids);
    if(selectionGroupIds) selectionGroupIds.textContent = groupLabels.length ? groupLabels.join(', ') : '—';
    if(selectionGroupMembers) selectionGroupMembers.textContent = memberSummaries.length ? memberSummaries.join(' | ') : '—';
    if(selectionGroupSize) selectionGroupSize.textContent = uniqueGroupSizes.size === 1 && uniqueGroupSizes.size > 0 ? String(Array.from(uniqueGroupSizes)[0]) : (uniqueGroupSizes.size > 1 ? Array.from(uniqueGroupSizes).join(', ') : '—');
    if(selectionType) selectionType.textContent = selType;
    if(selectionActionPreview) selectionActionPreview.textContent = preview;
  }

  // Toggle region select mode
  if(selectBtn){
    selectBtn.addEventListener('click', function(){
      var gl = state.graphLearning;
      gl.regionSelectActive = !gl.regionSelectActive;
      selectBtn.style.fontWeight = gl.regionSelectActive ? '700' : '';
      selectBtn.textContent = gl.regionSelectActive ? 'Selection Active' : 'Select Regions';
      if(interactionCanvas){
        interactionCanvas.style.cursor = gl.regionSelectActive ? 'pointer' : 'default';
        interactionCanvas.style.pointerEvents = gl.regionSelectActive ? 'auto' : 'none';
      }
      // Also activate if a legacy supervision mode is off
      if(gl.regionSelectActive) gl.supervisionMode = 'region_select';
      else if(gl.supervisionMode === 'region_select') gl.supervisionMode = null;
      updateSelectionUI();
      renderGraphLearningViewer();
    });
  }

  // Clear selection
  if(clearSelBtn){
    clearSelBtn.addEventListener('click', function(){
      state.graphLearning.selectedRegions = new Set();
      updateSelectionUI();
      renderGraphLearningViewer();
    });
  }

  // Find which atomic node a surface point falls in (via labelMap lookup)
  function findRegionAtPoint(pt){
    var gl = state.graphLearning;
    if(!gl.graph?.artifacts?.partitionLabelMap || !gl.graph?.normalizedSize) return null;
    var w = gl.graph.normalizedSize.width, h = gl.graph.normalizedSize.height;
    var px = Math.round(pt.x), py = Math.round(pt.y);
    if(px < 0 || py < 0 || px >= w || py >= h) return null;
    var labelMap = gl.graph.artifacts.partitionLabelMap;
    var pid = labelMap[py * w + px];
    if(pid < 0) return null;
    // Find the node with this partitionId
    var nodes = gl.graph.nodes || [];
    for(var i = 0; i < nodes.length; i++){
      if(nodes[i].partitionId === pid) return nodes[i];
    }
    return null;
  }

  // Click on interaction canvas to select/deselect regions
  if(interactionCanvas){
    interactionCanvas.addEventListener('click', function(e){
      var gl = state.graphLearning;
      if(!gl.regionSelectActive) return;
      var rect = interactionCanvas.getBoundingClientRect();
      var surf = gl.normalizedSurface;
      if(!surf) return;
      var scaleX = surf.width / rect.width;
      var scaleY = surf.height / rect.height;
      var pt = { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
      var node = findRegionAtPoint(pt);
      if(!node) return;
      // Toggle selection
      if(gl.selectedRegions.has(node.id)){
        gl.selectedRegions.delete(node.id);
      } else {
        gl.selectedRegions.add(node.id);
      }
      updateSelectionUI();
      renderGraphLearningViewer();
    });
  }

  // Merge Selected: merge all selected regions into one group
  if(mergeBtn){
    mergeBtn.addEventListener('click', function(){
      var gl = state.graphLearning;
      if(!gl.selectedRegions || gl.selectedRegions.size < 2) return;
      var selectedIds = Array.from(gl.selectedRegions);
      var selectedPids = [];
      var nodes = gl.graph?.nodes || [];
      var nodeById = {};
      for(var i = 0; i < nodes.length; i++) nodeById[nodes[i].id] = nodes[i];
      for(var j = 0; j < selectedIds.length; j++){
        var n = nodeById[selectedIds[j]];
        if(n) selectedPids.push(n.partitionId);
      }
      // Find adjacency pairs among selected
      var selSet = new Set(selectedIds);
      var adjPairs = [];
      var edges = gl.graph?.edges || [];
      for(var ei = 0; ei < edges.length; ei++){
        if(selSet.has(edges[ei].from) && selSet.has(edges[ei].to)){
          adjPairs.push({ from: edges[ei].from, to: edges[ei].to });
        }
      }
      // Register supervision session if needed
      if(_groupingSupervision && !gl.supervisionSessionId){
        gl.supervisionSessionId = _groupingSupervision.registerSession({
          fileId: gl.fileId,
          fileName: gl.fileName,
          engineParams: gl.params,
          surfaceSize: gl.normalizedSurface ? { width: gl.normalizedSurface.width, height: gl.normalizedSurface.height } : {},
          atomicRegionCount: nodes.length,
          pipelineMode: gl.graph?.pipelineMode || 'partition'
        });
      }
      // Store the region merge edit
      if(_groupingSupervision && gl.supervisionSessionId){
        _groupingSupervision.addRegionMerge({
          sessionId: gl.supervisionSessionId,
          regionNodeIds: selectedIds,
          regionPartitionIds: selectedPids,
          adjacencyPairs: adjPairs,
          engineContext: { mergeThreshold: gl.mergeThreshold, params: gl.params }
        });
      }
      // Recompute grouped graph (the new boundary labels from the merge will take effect)
      graphLearningRecomputeGroupedGraph();
      graphLearningUpdateGroupingInfo();
      // Clear selection after action
      gl.selectedRegions = new Set();
      updateSelectionUI();
      renderGraphLearningViewer();
      var mergedGroupLabels = new Set();
      var mergedPids = [];
      var membership = gl.groupedGraph?.membership || {};
      for(var mi = 0; mi < selectedIds.length; mi++){
        var sid = selectedIds[mi];
        var gid = membership[sid];
        if(gid) mergedGroupLabels.add(graphLearningDisplayGroupId(gid, gl.groupedGraph));
        var mn = nodeById[sid];
        if(mn && mn.partitionId !== undefined) mergedPids.push(mn.partitionId);
      }
      mergedPids.sort(function(a, b){ return a - b; });
      var mergedGroupText = Array.from(mergedGroupLabels);
      graphLearningStatus('Created/updated ' + (mergedGroupText.length ? mergedGroupText.join(', ') : 'group(s)') + ' from atomic regions ' + formatPidList(mergedPids) + '.');
    });
  }

  // Separate Selected: mark selected regions as should-not-be-grouped
  if(separateBtn){
    separateBtn.addEventListener('click', function(){
      var gl = state.graphLearning;
      if(!gl.selectedRegions || gl.selectedRegions.size < 2) return;
      var selectedIds = Array.from(gl.selectedRegions);
      var selectedPids = [];
      var nodes = gl.graph?.nodes || [];
      var nodeById = {};
      for(var i = 0; i < nodes.length; i++) nodeById[nodes[i].id] = nodes[i];
      for(var j = 0; j < selectedIds.length; j++){
        var n = nodeById[selectedIds[j]];
        if(n) selectedPids.push(n.partitionId);
      }
      var selSet = new Set(selectedIds);
      var adjPairs = [];
      var edges = gl.graph?.edges || [];
      for(var ei = 0; ei < edges.length; ei++){
        if(selSet.has(edges[ei].from) && selSet.has(edges[ei].to)){
          adjPairs.push({ from: edges[ei].from, to: edges[ei].to });
        }
      }
      if(_groupingSupervision && !gl.supervisionSessionId){
        gl.supervisionSessionId = _groupingSupervision.registerSession({
          fileId: gl.fileId,
          fileName: gl.fileName,
          engineParams: gl.params,
          surfaceSize: gl.normalizedSurface ? { width: gl.normalizedSurface.width, height: gl.normalizedSurface.height } : {},
          atomicRegionCount: nodes.length,
          pipelineMode: gl.graph?.pipelineMode || 'partition'
        });
      }
      if(_groupingSupervision && gl.supervisionSessionId){
        _groupingSupervision.addRegionSeparation({
          sessionId: gl.supervisionSessionId,
          regionNodeIds: selectedIds,
          regionPartitionIds: selectedPids,
          adjacencyPairs: adjPairs,
          engineContext: { mergeThreshold: gl.mergeThreshold, params: gl.params }
        });
      }
      graphLearningRecomputeGroupedGraph();
      graphLearningUpdateGroupingInfo();
      gl.selectedRegions = new Set();
      updateSelectionUI();
      renderGraphLearningViewer();
      var separatedPids = [];
      for(var si = 0; si < selectedIds.length; si++){
        var sn = nodeById[selectedIds[si]];
        if(sn && sn.partitionId !== undefined) separatedPids.push(sn.partitionId);
      }
      separatedPids.sort(function(a, b){ return a - b; });
      var resultingGroups = new Set();
      var afterMembership = gl.groupedGraph?.membership || {};
      for(var ai = 0; ai < selectedIds.length; ai++){
        var ag = afterMembership[selectedIds[ai]];
        if(ag) resultingGroups.add(graphLearningDisplayGroupId(ag, gl.groupedGraph));
      }
      var rg = Array.from(resultingGroups);
      graphLearningStatus('Applied separation constraints to atomic regions ' + formatPidList(separatedPids) + '; resulting groups: ' + (rg.length ? rg.join(', ') : 'none') + '.');
    });
  }

  // Enable region editing buttons when a graph is generated
  var _origRunGen2 = graphLearningRunGeneration;
  graphLearningRunGeneration = function(opts){
    _origRunGen2(opts);
    if(selectBtn) selectBtn.disabled = false;
    // Clear selection on new generation
    state.graphLearning.selectedRegions = new Set();
    updateSelectionUI();
  };

  state.graphLearning.refreshSelectionInspector = updateSelectionUI;

  // Update grouping info bar to include region edit count
  var _origUpdateGroupInfo = graphLearningUpdateGroupingInfo;
  graphLearningUpdateGroupingInfo = function(){
    _origUpdateGroupInfo();
    var gl = state.graphLearning;
    var reCountEl = document.getElementById('graph-learning-region-edit-count');
    if(reCountEl && _groupingSupervision && gl.supervisionSessionId){
      var edits = _groupingSupervision.getRegionEditsForSession(gl.supervisionSessionId);
      reCountEl.textContent = edits.length;
    } else if(reCountEl){
      reCountEl.textContent = '0';
    }
  };
})();

/* ═══ WFG2 Slider-Based Parameter Controls ═══ */

/**
 * Slider definitions: each maps a UI slider (0-100) to one or more WFG2 engine params.
 * The `toParams` function converts the 0-1 normalized slider value to engine param values.
 * The `fromParams` function reads the engine params and returns a 0-1 value for the slider.
 */
const WFG2_SLIDER_DEFS = {
  colorSensitivity: {
    label: 'Color Boundary Sensitivity',
    toParams: function(t, p){
      // Low t = high colorDistFloor (less sensitive), low colorWeight
      // High t = low colorDistFloor (more sensitive), high colorWeight, high colorMergePenalty
      p.colorDistFloor = Math.round(25 - t * 25);           // 25..0
      p.colorDistCeiling = Math.round(30 + (1 - t) * 50);   // 80..30
      p.colorWeight = 0.40 + t * 0.55;                       // 0.40..0.95
      p.colorMergePenalty = 1.0 + t * 4.0;                   // 1.0..5.0
      p.colorDistGamma = 3.2 - t * 2.4;                      // 3.2..0.8
    },
    fromParams: function(p){
      return 1 - (p.colorDistFloor || 0) / 25;
    }
  },
  luminanceSuppression: {
    label: 'Brightness-Only Edge Suppression',
    toParams: function(t, p){
      // Low t = luminance contributes more, High t = luminance suppressed
      p.luminanceWeight = 0.30 - t * 0.30;                   // 0.30..0
      p.varianceWeight = 0.20 - t * 0.20;                    // 0.20..0
      p.chromaWeight = 0.50 + t * 0.50;                      // 0.50..1.0
    },
    fromParams: function(p){
      return 1 - (p.luminanceWeight || 0) / 0.30;
    }
  },
  boundarySnap: {
    label: 'Boundary Snap Tightness',
    toParams: function(t, p){
      // Low t = coarse grid, high merge. High t = fine grid, lower edge sensitivity threshold
      p.gridSize = Math.round(20 - t * 16);                  // 20..4
      p.edgeSensitivity = Math.round(100 - t * 88);          // 100..12
    },
    fromParams: function(p){
      return 1 - ((p.gridSize || 8) - 4) / 16;
    }
  },
  mergeStrength: {
    label: 'Same-Surface Merge Strength',
    toParams: function(t, p){
      // Low t = low merge. High t = aggressive merge + high uniformity bias
      p.mergeThreshold = Math.round(4 + t * 56);             // 4..60
      p.surfaceUniformityBias = t * 0.80;                    // 0..0.80
      p.fragmentationTolerance = 0.05 + t * 0.75;            // 0.05..0.80
    },
    fromParams: function(p){
      return ((p.mergeThreshold || 18) - 4) / 56;
    }
  },
  smallRegion: {
    label: 'Small Region Preservation',
    toParams: function(t, p){
      // Low t = large minRegionArea (small regions merge). High t = tiny minRegionArea (preserved)
      p.minRegionArea = 0.08 - t * 0.0799;                   // 0.08..0.0001
    },
    fromParams: function(p){
      return 1 - ((p.minRegionArea || 0.0008) - 0.0001) / 0.0799;
    }
  },
  minSignificance: {
    label: 'Minimum Region Significance',
    toParams: function(t, p){
      // Low t = tiny area threshold (noisy). High t = large threshold (only strong regions)
      p.minRegionArea = Math.max(p.minRegionArea || 0, 0.0001 + t * 0.0799); // Override upwards only
      p.rectangularBiasPenalty = t * 1.0;                     // 0..1
    },
    fromParams: function(p){
      return (p.rectangularBiasPenalty || 0);
    }
  },
  shapeContinuity: {
    label: 'Shape Continuity Reinforcement',
    toParams: function(t, p){
      p.closureWeight = t * 0.60;                             // 0..0.60
      p.parentContourBonus = t * 0.60;                        // 0..0.60
    },
    fromParams: function(p){
      return (p.closureWeight || 0) / 0.60;
    }
  },
  closureBias: {
    label: 'Closure Bias',
    toParams: function(t, p){
      p.closureRadius = Math.round(1 + t * 7);               // 1..8
      p.minEnclosingArea = 0.10 - t * 0.098;                 // 0.10..0.002
    },
    fromParams: function(p){
      return ((p.closureRadius || 3) - 1) / 7;
    }
  },
  geoSimplify: {
    label: 'Geometric Simplification',
    toParams: function(t, p){
      // Use a dedicated param so geoSimplify doesn't fight with boundarySnap over gridSize
      p.geoSimplifyLevel = t; // 0..1 stored directly
    },
    fromParams: function(p){
      return (typeof p.geoSimplifyLevel === 'number') ? p.geoSimplifyLevel : 0;
    }
  },
  /* ═══ Partition sliders ═══ */
  partitionTolerance: {
    label: 'Partition Color Tolerance',
    toParams: function(t, p){
      p.partitionColorTolerance = Math.round(3 + t * 57);  // 3..60
    },
    fromParams: function(p){
      return ((p.partitionColorTolerance || 15) - 3) / 57;
    }
  },
  partitionContinuation: {
    label: 'Boundary Continuation Strength',
    toParams: function(t, p){
      p.partitionBoundaryContinuation = t;  // 0..1
    },
    fromParams: function(p){
      return (p.partitionBoundaryContinuation ?? 0.6);
    }
  },
  partitionRefinement: {
    label: 'Local Refinement Range',
    toParams: function(t, p){
      p.partitionLocalRefinementRange = Math.round(1 + t * 31);  // 1..32
    },
    fromParams: function(p){
      return ((p.partitionLocalRefinementRange || 8) - 1) / 31;
    }
  },
  partitionScoring: {
    label: 'Region Scoring Weights',
    toParams: function(t, p){
      // Low t = favor small high-contrast (more boundary/contour weight)
      // High t = favor large uniform (more variance/closure weight)
      p.partitionScoreVarianceW = 0.10 + t * 0.40;   // 0.10..0.50
      p.partitionScoreBoundaryW = 0.40 - t * 0.25;   // 0.40..0.15
      p.partitionScoreContourW = 0.25 - t * 0.10;    // 0.25..0.15
      p.partitionScoreClosureW = 0.10 + t * 0.15;    // 0.10..0.25
      p.partitionScoreLeakW = 0.15 - t * 0.05;       // 0.15..0.10
    },
    fromParams: function(p){
      return ((p.partitionScoreVarianceW || 0.25) - 0.10) / 0.40;
    }
  }
};

const WFG2_SLIDER_IDS = Object.keys(WFG2_SLIDER_DEFS);

function wfg2ReadSlidersToParams(){
  const engine = getGraphLearningEngine();
  if(!engine) return null;
  const p = engine.copyParams(engine.DEFAULT_PARAMS);
  // Store raw slider values for reliable round-tripping (no reverse-engineering needed)
  p._sliderValues = {};
  for(const id of WFG2_SLIDER_IDS){
    const el = document.getElementById('wfg2-slider-' + id);
    if(!el) continue;
    const raw = Number(el.value);
    p._sliderValues[id] = raw;
    const t = raw / 100;
    WFG2_SLIDER_DEFS[id].toParams(t, p);
  }
  // Apply geoSimplify effect on gridSize AFTER boundarySnap has set it
  if(typeof p.geoSimplifyLevel === 'number' && p.geoSimplifyLevel > 0){
    // Increase gridSize proportionally to simplification level
    p.gridSize = Math.max(p.gridSize, Math.round(4 + p.geoSimplifyLevel * 20));
  }
  // Clamp all params to valid ranges
  p.gridSize = Math.max(4, Math.min(24, Math.round(p.gridSize)));
  p.edgeSensitivity = Math.max(8, Math.min(120, Math.round(p.edgeSensitivity)));
  p.mergeThreshold = Math.max(4, Math.min(60, Math.round(p.mergeThreshold)));
  p.minRegionArea = Math.max(0.0001, Math.min(0.08, p.minRegionArea));
  p.fragmentationTolerance = Math.max(0.05, Math.min(0.8, p.fragmentationTolerance));
  p.rectangularBiasPenalty = Math.max(0, Math.min(1, p.rectangularBiasPenalty));
  p.colorWeight = Math.max(0.3, Math.min(0.95, p.colorWeight));
  p.luminanceWeight = Math.max(0, Math.min(0.3, p.luminanceWeight));
  p.varianceWeight = Math.max(0, Math.min(0.2, p.varianceWeight));
  p.colorMergePenalty = Math.max(0.5, Math.min(5, p.colorMergePenalty));
  p.chromaWeight = Math.max(0.5, Math.min(1.0, p.chromaWeight));
  p.colorDistFloor = Math.max(0, Math.min(25, p.colorDistFloor));
  p.colorDistCeiling = Math.max(15, Math.min(80, p.colorDistCeiling));
  p.colorDistGamma = Math.max(0.5, Math.min(3.5, p.colorDistGamma));
  p.surfaceUniformityBias = Math.max(0, Math.min(0.8, p.surfaceUniformityBias));
  p.closureRadius = Math.max(1, Math.min(8, Math.round(p.closureRadius)));
  p.closureWeight = Math.max(0, Math.min(0.6, p.closureWeight));
  p.parentContourBonus = Math.max(0, Math.min(0.6, p.parentContourBonus));
  p.minEnclosingArea = Math.max(0.002, Math.min(0.1, p.minEnclosingArea));
  // Partition params clamping
  p.partitionColorTolerance = Math.max(3, Math.min(60, Math.round(p.partitionColorTolerance || 15)));
  p.partitionMinRegionPixels = Math.max(4, Math.min(2000, Math.round(p.partitionMinRegionPixels || 64)));
  p.partitionBoundaryContinuation = Math.max(0, Math.min(1, p.partitionBoundaryContinuation ?? 0.6));
  p.partitionLocalRefinementRange = Math.max(1, Math.min(32, Math.round(p.partitionLocalRefinementRange || 8)));
  // Read pipeline mode from UI
  var modeEl = document.getElementById('graph-learning-pipeline-mode');
  if(modeEl) p.pipelineMode = modeEl.value || 'partition';
  return p;
}

function wfg2SyncSlidersFromParams(params){
  if(!params) return;
  const stored = params._sliderValues || {};
  for(const id of WFG2_SLIDER_IDS){
    // Prefer stored raw slider value (exact round-trip) over reverse-engineered value
    var val;
    if(typeof stored[id] === 'number'){
      val = stored[id];
    } else {
      const def = WFG2_SLIDER_DEFS[id];
      val = Math.round(def.fromParams(params) * 100);
    }
    val = Math.max(0, Math.min(100, Math.round(val)));
    const el = document.getElementById('wfg2-slider-' + id);
    const valEl = document.getElementById('wfg2-slider-' + id + '-val');
    if(el) el.value = val;
    if(valEl) valEl.textContent = (val / 100).toFixed(2);
  }
  // Sync pipeline mode selector
  var modeSelect = document.getElementById('graph-learning-pipeline-mode');
  if(modeSelect && params.pipelineMode) modeSelect.value = params.pipelineMode;
}

function wfg2UpdateSliderDisplay(id){
  const el = document.getElementById('wfg2-slider-' + id);
  const valEl = document.getElementById('wfg2-slider-' + id + '-val');
  if(el && valEl) valEl.textContent = (Number(el.value) / 100).toFixed(2);
}

// Attach slider input events for real-time value display
for(const id of WFG2_SLIDER_IDS){
  const el = document.getElementById('wfg2-slider-' + id);
  if(el){
    el.addEventListener('input', function(){ wfg2UpdateSliderDisplay(id); });
  }
}

