/* ====================== Object Learning (ML System) ================== */

var _olEngine = window.ObjectLearningEngine || null;
var _olStore = _olEngine ? _olEngine.createObjectLearningStore(localStorage) : null;

function objectLearningStatus(msg){ if(els.objectLearningStatus) els.objectLearningStatus.textContent = msg || ''; }

function wfg2GetEffectiveParams(){
  var baseline = wfg2LoadAcceptedBaseline();
  if(baseline?.params && _wfg2) return _wfg2.copyParams(baseline.params);
  if(state.graphLearning?.params && _wfg2) return _wfg2.copyParams(state.graphLearning.params);
  return _wfg2 ? _wfg2.copyParams(_wfg2.DEFAULT_PARAMS) : null;
}

function objectLearningUsesLocalWfg3(){
  return getGraphLearningEngineType() === 'wfg3' && !!_wfg3;
}

function objectLearningGetWfg3Params(){
  if(!_wfg3) return null;
  var src = (state.graphLearning?.params && state.graphLearning.graph?.engine === 'wfg3')
    ? state.graphLearning.params
    : _wfg3.DEFAULT_PARAMS;
  var params = _wfg3.copyParams(src);
  var pipelineMode = els.objectLearningPipelineMode ? els.objectLearningPipelineMode.value : 'partition';
  params.pipelineMode = pipelineMode;
  return params;
}

function objectLearningClampBoxToSurface(box, surface){
  if(!box || !surface) return null;
  var x0 = Math.max(0, Math.floor(box.x || 0));
  var y0 = Math.max(0, Math.floor(box.y || 0));
  var x1 = Math.min(surface.width, Math.ceil((box.x || 0) + (box.w || 0)));
  var y1 = Math.min(surface.height, Math.ceil((box.y || 0) + (box.h || 0)));
  var w = Math.max(1, x1 - x0);
  var h = Math.max(1, y1 - y0);
  return { x: x0, y: y0, w: w, h: h };
}

function objectLearningCropSurface(surface, bbox){
  if(!surface || !bbox || !surface.width || !surface.height) return null;
  var crop = objectLearningClampBoxToSurface(bbox, surface);
  if(!crop) return null;
  var cw = crop.w, ch = crop.h;
  var out = {
    kind: 'wfg3-local-surface',
    width: cw,
    height: ch,
    gray: new Uint8Array(cw * ch),
    rgb: null,
    lab: null,
    source: Object.assign({}, surface.source || {}, {
      localCrop: { x: crop.x, y: crop.y, w: crop.w, h: crop.h }
    }),
    artifacts: { localCrop: { x: crop.x, y: crop.y, w: crop.w, h: crop.h } }
  };
  if(surface.rgb && surface.rgb.r && surface.rgb.g && surface.rgb.b){
    out.rgb = {
      r: new Uint8Array(cw * ch),
      g: new Uint8Array(cw * ch),
      b: new Uint8Array(cw * ch)
    };
  }
  if(surface.lab && surface.lab.L && surface.lab.a && surface.lab.b){
    out.lab = {
      L: new Float32Array(cw * ch),
      a: new Float32Array(cw * ch),
      b: new Float32Array(cw * ch)
    };
  }
  for(var y = 0; y < ch; y++){
    var srcRow = (crop.y + y) * surface.width;
    var dstRow = y * cw;
    for(var x = 0; x < cw; x++){
      var si = srcRow + crop.x + x;
      var di = dstRow + x;
      out.gray[di] = surface.gray?.[si] || 0;
      if(out.rgb){
        out.rgb.r[di] = surface.rgb.r?.[si] || 0;
        out.rgb.g[di] = surface.rgb.g?.[si] || 0;
        out.rgb.b[di] = surface.rgb.b?.[si] || 0;
      }
      if(out.lab){
        out.lab.L[di] = surface.lab.L?.[si] || 0;
        out.lab.a[di] = surface.lab.a?.[si] || 0;
        out.lab.b[di] = surface.lab.b?.[si] || 0;
      }
    }
  }
  return { crop: crop, surface: out };
}

function objectLearningTranslateLocalGraph(localGraph, crop){
  if(!localGraph) return null;
  var tx = crop?.x || 0, ty = crop?.y || 0;
  var nodes = (localGraph.nodes || []).map(function(n){
    var b = n.bbox || { x: 0, y: 0, w: 0, h: 0 };
    return Object.assign({}, n, {
      x: (n.x || 0) + tx,
      y: (n.y || 0) + ty,
      center: n.center ? { x: (n.center.x || 0) + tx, y: (n.center.y || 0) + ty } : n.center,
      bbox: { x: (b.x || 0) + tx, y: (b.y || 0) + ty, w: b.w || 0, h: b.h || 0 }
    });
  });
  var edges = (localGraph.edges || []).map(function(e){
    return Object.assign({}, e, {
      from: e.from != null ? e.from : e.source,
      to: e.to != null ? e.to : e.target
    });
  });
  return Object.assign({}, localGraph, {
    engine: 'wfg3_local_object',
    localCrop: crop,
    nodes: nodes,
    edges: edges
  });
}

function objectLearningRunWfg3LocalOnBox(box, surface){
  if(!_wfg3 || !surface || !box) return null;
  var cropped = objectLearningCropSurface(surface, box);
  if(!cropped || !cropped.surface) return null;
  var graph = _wfg3.generateFeatureGraph(cropped.surface, objectLearningGetWfg3Params() || _wfg3.DEFAULT_PARAMS);
  if(!graph) return null;
  return objectLearningTranslateLocalGraph(graph, cropped.crop);
}

function wfg2UpdateObjectLearningSummary(summary){
  var baseline = wfg2LoadAcceptedBaseline();
  if(!baseline) return;
  baseline.objectLearningSummary = summary || null;
  baseline.objectLearningUpdatedAt = new Date().toISOString();
  wfg2SaveAcceptedBaseline(baseline);
  updateObjectLearningBaselineStatus();
  wfg2UpdateStateIndicator();
}

function updateObjectLearningBaselineStatus(){
  if(!els.objectLearningBaselineStatus) return;
  var baseline = wfg2LoadAcceptedBaseline();
  if(!baseline){
    els.objectLearningBaselineStatus.textContent = 'No accepted baseline yet. Object analysis is using temporary/default tuning.';
    return;
  }
  var stamp = baseline.acceptedAt ? new Date(baseline.acceptedAt).toLocaleString() : 'unknown';
  var ol = baseline.objectLearningSummary;
  if(ol && Number.isFinite(ol.objectCohesionScore)){
    els.objectLearningBaselineStatus.textContent = 'Accepted baseline (' + stamp + ') • last cohesion ' + ol.objectCohesionScore.toFixed(1) + '% over ' + (ol.boxCount || 0) + ' object(s).';
  } else {
    els.objectLearningBaselineStatus.textContent = 'Accepted baseline (' + stamp + ') loaded. Run Object Learning analysis to record object summary.';
  }
}

function syncObjectLearningCanvases(){
  var ol = state.objectLearning;
  var surf = ol.normalizedSurface;
  var base = els.objectLearningBaseCanvas;
  var overlay = els.objectLearningOverlayCanvas;
  if(!surf || !base || !overlay) return null;
  if(base.width !== surf.width || base.height !== surf.height){ base.width = surf.width; base.height = surf.height; }
  if(overlay.width !== surf.width || overlay.height !== surf.height){ overlay.width = surf.width; overlay.height = surf.height; }
  var container = base.parentElement;
  var maxW = (container && container.clientWidth > 0) ? container.clientWidth : surf.width;
  var maxH = Math.round(window.innerHeight * 0.65);
  var fitScale = Math.min(maxW / surf.width, maxH / surf.height, 1);
  var cssW = Math.round(surf.width * fitScale) + 'px';
  var cssH = Math.round(surf.height * fitScale) + 'px';
  base.style.width = cssW; base.style.height = cssH;
  overlay.style.width = cssW; overlay.style.height = cssH;
  return { base: base, overlay: overlay, width: surf.width, height: surf.height };
}

function renderObjectLearningBaseSurface(){
  var synced = syncObjectLearningCanvases();
  if(!synced) return;
  var surf = state.objectLearning.normalizedSurface;
  var ctx = synced.base.getContext('2d', { willReadFrequently: true });
  var out = new Uint8ClampedArray(surf.width * surf.height * 4);
  var hasColor = surf.rgb && surf.rgb.r;
  for(var i = 0, j = 0; i < surf.gray.length; i++, j += 4){
    if(hasColor){ out[j] = surf.rgb.r[i] || 0; out[j + 1] = surf.rgb.g[i] || 0; out[j + 2] = surf.rgb.b[i] || 0; }
    else { var v = surf.gray[i] || 0; out[j] = v; out[j + 1] = v; out[j + 2] = v; }
    out[j + 3] = 255;
  }
  ctx.putImageData(new ImageData(out, surf.width, surf.height), 0, 0);
}

function pointInBox(pt, box){ return !!pt && pt.x >= box.x && pt.y >= box.y && pt.x <= box.x + box.w && pt.y <= box.y + box.h; }
function intersectArea(a, b){
  var x1 = Math.max(a.x, b.x), y1 = Math.max(a.y, b.y);
  var x2 = Math.min(a.x + a.w, b.x + b.w), y2 = Math.min(a.y + a.h, b.y + b.h);
  var w = x2 - x1, h = y2 - y1;
  return (w > 0 && h > 0) ? (w * h) : 0;
}

function objectLearningAnalyzeBox(box, graph){
  var nodes = graph?.nodes || [];
  var edges = graph?.edges || [];
  var boxArea = Math.max(1, box.w * box.h);
  var hits = [];
  for(var i = 0; i < nodes.length; i++){
    var node = nodes[i];
    var nb = node.bbox || { x: 0, y: 0, w: 0, h: 0 };
    var ov = intersectArea(box, nb);
    if(ov <= 0 && !pointInBox(node.center, box)) continue;
    var nodeArea = Math.max(1, (nb.w || 1) * (nb.h || 1));
    var outsideRatio = Math.max(0, nodeArea - ov) / nodeArea;
    hits.push({ node: node, overlapArea: ov, overlapRatio: ov / boxArea, outsideRatio: outsideRatio });
  }
  hits.sort(function(a, b){ return b.overlapArea - a.overlapArea; });
  var dominant = hits[0] || null;
  var dominantCoverage = dominant ? (dominant.overlapArea / boxArea) : 0;
  var fragmentation = hits.length <= 1 ? 0 : Math.min(1, (hits.length - 1) / 4);
  var leakage = 0;
  for(var h = 0; h < hits.length; h++) leakage += hits[h].outsideRatio;
  leakage = hits.length ? Math.min(1, leakage / hits.length) : 1;
  var coverageTotal = 0;
  for(var t = 0; t < hits.length; t++) coverageTotal += hits[t].overlapRatio;
  var boundaryAlignment = Math.max(0, Math.min(1, (dominantCoverage * 0.75) + ((1 - leakage) * 0.25) - Math.max(0, coverageTotal - 1) * 0.1));

  var splitBoundaries = [];
  var leakEdges = [];
  var hitIds = new Set(hits.map(function(hh){ return hh.node.id; }));
  for(var e = 0; e < edges.length; e++){
    var edge = edges[e];
    var inFrom = hitIds.has(edge.from);
    var inTo = hitIds.has(edge.to);
    if(inFrom && inTo) splitBoundaries.push(edge);
    else if(inFrom || inTo) leakEdges.push(edge);
  }

  var classification = 'coherent';
  if(!hits.length || dominantCoverage < 0.35) classification = 'unstable';
  else if(hits.length >= 3 || fragmentation > 0.5) classification = 'split';
  else if(leakage > 0.45 && dominantCoverage > 0.55) classification = 'merged';
  else if(leakage > 0.22 || leakEdges.length > splitBoundaries.length + 1) classification = 'leaking';

  return {
    boxId: box.id,
    classification: classification,
    metrics: {
      intersectingRegions: hits.length,
      dominantRegionCoveragePct: dominantCoverage * 100,
      fragmentationScore: fragmentation,
      leakageScore: leakage,
      boundaryAlignmentScore: boundaryAlignment
    },
    overlay: {
      hitNodes: hits.map(function(hh){ return hh.node.id; }),
      splitBoundaries: splitBoundaries,
      leakEdges: leakEdges,
      dominantNodeId: dominant?.node?.id || null
    },
    constraints: {
      shouldNotSplit: true,
      shouldNotMergeExternally: true,
      shouldRemainStable: true
    },
    objectiveContribution: Math.max(0, Math.min(1, (dominantCoverage * 0.45) + ((1 - fragmentation) * 0.2) + ((1 - leakage) * 0.25) + (boundaryAlignment * 0.1)))
  };
}

function objectLearningBuildAggregate(analyses){
  if(!analyses.length) return null;
  var cohesive = 0, fragment = 0, leak = 0, passed = 0;
  analyses.forEach(function(a){
    cohesive += a.objectiveContribution;
    fragment += a.metrics.fragmentationScore;
    leak += a.metrics.leakageScore;
    if(a.classification === 'coherent') passed++;
  });
  var score = (cohesive / analyses.length) * 100;
  return {
    boxCount: analyses.length,
    objectCohesionScore: score,
    fragmentationAverage: fragment / analyses.length,
    leakageAverage: leak / analyses.length,
    passedCount: passed,
    failedCount: analyses.length - passed,
    autoTuneObjective: cohesive / analyses.length,
    constraints: analyses.map(function(a){ return { boxId: a.boxId, classification: a.classification, objectiveContribution: a.objectiveContribution, constraints: a.constraints }; })
  };
}

function renderObjectLearningResults(){
  if(els.objectLearningResults){
    var analyses = state.objectLearning.analyses || [];
    if(!analyses.length){
      els.objectLearningResults.innerHTML = '<p class="sub" style="color:var(--muted);">Draw boxes and click Analyze Objects.</p>';
    } else {
      els.objectLearningResults.innerHTML = analyses.map(function(a, idx){
        var m = a.metrics;
        return '<div style="border-bottom:1px solid var(--border,#eee);padding:8px 0;">' +
          '<strong>Box #' + (idx + 1) + '</strong> — <span style="text-transform:capitalize;">' + a.classification + '</span>' +
          '<div class="sub" style="margin-top:4px;color:var(--muted);">' +
          'regions=' + m.intersectingRegions +
          ', dominant=' + m.dominantRegionCoveragePct.toFixed(1) + '%' +
          ', fragmentation=' + m.fragmentationScore.toFixed(2) +
          ', leakage=' + m.leakageScore.toFixed(2) +
          ', boundary=' + m.boundaryAlignmentScore.toFixed(2) +
          '</div>' +
          '</div>';
      }).join('');
    }
  }
  var agg = state.objectLearning.aggregate;
  if(els.objectLearningSummary){
    if(!agg) els.objectLearningSummary.textContent = 'No analysis yet.';
    else els.objectLearningSummary.textContent = 'Object cohesion ' + agg.objectCohesionScore.toFixed(1) + '% • fragmentation avg ' + agg.fragmentationAverage.toFixed(2) + ' • leakage avg ' + agg.leakageAverage.toFixed(2) + ' • passed ' + agg.passedCount + '/' + agg.boxCount + '.';
  }
}

function objectLearningDrawOverlay(ctx){
  var ol = state.objectLearning;
  var graph = ol.graph;
  var showCompiled = !!els.objectLearningShowCompiled?.checked;
  var showRegions = !!els.objectLearningShowRegions?.checked;
  var showRegionIds = !!els.objectLearningShowRegionIds?.checked;
  var showAdjacency = !!els.objectLearningShowAdjacency?.checked;
  var showPartition = !!els.objectLearningShowPartition?.checked;
  var showHierarchy = !!els.objectLearningShowHierarchy?.checked;
  var showAnalysis = !!els.objectLearningShowAnalysis?.checked;
  var nodes = graph?.nodes || [];
  var edges = graph?.edges || [];

  // Partition overlay (colored regions, matching Graph Learning)
  if(showPartition && graph?.partition?.labelMap){
    var labelMap = graph.partition.labelMap;
    var regionCount = graph.partition.regionCount || 0;
    var surf = ol.normalizedSurface;
    if(surf && labelMap.length === surf.width * surf.height){
      var w = surf.width, h = surf.height;
      var imgData = ctx.getImageData(0, 0, w, h);
      var d = imgData.data;
      var palette = _objectLearningPartitionPalette(regionCount);
      for(var pi = 0, pj = 0; pi < labelMap.length; pi++, pj += 4){
        var label = labelMap[pi];
        if(label >= 0 && label < palette.length){
          var pc = palette[label];
          d[pj] = (d[pj] * 0.6 + pc[0] * 0.4) | 0;
          d[pj+1] = (d[pj+1] * 0.6 + pc[1] * 0.4) | 0;
          d[pj+2] = (d[pj+2] * 0.6 + pc[2] * 0.4) | 0;
        }
      }
      ctx.putImageData(imgData, 0, 0);
    }
  }

  // Compiled graph contours
  if(showCompiled){
    for(var i = 0; i < nodes.length; i++){
      var c = nodes[i].contour || [];
      if(c.length < 3) continue;
      ctx.fillStyle = 'rgba(33,150,243,0.08)';
      ctx.strokeStyle = 'rgba(0,150,136,0.7)';
      ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(c[0].x, c[0].y);
      for(var j = 1; j < c.length; j++) ctx.lineTo(c[j].x, c[j].y);
      ctx.closePath(); ctx.fill(); ctx.stroke();
    }
  }

  // Region bounding boxes
  if(showRegions){
    nodes.forEach(function(n){
      var b = n.bbox || {};
      ctx.strokeStyle = 'rgba(63,81,181,0.5)';
      ctx.lineWidth = 1;
      ctx.strokeRect(b.x||0, b.y||0, b.w||0, b.h||0);
    });
  }

  // Region IDs / labels
  if(showRegionIds){
    ctx.font = '10px IBM Plex Mono, monospace';
    ctx.textBaseline = 'top';
    nodes.forEach(function(n, idx){
      var b = n.bbox || {};
      var label = n.id || ('R' + idx);
      // Shorten ID for display
      var shortId = label.replace('wfg2-p-', 'R');
      ctx.fillStyle = 'rgba(0,0,0,0.7)';
      ctx.fillRect((b.x||0), (b.y||0), ctx.measureText(shortId).width + 4, 12);
      ctx.fillStyle = '#fff';
      ctx.fillText(shortId, (b.x||0) + 2, (b.y||0) + 1);
    });
    ctx.textBaseline = 'alphabetic';
  }

  // Adjacency edges
  if(showAdjacency){
    var nodeMap = new Map(nodes.map(function(n){ return [n.id, n]; }));
    ctx.strokeStyle = 'rgba(255,152,0,0.4)';
    ctx.lineWidth = 1;
    edges.forEach(function(edge){
      var a = nodeMap.get(edge.from), b = nodeMap.get(edge.to);
      if(!a || !b) return;
      ctx.beginPath();
      ctx.moveTo(a.center?.x || 0, a.center?.y || 0);
      ctx.lineTo(b.center?.x || 0, b.center?.y || 0);
      ctx.stroke();
    });
  }

  // Hierarchy (containment) lines
  if(showHierarchy){
    // Draw containment edges if present
    var nodeMap2 = new Map(nodes.map(function(n){ return [n.id, n]; }));
    edges.forEach(function(edge){
      if(edge.kind !== 'contains' && edge.kind !== 'containment') return;
      var a = nodeMap2.get(edge.from), b = nodeMap2.get(edge.to);
      if(!a || !b) return;
      ctx.strokeStyle = 'rgba(156,39,176,0.5)';
      ctx.lineWidth = 2;
      ctx.setLineDash([3, 3]);
      ctx.beginPath();
      ctx.moveTo(a.center?.x || 0, a.center?.y || 0);
      ctx.lineTo(b.center?.x || 0, b.center?.y || 0);
      ctx.stroke();
      ctx.setLineDash([]);
    });
  }

  // Reference BBOX highlight
  if(ol.referenceBbox){
    var rb = ol.referenceBbox;
    ctx.strokeStyle = '#e91e63';
    ctx.lineWidth = 3;
    ctx.setLineDash([8, 4]);
    ctx.strokeRect(rb.x, rb.y, rb.w, rb.h);
    ctx.setLineDash([]);
    ctx.font = 'bold 12px IBM Plex Mono, monospace';
    ctx.fillStyle = '#e91e63';
    ctx.fillText('REF: ' + (ol.currentFieldName || ol.currentFieldId || 'field'), rb.x + 4, Math.max(14, rb.y - 6));
  }

  // User-drawn boxes
  ol.boxes.forEach(function(box, idx){
    var analysis = (ol.analyses || []).find(function(a){ return a.boxId === box.id; });
    var color = analysis
      ? (analysis.classification === 'coherent' ? '#2a7' : analysis.classification === 'split' ? '#c44' : analysis.classification === 'merged' ? '#a24' : analysis.classification === 'leaking' ? '#d9822b' : '#666')
      : '#4a90e2';
    ctx.fillStyle = color + '22';
    ctx.strokeStyle = color;
    ctx.lineWidth = 2;
    ctx.fillRect(box.x, box.y, box.w, box.h);
    ctx.strokeRect(box.x, box.y, box.w, box.h);
    ctx.font = '11px IBM Plex Mono, monospace';
    ctx.fillStyle = color;
    ctx.fillText('#' + (idx + 1) + (analysis ? (' ' + analysis.classification) : ''), box.x + 4, Math.max(12, box.y - 4));

    if(showAnalysis && analysis){
      var nMap = new Map(nodes.map(function(n){ return [n.id, n]; }));
      ctx.strokeStyle = 'rgba(255,82,82,0.85)';
      ctx.lineWidth = 1;
      analysis.overlay.splitBoundaries.forEach(function(edge){
        var a = nMap.get(edge.from), b = nMap.get(edge.to);
        if(!a || !b) return;
        ctx.beginPath(); ctx.moveTo(a.center?.x || 0, a.center?.y || 0); ctx.lineTo(b.center?.x || 0, b.center?.y || 0); ctx.stroke();
      });
      ctx.strokeStyle = 'rgba(255,193,7,0.85)';
      analysis.overlay.leakEdges.forEach(function(edge){
        var a = nMap.get(edge.from), b = nMap.get(edge.to);
        if(!a || !b) return;
        ctx.beginPath(); ctx.moveTo(a.center?.x || 0, a.center?.y || 0); ctx.lineTo(b.center?.x || 0, b.center?.y || 0); ctx.stroke();
      });
    }
  });

  // Drawing in progress
  if(ol.drawing){
    var dd = ol.drawing;
    ctx.setLineDash([6, 4]);
    ctx.strokeStyle = '#009688';
    ctx.lineWidth = 2;
    ctx.strokeRect(dd.x, dd.y, dd.w, dd.h);
    ctx.setLineDash([]);
  }
}

function _objectLearningPartitionPalette(count){
  var palette = [];
  for(var i = 0; i < Math.max(count, 1); i++){
    var hue = (i * 137.508) % 360;
    var r, g, b;
    var h = hue / 60, f = h - Math.floor(h);
    var s = 0.6, l = 0.7;
    var c = (1 - Math.abs(2 * l - 1)) * s;
    var x = c * (1 - Math.abs(h % 2 - 1));
    var m = l - c / 2;
    if(h < 1){ r = c; g = x; b = 0; }
    else if(h < 2){ r = x; g = c; b = 0; }
    else if(h < 3){ r = 0; g = c; b = x; }
    else if(h < 4){ r = 0; g = x; b = c; }
    else if(h < 5){ r = x; g = 0; b = c; }
    else { r = c; g = 0; b = x; }
    palette.push([(r + m) * 255 | 0, (g + m) * 255 | 0, (b + m) * 255 | 0]);
  }
  return palette;
}

function renderObjectLearningViewer(){
  var synced = syncObjectLearningCanvases();
  if(!synced) return;
  renderObjectLearningBaseSurface();
  var octx = synced.overlay.getContext('2d');
  octx.clearRect(0, 0, synced.width, synced.height);
  objectLearningDrawOverlay(octx);
}

function clearObjectLearningViewer(){
  var base = els.objectLearningBaseCanvas;
  var overlay = els.objectLearningOverlayCanvas;
  if(base){ var bctx = base.getContext('2d'); bctx.clearRect(0,0,base.width||1,base.height||1); }
  if(overlay){ var octx = overlay.getContext('2d'); octx.clearRect(0,0,overlay.width||1,overlay.height||1); }
}

function objectLearningUpdateButtons(){
  var hasBoxes = (state.objectLearning.boxes || []).length > 0;
  if(els.objectLearningUndoBtn) els.objectLearningUndoBtn.disabled = !hasBoxes;
  if(els.objectLearningClearBtn) els.objectLearningClearBtn.disabled = !hasBoxes;
  var readyForAnalyze = objectLearningUsesLocalWfg3()
    ? (!!state.objectLearning.normalizedSurface && hasBoxes)
    : (!!state.objectLearning.graph && hasBoxes);
  if(els.objectLearningAnalyzeBtn) els.objectLearningAnalyzeBtn.disabled = !readyForAnalyze;
}

function objectLearningAnalyze(){
  var ol = state.objectLearning;
  if(!ol.boxes.length){ objectLearningStatus('Upload file and draw at least one object box.'); return; }
  if(objectLearningUsesLocalWfg3()){
    if(!ol.normalizedSurface){ objectLearningStatus('Upload file before running WFG3 local object analysis.'); return; }
    ol.localGraphsByBox = {};
    ol.analyses = ol.boxes.map(function(b){
      var localGraph = objectLearningRunWfg3LocalOnBox(b, ol.normalizedSurface);
      if(localGraph) ol.localGraphsByBox[b.id] = localGraph;
      return objectLearningAnalyzeBox(b, localGraph || { nodes: [], edges: [] });
    });
  } else {
    if(!ol.graph){ objectLearningStatus('Upload file and draw at least one object box.'); return; }
    ol.analyses = ol.boxes.map(function(b){ return objectLearningAnalyzeBox(b, ol.graph); });
  }
  ol.aggregate = objectLearningBuildAggregate(ol.analyses);
  ol.constraints = ol.aggregate?.constraints || [];
  ol.objective = ol.aggregate?.autoTuneObjective || 0;
  renderObjectLearningResults();
  renderObjectLearningViewer();
  if(ol.aggregate){
    objectLearningStatus('Analyzed ' + ol.aggregate.boxCount + ' object(s): cohesion ' + ol.aggregate.objectCohesionScore.toFixed(1) + '%.');
    wfg2UpdateObjectLearningSummary({
      boxCount: ol.aggregate.boxCount,
      objectCohesionScore: ol.aggregate.objectCohesionScore,
      fragmentationAverage: ol.aggregate.fragmentationAverage,
      leakageAverage: ol.aggregate.leakageAverage,
      passedCount: ol.aggregate.passedCount,
      failedCount: ol.aggregate.failedCount,
      objective: ol.aggregate.autoTuneObjective,
      analyzedAt: new Date().toISOString()
    });
  }
}

function objectLearningCanvasToSurfacePoint(evt){
  var canvas = els.objectLearningOverlayCanvas;
  if(!canvas) return null;
  var rect = canvas.getBoundingClientRect();
  var sx = canvas.width / Math.max(1, rect.width);
  var sy = canvas.height / Math.max(1, rect.height);
  return { x: (evt.clientX - rect.left) * sx, y: (evt.clientY - rect.top) * sy };
}

function objectLearningBindDrawing(){
  var canvas = els.objectLearningOverlayCanvas;
  if(!canvas || canvas._objBound) return;
  var isDown = false;
  canvas.addEventListener('pointerdown', function(evt){
    if(!state.objectLearning.normalizedSurface) return;
    var p = objectLearningCanvasToSurfacePoint(evt); if(!p) return;
    isDown = true;
    state.objectLearning.drawing = { startX: p.x, startY: p.y, x: p.x, y: p.y, w: 1, h: 1 };
    renderObjectLearningViewer();
  });
  canvas.addEventListener('pointermove', function(evt){
    if(!isDown || !state.objectLearning.drawing) return;
    var p = objectLearningCanvasToSurfacePoint(evt); if(!p) return;
    var d = state.objectLearning.drawing;
    d.x = Math.min(d.startX, p.x); d.y = Math.min(d.startY, p.y);
    d.w = Math.abs(p.x - d.startX); d.h = Math.abs(p.y - d.startY);
    renderObjectLearningViewer();
  });
  function finishDraw(){
    if(!isDown) return;
    isDown = false;
    var d = state.objectLearning.drawing;
    state.objectLearning.drawing = null;
    if(d && d.w >= 8 && d.h >= 8){
      state.objectLearning.boxes.push({ id: 'objbox-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2,6), x: d.x, y: d.y, w: d.w, h: d.h });
      state.objectLearning.analyses = [];
      state.objectLearning.aggregate = null;
      objectLearningStatus('Box added. Click Analyze Objects to evaluate constraints.');
    }
    objectLearningUpdateButtons();
    renderObjectLearningResults();
    renderObjectLearningViewer();
  }
  canvas.addEventListener('pointerup', finishDraw);
  canvas.addEventListener('pointerleave', function(){ if(isDown) finishDraw(); });
  canvas._objBound = true;
}

function objectLearningRunGeneration(){
  var ol = state.objectLearning;
  if(!ol.normalizedSurface) return;
  if(objectLearningUsesLocalWfg3()){
    // WFG3 local mode intentionally does not build a full-document graph in Object Learning.
    // Local graph processing is run per user-selected box at analysis/reference time.
    ol.graph = {
      engine: 'wfg3_local_object',
      localOnly: true,
      nodes: [],
      edges: [],
      partition: null
    };
  } else {
    if(!_wfg2) return;
    var params = wfg2GetEffectiveParams();
    // Use the pipeline mode from Object Learning's own selector (parity with Graph Learning)
    var pipelineMode = els.objectLearningPipelineMode ? els.objectLearningPipelineMode.value : 'partition';
    if(params) params.pipelineMode = pipelineMode;
    ol.graph = _wfg2.generateFeatureGraph(ol.normalizedSurface, params || _wfg2.DEFAULT_PARAMS);
  }
  objectLearningUpdateButtons();
  renderObjectLearningViewer();
}

async function objectLearningOpenFile(file){
  if(!file) return;
  if(!objectLearningUsesLocalWfg3() && !_wfg2) return;
  state.objectLearning.active = true;
  state.objectLearning.fileName = file.name || 'untitled';
  state.objectLearning.fileId = 'wfg2obj-' + Date.now().toString(36);
  state.objectLearning.boxes = [];
  state.objectLearning.analyses = [];
  state.objectLearning.aggregate = null;
  state.objectLearning.objective = null;
  state.objectLearning.constraints = [];
  clearObjectLearningViewer();
  renderObjectLearningResults();
  objectLearningStatus('Loading file…');
  state.selectedEngineType = ENGINE_KIND.WROKIT_VISION;
  try { await openFile(file); }
  catch(err){
    console.error('[WFG2][ObjectLearning] openFile failed', err);
    objectLearningStatus('Could not load this file for Object Learning.');
    return;
  }
  var page = state.pageNum || 1;
  var img = graphLearningCaptureGray(page);
  if(!img || !img.width || !img.height){ objectLearningStatus('File loaded but no render surface was available.'); return; }
  state.objectLearning.normalizedSurface = objectLearningUsesLocalWfg3()
    ? _wfg3.normalizeVisualInput(img, { maxSide: 1300 })
    : _wfg2.normalizeVisualInput(img, { maxSide: 1300 });
  if(!state.objectLearning.normalizedSurface){ objectLearningStatus('Normalization failed for this file.'); return; }
  renderObjectLearningBaseSurface();
  objectLearningRunGeneration();
  objectLearningBindDrawing();
  updateObjectLearningBaselineStatus();
  objectLearningStatus(
    objectLearningUsesLocalWfg3()
      ? 'File loaded (WFG3 local mode). Draw object boxes; analysis runs only inside each selected box.'
      : 'File loaded. Draw one or more object boxes, then click Analyze Objects.'
  );
}

if(els.objectLearningFileInput){
  els.objectLearningFileInput.addEventListener('change', async function(e){
    var file = e.target.files?.[0];
    if(!file) return;
    e.target.value = '';
    await objectLearningOpenFile(file);
  });
}
if(els.objectLearningUndoBtn){
  els.objectLearningUndoBtn.addEventListener('click', function(){
    if(!state.objectLearning.boxes.length) return;
    state.objectLearning.boxes.pop();
    state.objectLearning.analyses = [];
    state.objectLearning.aggregate = null;
    objectLearningUpdateButtons();
    renderObjectLearningResults();
    renderObjectLearningViewer();
  });
}
if(els.objectLearningClearBtn){
  els.objectLearningClearBtn.addEventListener('click', function(){
    state.objectLearning.boxes = [];
    state.objectLearning.analyses = [];
    state.objectLearning.aggregate = null;
    objectLearningUpdateButtons();
    renderObjectLearningResults();
    renderObjectLearningViewer();
    objectLearningStatus('All object boxes cleared.');
  });
}
if(els.objectLearningAnalyzeBtn){ els.objectLearningAnalyzeBtn.addEventListener('click', objectLearningAnalyze); }
[els.objectLearningShowCompiled, els.objectLearningShowRegions, els.objectLearningShowRegionIds,
 els.objectLearningShowAdjacency, els.objectLearningShowPartition, els.objectLearningShowHierarchy,
 els.objectLearningShowAnalysis].forEach(function(el){
  if(!el) return;
  el.addEventListener('change', function(){ renderObjectLearningViewer(); });
});
// Pipeline mode change re-runs generation
if(els.objectLearningPipelineMode){
  els.objectLearningPipelineMode.addEventListener('change', function(){
    if(state.objectLearning.normalizedSurface) objectLearningRunGeneration();
  });
}
updateObjectLearningBaselineStatus();
objectLearningUpdateButtons();
renderObjectLearningResults();

/* ── Object Learning ML System ─────────────────────────────────────────── */

// Initialize scoring model
if(_olEngine && !state.objectLearning.scoringModel){
  state.objectLearning.scoringModel = _olEngine.createScoringModel();
}

/* ── Mode switching ────────────────────────────────────────────────────── */

function objectLearningSetMode(mode){
  state.objectLearning.mode = mode;
  if(els.objectLearningReferencePanel) els.objectLearningReferencePanel.style.display = mode === 'reference' ? '' : 'none';
  if(els.objectLearningBatchPanel) els.objectLearningBatchPanel.style.display = mode === 'batch' ? '' : 'none';
  if(els.objectLearningReviewPanel) els.objectLearningReviewPanel.style.display = mode === 'review' ? '' : 'none';
  if(mode === 'review') objectLearningRenderReview();
}

if(els.objectLearningModeSelect){
  els.objectLearningModeSelect.addEventListener('change', function(){
    objectLearningSetMode(this.value);
  });
}

/* ── Field management ──────────────────────────────────────────────────── */

function objectLearningRefreshFieldSelect(){
  if(!els.objectLearningFieldSelect || !_olStore) return;
  var configs = _olStore.getAllFieldConfigs();
  var select = els.objectLearningFieldSelect;
  // Keep the (new field) option
  while(select.options.length > 1) select.remove(1);
  Object.keys(configs).forEach(function(fid){
    var opt = document.createElement('option');
    opt.value = fid;
    opt.textContent = configs[fid].field_id + (configs[fid].training_count ? ' (' + configs[fid].training_count + ' examples)' : '');
    select.appendChild(opt);
  });
}

function objectLearningLoadField(fieldId){
  if(!_olStore || !_olEngine) return;
  var config = _olStore.getFieldConfig(fieldId);
  if(!config){
    if(els.objectLearningFieldStatus) els.objectLearningFieldStatus.textContent = 'Field not found.';
    return;
  }
  var ol = state.objectLearning;
  ol.currentFieldId = config.field_id;
  ol.currentFieldName = config.field_id;
  ol.fieldConfig = config;
  ol.referenceDescriptor = config.reference_descriptor || null;
  ol.referenceBbox = config.reference_bbox || null;
  ol.referenceGraphStats = config.reference_graph_stats || null;
  // Restore model weights
  if(ol.scoringModel && config.model_weights){
    ol.scoringModel.setWeights(config.model_weights);
  }
  if(ol.scoringModel && config.training_data){
    ol.scoringModel.setTrainingData(config.training_data);
  }
  if(els.objectLearningFieldName) els.objectLearningFieldName.value = config.field_id;
  if(els.objectLearningFieldStatus) els.objectLearningFieldStatus.textContent = 'Loaded field: ' + config.field_id + ' (' + (config.training_count || 0) + ' training examples)';
  objectLearningUpdateSetReferenceBtn();
  renderObjectLearningViewer();
  objectLearningRenderDescriptor();
}

if(els.objectLearningFieldSelect){
  els.objectLearningFieldSelect.addEventListener('change', function(){
    var val = this.value;
    if(val) objectLearningLoadField(val);
    else {
      // New field mode
      state.objectLearning.currentFieldId = null;
      state.objectLearning.currentFieldName = '';
      state.objectLearning.fieldConfig = null;
      state.objectLearning.referenceDescriptor = null;
      state.objectLearning.referenceBbox = null;
      if(els.objectLearningFieldName) els.objectLearningFieldName.value = '';
      if(els.objectLearningFieldStatus) els.objectLearningFieldStatus.textContent = '';
      objectLearningUpdateSetReferenceBtn();
    }
  });
}

if(els.objectLearningCreateFieldBtn){
  els.objectLearningCreateFieldBtn.addEventListener('click', function(){
    var name = (els.objectLearningFieldName?.value || '').trim();
    if(!name){
      if(els.objectLearningFieldStatus) els.objectLearningFieldStatus.textContent = 'Please enter a field name.';
      return;
    }
    var fieldId = name.toLowerCase().replace(/[^a-z0-9_]/g, '_');
    state.objectLearning.currentFieldId = fieldId;
    state.objectLearning.currentFieldName = name;

    // Check if field already exists
    if(_olStore){
      var existing = _olStore.getFieldConfig(fieldId);
      if(existing){
        objectLearningLoadField(fieldId);
        return;
      }
    }

    if(els.objectLearningFieldStatus) els.objectLearningFieldStatus.textContent = 'Field "' + name + '" ready. Upload a reference image and draw a BBOX.';
    objectLearningUpdateSetReferenceBtn();
    objectLearningRefreshFieldSelect();
  });
}

/* ── Set Reference BBOX ────────────────────────────────────────────────── */

function objectLearningUpdateSetReferenceBtn(){
  if(!els.objectLearningSetReferenceBtn) return;
  var ol = state.objectLearning;
  var hasGraphContext = objectLearningUsesLocalWfg3()
    ? !!ol.normalizedSurface
    : !!ol.graph;
  els.objectLearningSetReferenceBtn.disabled = !(ol.currentFieldId && ol.boxes.length === 1 && hasGraphContext);
}

if(els.objectLearningSetReferenceBtn){
  els.objectLearningSetReferenceBtn.addEventListener('click', function(){
    var ol = state.objectLearning;
    if(!ol.currentFieldId || !ol.boxes.length || !_olEngine) return;

    var bbox = ol.boxes[0]; // Use the first drawn box as the reference
    var surfaceSize = { width: ol.normalizedSurface?.width || 1, height: ol.normalizedSurface?.height || 1 };
    var refGraph = ol.graph;
    if(objectLearningUsesLocalWfg3()){
      if(!ol.normalizedSurface) return;
      refGraph = objectLearningRunWfg3LocalOnBox(bbox, ol.normalizedSurface);
      if(!refGraph){
        objectLearningStatus('WFG3 local reference extraction failed for the selected box.');
        return;
      }
    } else if(!ol.graph){
      return;
    }

    // Build reference descriptor
    ol.referenceDescriptor = _olEngine.buildReferenceDescriptor(bbox, refGraph, surfaceSize);
    ol.referenceBbox = { x: bbox.x, y: bbox.y, w: bbox.w, h: bbox.h };

    // Capture reference graph statistics for graph normalization
    ol.referenceGraphStats = _olEngine.computeGraphStats(refGraph, surfaceSize);

    // Create or update field config
    ol.fieldConfig = _olEngine.createFieldConfig(ol.currentFieldId, ol.referenceBbox, ol.referenceDescriptor);
    // Store graph stats in the config for persistence
    ol.fieldConfig.reference_graph_stats = ol.referenceGraphStats;

    // Save to store
    if(_olStore){
      _olStore.saveFieldConfig(ol.currentFieldId, ol.fieldConfig);
    }

    objectLearningStatus('Reference set for field "' + ol.currentFieldId + '". Switch to Batch Processing to train.');
    objectLearningRenderDescriptor();
    renderObjectLearningViewer();
    objectLearningRefreshFieldSelect();
  });
}

function objectLearningRenderDescriptor(){
  if(els.objectLearningDescriptorOutput){
    var desc = state.objectLearning.referenceDescriptor;
    if(!desc){
      els.objectLearningDescriptorOutput.textContent = 'No reference defined yet.';
    } else {
      els.objectLearningDescriptorOutput.textContent = JSON.stringify(desc, null, 2);
    }
  }
  var statsEl = document.getElementById('object-learning-ref-graph-stats');
  if(statsEl){
    var stats = state.objectLearning.referenceGraphStats;
    if(!stats){
      statsEl.textContent = 'No reference graph stats yet.';
    } else {
      statsEl.textContent = JSON.stringify(stats, null, 2);
    }
  }
}

// Listen to box changes to update the set-reference button
var _origFinishDraw = null;
// We hook into existing box updates by overriding objectLearningUpdateButtons
var _origUpdateButtons = objectLearningUpdateButtons;
objectLearningUpdateButtons = function(){
  _origUpdateButtons();
  objectLearningUpdateSetReferenceBtn();
};

/* ── Batch Processing ──────────────────────────────────────────────────── */

if(els.objectLearningBatchInput){
  els.objectLearningBatchInput.addEventListener('change', function(e){
    var files = Array.from(e.target.files || []);
    e.target.value = '';
    if(!files.length) return;
    var ol = state.objectLearning;
    if(!ol.currentFieldId || !ol.referenceDescriptor){
      objectLearningStatus('Define a field and set a reference BBOX first.');
      return;
    }
    ol.batchFiles = files;
    ol.batchIndex = -1;
    ol.batchFeedbackGiven = false;
    objectLearningRenderBatchQueue();
    if(els.objectLearningBatchStatus) els.objectLearningBatchStatus.textContent = files.length + ' files queued. Processing will start with the first file.';
    // Start processing the first file
    objectLearningProcessNextBatchDoc();
  });
}

function objectLearningRenderBatchQueue(){
  if(!els.objectLearningBatchQueue) return;
  var ol = state.objectLearning;
  if(!ol.batchFiles.length){
    els.objectLearningBatchQueue.innerHTML = '<span class="sub" style="color:var(--muted);">No files queued.</span>';
    return;
  }
  var html = '<div style="display:flex;flex-wrap:wrap;gap:6px;">';
  ol.batchFiles.forEach(function(f, idx){
    var isCurrent = idx === ol.batchIndex;
    var isDone = idx < ol.batchIndex;
    var bg = isCurrent ? '#e3f2fd' : isDone ? '#e8f5e9' : '#f5f5f5';
    var border = isCurrent ? '#2196f3' : isDone ? '#4caf50' : '#ddd';
    html += '<span style="padding:2px 8px;border-radius:4px;font-size:11px;border:1px solid ' + border + ';background:' + bg + ';">';
    html += (isDone ? '&#10003; ' : isCurrent ? '&#9654; ' : '') + (f.name || 'file ' + (idx + 1));
    html += '</span>';
  });
  html += '</div>';
  els.objectLearningBatchQueue.innerHTML = html;
  if(els.objectLearningBatchProgress){
    els.objectLearningBatchProgress.textContent = 'Progress: ' + Math.max(0, ol.batchIndex) + ' / ' + ol.batchFiles.length;
  }
}

async function objectLearningProcessNextBatchDoc(){
  var ol = state.objectLearning;
  ol.batchIndex++;
  if(ol.batchIndex >= ol.batchFiles.length){
    // Batch complete
    objectLearningBatchComplete();
    return;
  }

  ol.batchFeedbackGiven = false;
  ol.batchAdjustedBbox = null;
  ol.batchDrawing = null;
  ol.batchCurrentPrediction = null;
  ol.batchCurrentCandidates = [];

  var file = ol.batchFiles[ol.batchIndex];
  objectLearningRenderBatchQueue();
  if(els.objectLearningBatchDocPanel) els.objectLearningBatchDocPanel.style.display = '';
  if(els.objectLearningBatchDocInfo) els.objectLearningBatchDocInfo.textContent = 'Processing: ' + (file.name || 'document') + ' (' + (ol.batchIndex + 1) + '/' + ol.batchFiles.length + ')';
  objectLearningBatchUpdateFeedbackBtns();

  // Load file through the same pipeline
  if(!_wfg2) return;
  state.selectedEngineType = ENGINE_KIND.WROKIT_VISION;
  try { await openFile(file); } catch(err){
    console.error('[ObjectLearning][Batch] openFile failed', err);
    if(els.objectLearningBatchDocInfo) els.objectLearningBatchDocInfo.textContent = 'Failed to load: ' + (file.name || 'document');
    return;
  }

  var page = state.pageNum || 1;
  var img = graphLearningCaptureGray(page);
  if(!img || !img.width || !img.height){
    if(els.objectLearningBatchDocInfo) els.objectLearningBatchDocInfo.textContent = 'No render surface for: ' + (file.name || 'document');
    return;
  }

  ol.batchCurrentSurface = _wfg2.normalizeVisualInput(img, { maxSide: 1300 });
  if(!ol.batchCurrentSurface) return;

  var params = wfg2GetEffectiveParams();
  var pipelineMode = els.objectLearningPipelineMode ? els.objectLearningPipelineMode.value : 'partition';
  if(params) params.pipelineMode = pipelineMode;
  var surfaceSize = { width: ol.batchCurrentSurface.width, height: ol.batchCurrentSurface.height };

  // ── Pre-match graph normalization stage ──
  // If we have reference graph stats, run multiple WFG2 variants and select
  // the graph most structurally similar to the reference.
  ol.batchNormalizationResult = null;
  if(ol.referenceGraphStats && _olEngine.selectBestGraph){
    if(els.objectLearningBatchDocInfo){
      els.objectLearningBatchDocInfo.textContent = 'Normalizing graph for: ' + (file.name || 'document') + ' (' + (ol.batchIndex + 1) + '/' + ol.batchFiles.length + ')';
    }
    var normResult = _olEngine.selectBestGraph(
      ol.batchCurrentSurface,
      ol.referenceGraphStats,
      params || _wfg2.DEFAULT_PARAMS,
      _wfg2.generateFeatureGraph,
      _wfg2.copyParams,
      { variantCount: 9, pipelineMode: pipelineMode }
    );
    ol.batchNormalizationResult = normResult;
    ol.batchCurrentGraph = normResult.bestGraph;
  } else {
    // Fallback: single WFG2 run (no normalization)
    ol.batchCurrentGraph = _wfg2.generateFeatureGraph(ol.batchCurrentSurface, params || _wfg2.DEFAULT_PARAMS);
  }

  if(els.objectLearningBatchDocInfo){
    var normInfo = ol.batchNormalizationResult
      ? ' | graph normalized (variant: ' + ol.batchNormalizationResult.bestLabel + ', similarity: ' + ol.batchNormalizationResult.bestSimilarity.toFixed(3) + ', tested: ' + ol.batchNormalizationResult.variantCount + ')'
      : '';
    els.objectLearningBatchDocInfo.textContent = 'Processing: ' + (file.name || 'document') + ' (' + (ol.batchIndex + 1) + '/' + ol.batchFiles.length + ')' + normInfo;
  }

  // Generate candidates and score them
  var candidates = _olEngine.generateCandidates(ol.batchCurrentGraph, surfaceSize);
  var scored = _olEngine.scoreAndRankCandidates(candidates, ol.referenceDescriptor, ol.batchCurrentGraph, surfaceSize, ol.scoringModel);
  ol.batchCurrentCandidates = scored;
  ol.batchCurrentPrediction = scored[0] || null;

  // Render
  objectLearningRenderBatchViewer();
  objectLearningRenderPredictionInfo();
  objectLearningRenderCandidatesList();
  objectLearningRenderNormalizationInfo();
  objectLearningBatchBindDrawing();
  objectLearningBatchUpdateFeedbackBtns();
}

function objectLearningRenderBatchViewer(){
  var ol = state.objectLearning;
  var surf = ol.batchCurrentSurface;
  var base = els.objectLearningBatchBaseCanvas;
  var overlay = els.objectLearningBatchOverlayCanvas;
  if(!surf || !base || !overlay) return;

  if(base.width !== surf.width || base.height !== surf.height){ base.width = surf.width; base.height = surf.height; }
  if(overlay.width !== surf.width || overlay.height !== surf.height){ overlay.width = surf.width; overlay.height = surf.height; }

  var container = base.parentElement;
  var maxW = (container && container.clientWidth > 0) ? container.clientWidth : surf.width;
  var maxH = Math.round(window.innerHeight * 0.65);
  var fitScale = Math.min(maxW / surf.width, maxH / surf.height, 1);
  var cssW = Math.round(surf.width * fitScale) + 'px';
  var cssH = Math.round(surf.height * fitScale) + 'px';
  base.style.width = cssW; base.style.height = cssH;
  overlay.style.width = cssW; overlay.style.height = cssH;

  // Draw base image
  var ctx = base.getContext('2d', { willReadFrequently: true });
  var out = new Uint8ClampedArray(surf.width * surf.height * 4);
  var hasColor = surf.rgb && surf.rgb.r;
  for(var i = 0, j = 0; i < surf.gray.length; i++, j += 4){
    if(hasColor){ out[j] = surf.rgb.r[i] || 0; out[j+1] = surf.rgb.g[i] || 0; out[j+2] = surf.rgb.b[i] || 0; }
    else { var v = surf.gray[i] || 0; out[j] = v; out[j+1] = v; out[j+2] = v; }
    out[j+3] = 255;
  }
  ctx.putImageData(new ImageData(out, surf.width, surf.height), 0, 0);

  // Draw overlay
  var octx = overlay.getContext('2d');
  octx.clearRect(0, 0, surf.width, surf.height);
  objectLearningDrawBatchOverlay(octx);
}

function objectLearningDrawBatchOverlay(ctx){
  var ol = state.objectLearning;
  var graph = ol.batchCurrentGraph;
  var nodes = graph?.nodes || [];
  var showCompiled = !!els.objectLearningBatchShowCompiled?.checked;
  var showRegions = !!els.objectLearningBatchShowRegions?.checked;
  var showRegionIds = !!els.objectLearningBatchShowRegionIds?.checked;
  var showPrediction = !!els.objectLearningBatchShowPrediction?.checked;

  if(showCompiled){
    for(var i = 0; i < nodes.length; i++){
      var c = nodes[i].contour || [];
      if(c.length < 3) continue;
      ctx.fillStyle = 'rgba(33,150,243,0.08)';
      ctx.strokeStyle = 'rgba(0,150,136,0.7)';
      ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(c[0].x, c[0].y);
      for(var j = 1; j < c.length; j++) ctx.lineTo(c[j].x, c[j].y);
      ctx.closePath(); ctx.fill(); ctx.stroke();
    }
  }

  if(showRegions){
    nodes.forEach(function(n){
      var b = n.bbox || {};
      ctx.strokeStyle = 'rgba(63,81,181,0.3)';
      ctx.lineWidth = 1;
      ctx.strokeRect(b.x||0, b.y||0, b.w||0, b.h||0);
    });
  }

  if(showRegionIds){
    ctx.font = '10px IBM Plex Mono, monospace';
    ctx.textBaseline = 'top';
    nodes.forEach(function(n){
      var b = n.bbox || {};
      var shortId = (n.id || '').replace('wfg2-p-', 'R');
      ctx.fillStyle = 'rgba(0,0,0,0.6)';
      ctx.fillRect(b.x||0, b.y||0, ctx.measureText(shortId).width + 4, 12);
      ctx.fillStyle = '#fff';
      ctx.fillText(shortId, (b.x||0) + 2, (b.y||0) + 1);
    });
    ctx.textBaseline = 'alphabetic';
  }

  // Prediction BBOX
  if(showPrediction && ol.batchCurrentPrediction){
    var pred = ol.batchCurrentPrediction;
    var pb = pred.bbox;
    ctx.strokeStyle = '#4caf50';
    ctx.lineWidth = 3;
    ctx.strokeRect(pb.x, pb.y, pb.w, pb.h);
    ctx.fillStyle = 'rgba(76,175,80,0.15)';
    ctx.fillRect(pb.x, pb.y, pb.w, pb.h);
    ctx.font = 'bold 12px IBM Plex Mono, monospace';
    ctx.fillStyle = '#4caf50';
    ctx.fillText('PREDICTED (score: ' + pred.score.toFixed(3) + ')', pb.x + 4, Math.max(14, pb.y - 6));
  }

  // Adjusted BBOX (user correction)
  if(ol.batchAdjustedBbox){
    var ab = ol.batchAdjustedBbox;
    ctx.strokeStyle = '#ff9800';
    ctx.lineWidth = 3;
    ctx.setLineDash([6, 3]);
    ctx.strokeRect(ab.x, ab.y, ab.w, ab.h);
    ctx.setLineDash([]);
    ctx.font = 'bold 12px IBM Plex Mono, monospace';
    ctx.fillStyle = '#ff9800';
    ctx.fillText('ADJUSTED', ab.x + 4, Math.max(14, ab.y - 6));
  }

  // Drawing in progress (for adjust mode)
  if(ol.batchDrawing){
    var bd = ol.batchDrawing;
    ctx.setLineDash([6, 4]);
    ctx.strokeStyle = '#ff9800';
    ctx.lineWidth = 2;
    ctx.strokeRect(bd.x, bd.y, bd.w, bd.h);
    ctx.setLineDash([]);
  }
}

function objectLearningRenderPredictionInfo(){
  if(!els.objectLearningPredictionInfo) return;
  var ol = state.objectLearning;
  var pred = ol.batchCurrentPrediction;
  if(!pred){
    els.objectLearningPredictionInfo.textContent = 'No candidates found.';
    return;
  }
  els.objectLearningPredictionInfo.textContent =
    'Best match: ' + pred.candidate_id + ' (score: ' + pred.score.toFixed(4) + ')' +
    ' | bbox: [' + Math.round(pred.bbox.x) + ',' + Math.round(pred.bbox.y) + ',' + Math.round(pred.bbox.w) + ',' + Math.round(pred.bbox.h) + ']' +
    ' | candidates: ' + ol.batchCurrentCandidates.length;
}

function objectLearningRenderCandidatesList(){
  if(!els.objectLearningCandidatesList) return;
  var candidates = state.objectLearning.batchCurrentCandidates;
  if(!candidates.length){
    els.objectLearningCandidatesList.innerHTML = '<span class="sub" style="color:var(--muted);">No candidates.</span>';
    return;
  }
  var html = candidates.slice(0, 20).map(function(c, idx){
    return '<div style="border-bottom:1px solid var(--border,#eee);padding:4px 0;font-size:11px;">' +
      '<strong>#' + (idx + 1) + '</strong> ' + c.candidate_id +
      ' — score: ' + c.score.toFixed(4) +
      ' | bbox: [' + Math.round(c.bbox.x) + ',' + Math.round(c.bbox.y) + ',' + Math.round(c.bbox.w) + ',' + Math.round(c.bbox.h) + ']' +
      '</div>';
  }).join('');
  if(candidates.length > 20) html += '<div class="sub" style="color:var(--muted);padding:4px 0;">...and ' + (candidates.length - 20) + ' more</div>';
  els.objectLearningCandidatesList.innerHTML = html;
}

/* ── Graph Normalization Debug ──────────────────────────────────────── */

function objectLearningRenderNormalizationInfo(){
  var el = document.getElementById('object-learning-normalization-info');
  if(!el) return;
  var ol = state.objectLearning;
  var nr = ol.batchNormalizationResult;
  if(!nr){
    el.innerHTML = '<span class="sub" style="color:var(--muted);">No graph normalization performed (no reference graph stats available).</span>';
    return;
  }

  var refStats = ol.referenceGraphStats;
  // Build the selected graph stats
  var selectedStats = null;
  if(nr.variants && nr.variants.length){
    var best = nr.variants.find(function(v){ return v.label === nr.bestLabel; });
    selectedStats = best?.stats || null;
  }

  var html = '<div style="margin-bottom:8px;">';
  html += '<strong>Selected variant:</strong> <span style="color:#2196f3;font-weight:600;">' + nr.bestLabel + '</span>';
  html += ' | <strong>Similarity:</strong> ' + nr.bestSimilarity.toFixed(4);
  html += ' | <strong>Variants tested:</strong> ' + nr.variantCount;
  html += '</div>';

  // Reference vs Selected stats comparison
  if(refStats && selectedStats){
    html += '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:4px;font-size:11px;margin-bottom:8px;">';
    html += '<div style="font-weight:600;">Metric</div><div style="font-weight:600;">Reference</div><div style="font-weight:600;">Selected</div>';
    var pairs = [
      ['Region count', refStats.region_count, selectedStats.region_count],
      ['Meaningful regions', refStats.meaningful_region_count, selectedStats.meaningful_region_count],
      ['Avg region area', (refStats.avg_region_area * 100).toFixed(2) + '%', (selectedStats.avg_region_area * 100).toFixed(2) + '%'],
      ['Median region area', (refStats.median_region_area * 100).toFixed(2) + '%', (selectedStats.median_region_area * 100).toFixed(2) + '%'],
      ['Dominant coverage', (refStats.dominant_region_coverage * 100).toFixed(1) + '%', (selectedStats.dominant_region_coverage * 100).toFixed(1) + '%'],
      ['Area CV', refStats.area_cv.toFixed(2), selectedStats.area_cv.toFixed(2)],
      ['Avg edges/node', refStats.avg_edges_per_node.toFixed(2), selectedStats.avg_edges_per_node.toFixed(2)],
      ['Max depth', refStats.containment_depth_max, selectedStats.containment_depth_max],
      ['Quality', refStats.quality_score.toFixed(2), selectedStats.quality_score.toFixed(2)]
    ];
    pairs.forEach(function(p){
      html += '<div>' + p[0] + '</div><div>' + p[1] + '</div><div>' + p[2] + '</div>';
    });
    html += '</div>';
  }

  // Similarity component breakdown
  if(nr.variants && nr.variants[0]?.components){
    var best = nr.variants[0]; // already sorted by similarity
    html += '<div style="margin-bottom:8px;"><strong>Similarity components (best):</strong></div>';
    html += '<div style="display:grid;grid-template-columns:1fr auto auto;gap:4px;font-size:11px;">';
    html += '<div style="font-weight:600;">Component</div><div style="font-weight:600;">Score</div><div style="font-weight:600;">Weight</div>';
    Object.entries(best.components).forEach(function(entry){
      var name = entry[0], comp = entry[1];
      html += '<div>' + name.replace(/_/g, ' ') + '</div>';
      html += '<div>' + comp.score.toFixed(3) + '</div>';
      html += '<div>' + comp.weight.toFixed(2) + '</div>';
    });
    html += '</div>';
  }

  // Top variants table
  html += '<div style="margin-top:8px;"><strong>Top variants:</strong></div>';
  html += '<div style="font-size:11px;max-height:150px;overflow:auto;">';
  var topN = Math.min(nr.variants.length, 8);
  for(var i = 0; i < topN; i++){
    var v = nr.variants[i];
    var isBest = v.label === nr.bestLabel;
    html += '<div style="padding:2px 0;' + (isBest ? 'font-weight:600;color:#2196f3;' : '') + '">';
    html += (i + 1) + '. ' + v.label + ' — similarity: ' + v.similarity.toFixed(4) + ' | regions: ' + (v.region_count || '?');
    if(isBest) html += ' (selected)';
    html += '</div>';
  }
  html += '</div>';

  el.innerHTML = html;
}

/* ── Batch feedback ────────────────────────────────────────────────────── */

function objectLearningBatchUpdateFeedbackBtns(){
  var ol = state.objectLearning;
  var hasDoc = ol.batchIndex >= 0 && ol.batchIndex < ol.batchFiles.length;
  var hasPred = !!ol.batchCurrentPrediction;
  var feedbackGiven = ol.batchFeedbackGiven;

  if(els.objectLearningConfirmBtn) els.objectLearningConfirmBtn.disabled = !hasDoc || !hasPred || feedbackGiven;
  if(els.objectLearningAdjustBtn) els.objectLearningAdjustBtn.disabled = !hasDoc || feedbackGiven;
  if(els.objectLearningRejectBtn) els.objectLearningRejectBtn.disabled = !hasDoc || !hasPred || feedbackGiven;
  if(els.objectLearningNextBtn) els.objectLearningNextBtn.disabled = !hasDoc || !feedbackGiven;
}

function objectLearningLogTrainingData(selectedBbox, isPositive){
  var ol = state.objectLearning;
  if(!_olEngine || !ol.referenceDescriptor || !ol.batchCurrentGraph) return;

  var surfaceSize = { width: ol.batchCurrentSurface?.width || 1, height: ol.batchCurrentSurface?.height || 1 };

  // Log all candidates: the selected one as positive, others as negative
  ol.batchCurrentCandidates.forEach(function(cand){
    var isSelected = false;
    if(selectedBbox && isPositive){
      // Check if this candidate is the one being confirmed/adjusted
      isSelected = _olEngine.iou(cand.bbox, selectedBbox) > 0.5;
    }
    var label = isSelected ? 1 : 0;
    if(ol.scoringModel){
      ol.scoringModel.addTrainingExample(cand.feature_vector, label);
    }
    // Also store in field config
    if(ol.fieldConfig){
      _olEngine.addTrainingExample(ol.fieldConfig, {
        field_id: ol.currentFieldId,
        reference_id: ol.referenceDescriptor.primary_region_id,
        candidate_id: cand.candidate_id,
        feature_vector: cand.feature_vector,
        label: label,
        document_index: ol.batchIndex,
        timestamp: new Date().toISOString()
      });
    }
  });

  // If rejecting, log ALL as negative (no positive)
  if(!isPositive){
    // Already logged all as 0 above since isSelected would be false
  }

  // Update model weights after new data
  if(ol.scoringModel) ol.scoringModel.updateWeights();

  // Save updated config
  if(_olStore && ol.fieldConfig){
    ol.fieldConfig.model_weights = ol.scoringModel ? ol.scoringModel.getWeights() : null;
    ol.fieldConfig.updated_at = new Date().toISOString();
    _olStore.saveFieldConfig(ol.currentFieldId, ol.fieldConfig);
  }
}

// Confirm prediction
if(els.objectLearningConfirmBtn){
  els.objectLearningConfirmBtn.addEventListener('click', function(){
    var ol = state.objectLearning;
    if(!ol.batchCurrentPrediction) return;
    ol.batchFeedbackGiven = true;
    objectLearningLogTrainingData(ol.batchCurrentPrediction.bbox, true);
    objectLearningBatchUpdateFeedbackBtns();
    objectLearningStatus('Confirmed. Click Next to continue.');
  });
}

// Adjust (redraw BBOX)
var _batchAdjustMode = false;
if(els.objectLearningAdjustBtn){
  els.objectLearningAdjustBtn.addEventListener('click', function(){
    _batchAdjustMode = true;
    objectLearningStatus('Draw the correct BBOX on the image. Release to confirm.');
  });
}

function objectLearningBatchBindDrawing(){
  var canvas = els.objectLearningBatchOverlayCanvas;
  if(!canvas || canvas._batchObjBound) return;
  var isDown = false;

  canvas.addEventListener('pointerdown', function(evt){
    if(!_batchAdjustMode) return;
    var rect = canvas.getBoundingClientRect();
    var sx = canvas.width / Math.max(1, rect.width);
    var sy = canvas.height / Math.max(1, rect.height);
    var p = { x: (evt.clientX - rect.left) * sx, y: (evt.clientY - rect.top) * sy };
    isDown = true;
    state.objectLearning.batchDrawing = { startX: p.x, startY: p.y, x: p.x, y: p.y, w: 1, h: 1 };
    objectLearningRenderBatchViewer();
  });

  canvas.addEventListener('pointermove', function(evt){
    if(!isDown || !state.objectLearning.batchDrawing) return;
    var rect = canvas.getBoundingClientRect();
    var sx = canvas.width / Math.max(1, rect.width);
    var sy = canvas.height / Math.max(1, rect.height);
    var p = { x: (evt.clientX - rect.left) * sx, y: (evt.clientY - rect.top) * sy };
    var d = state.objectLearning.batchDrawing;
    d.x = Math.min(d.startX, p.x); d.y = Math.min(d.startY, p.y);
    d.w = Math.abs(p.x - d.startX); d.h = Math.abs(p.y - d.startY);
    objectLearningRenderBatchViewer();
  });

  function finishBatchDraw(){
    if(!isDown) return;
    isDown = false;
    _batchAdjustMode = false;
    var d = state.objectLearning.batchDrawing;
    state.objectLearning.batchDrawing = null;
    if(d && d.w >= 8 && d.h >= 8){
      state.objectLearning.batchAdjustedBbox = { x: d.x, y: d.y, w: d.w, h: d.h };
      state.objectLearning.batchFeedbackGiven = true;
      objectLearningLogTrainingData(state.objectLearning.batchAdjustedBbox, true);
      objectLearningBatchUpdateFeedbackBtns();
      objectLearningStatus('BBOX adjusted. Click Next to continue.');
    }
    objectLearningRenderBatchViewer();
  }

  canvas.addEventListener('pointerup', finishBatchDraw);
  canvas.addEventListener('pointerleave', function(){ if(isDown) finishBatchDraw(); });
  canvas._batchObjBound = true;
}

// Reject prediction
if(els.objectLearningRejectBtn){
  els.objectLearningRejectBtn.addEventListener('click', function(){
    var ol = state.objectLearning;
    ol.batchFeedbackGiven = true;
    objectLearningLogTrainingData(null, false);
    objectLearningBatchUpdateFeedbackBtns();
    objectLearningStatus('Rejected. Click Next to continue.');
  });
}

