/* ── Batch session state ───────────────────────────────────────────── */

var _batchStore = _learningAPI && _learningAPI.createBatchSessionStore
  ? _learningAPI.createBatchSessionStore(localStorage)
  : null;
var _activeBatchSessionId = null;

// In-memory token store for Phase 2B extraction (tokens are too large for localStorage)
var _batchTokenStore = {};
// In-memory canvas data URL store for Phase 2B viewport rendering
var _batchCanvasStore = {};

// Wrap _batchStore.addDocument to auto-invalidate stale analysis on doc changes
if (_batchStore && _batchStore.addDocument) {
  var _origAddDocument = _batchStore.addDocument.bind(_batchStore);
  _batchStore.addDocument = function(sessionId, docSummary) {
    var result = _origAddDocument(sessionId, docSummary);
    _invalidateLearningArtifacts(sessionId);
    return result;
  };
}
// Wrap _batchStore.removeDocument to auto-invalidate stale analysis on doc changes
if (_batchStore && _batchStore.removeDocument) {
  var _origRemoveDocument = _batchStore.removeDocument.bind(_batchStore);
  _batchStore.removeDocument = function(sessionId, documentId) {
    var result = _origRemoveDocument(sessionId, documentId);
    _invalidateLearningArtifacts(sessionId);
    return result;
  };
}

/**
 * Invalidate all downstream learning artifacts for the current session.
 * Called when documents are added/removed to ensure stale results
 * cannot contaminate new analysis.
 */
function _invalidateLearningArtifacts(sessionId) {
  if (!_batchStore || !sessionId) return;
  var sessions;
  try {
    var raw = localStorage.getItem('wrokit.learning.batchSessions');
    sessions = raw ? JSON.parse(raw) : [];
  } catch(_e) { return; }
  var session = sessions.find(function(s) { return s.sessionId === sessionId; });
  if (!session) return;
  var changed = false;
  if (session.stabilityReport) { session.stabilityReport = null; changed = true; }
  if (session.correspondenceResult) { session.correspondenceResult = null; changed = true; }
  if (session.geometryProfiles) { session.geometryProfiles = null; changed = true; }
  if (changed) {
    session.updatedAt = new Date().toISOString();
    try { localStorage.setItem('wrokit.learning.batchSessions', JSON.stringify(sessions)); }
    catch(_e2) {}
  }
  // Also clear in-memory Phase 2B state since it depends on correspondence
  _resetPhase2bState();
}

/**
 * Reset Phase 2B in-memory state. Called on session switch, document
 * changes, or any event that invalidates downstream artifacts.
 */
function _resetPhase2bState() {
  if (typeof _phase2bState !== 'undefined') {
    _phase2bState.selectedDocId = null;
    _phase2bState.selectedDocName = null;
    _phase2bState.canvasDataUrl = null;
    _phase2bState.drawingFieldIdx = -1;
    _phase2bState.extractionTargets = [null, null, null];
    _phase2bState.pendingDraw = null;
    _phase2bState.refinementResult = null;
    _phase2bState.extractionResult = null;
    _phase2bState.correspondenceResult = null;
  }
}

function _storeBatchTokens(sessionId, documentId, tokens, viewport) {
  if (!_batchTokenStore[sessionId]) _batchTokenStore[sessionId] = {};
  _batchTokenStore[sessionId][documentId] = { tokens: tokens, viewport: viewport };
}

function _getBatchTokens(sessionId) {
  return _batchTokenStore[sessionId] || {};
}

/* ── Batch session UI helpers ──────────────────────────────────────── */

function refreshBatchSessionUI(){
  if(!_batchStore) return;
  var select = document.getElementById('batch-session-select');
  if(!select) return;
  var sessions = _batchStore.getAllSessions();
  // Preserve selection
  var prev = _activeBatchSessionId || select.value;
  select.innerHTML = '<option value="">— Select or create a session —</option>';
  for(var i = 0; i < sessions.length; i++){
    var s = sessions[i];
    var opt = document.createElement('option');
    opt.value = s.sessionId;
    opt.textContent = s.name + ' (' + s.documents.length + ' docs)';
    if(s.sessionId === prev) opt.selected = true;
    select.appendChild(opt);
  }
  if(prev && sessions.find(function(s){return s.sessionId===prev;})){
    _activeBatchSessionId = prev;
    showBatchSessionDetails(prev);
  } else {
    _activeBatchSessionId = null;
    var details = document.getElementById('batch-session-details');
    if(details) details.style.display = 'none';
    // Hide Phase 2 and 2B panels when no session is active
    var p2 = document.getElementById('batch-phase2-panel');
    if(p2) p2.style.display = 'none';
    var p2b = document.getElementById('batch-phase2b-panel');
    if(p2b) p2b.style.display = 'none';
    var p2bSel = document.getElementById('batch-phase2b-doc-select');
    if(p2bSel) p2bSel.innerHTML = '<option value="">— Select a document —</option>';
    var p3a = document.getElementById('batch-phase3a-panel');
    if(p3a) p3a.style.display = 'none';
  }
}

function showBatchSessionDetails(sessionId){
  if(!_batchStore) return;
  var session = _batchStore.getSession(sessionId);
  var details = document.getElementById('batch-session-details');
  if(!session || !details){ if(details) details.style.display = 'none'; return; }
  details.style.display = 'block';
  var nameEl = document.getElementById('batch-session-name-display');
  var descEl = document.getElementById('batch-session-desc-display');
  var countEl = document.getElementById('batch-doc-count');
  var statusEl = document.getElementById('batch-session-status');
  var listCountEl = document.getElementById('batch-doc-list-count');
  var analyzeBtn = document.getElementById('batch-analyze-btn');
  if(nameEl) nameEl.textContent = session.name;
  if(descEl) descEl.textContent = session.description || '';
  if(countEl) countEl.textContent = session.documents.length;
  if(listCountEl) listCountEl.textContent = session.documents.length;
  if(statusEl) statusEl.textContent = 'Created: ' + new Date(session.createdAt).toLocaleDateString();
  if(analyzeBtn){
    analyzeBtn.disabled = validCount < 2;
    analyzeBtn.title = validCount < 2
      ? 'Need at least 2 documents with real structural outputs (' + validCount + ' valid)'
      : '';
  }

  // Render document list with validity states
  var listEl = document.getElementById('batch-doc-list');
  var validCount = 0;
  if(listEl){
    if(!session.documents.length){
      listEl.innerHTML = '<p class="sub" style="color:var(--muted);">No documents yet. Upload documents to add them.</p>';
    } else {
      for(var vi = 0; vi < session.documents.length; vi++){
        if(session.documents[vi].structurallyValid) validCount++;
      }
      listEl.innerHTML = session.documents.map(function(d, idx){
        var isValid = d.structurallyValid === true;
        var statusBadge = isValid
          ? '<span style="color:#2a7;font-size:11px;font-weight:600;">analyzed</span>'
          : '<span style="color:#c44;font-size:11px;font-weight:600;" title="' +
            (d.validationReason || 'No structural outputs').replace(/"/g, '&quot;') +
            '">invalid</span>';
        var metricsText = isValid
          ? d.metrics.regionCount + ' regions, ' + d.metrics.textBlockCount + ' blocks'
          : (d.validationReason || 'Missing structural data');
        return '<div style="display:flex;align-items:center;gap:8px;padding:4px 0;border-bottom:1px solid var(--border,#eee);' +
          (isValid ? '' : 'opacity:0.6;') + '">' +
          '<span class="sub" style="min-width:24px;text-align:right;">' + (idx+1) + '.</span>' +
          statusBadge + ' ' +
          '<span style="flex:1;">' + (d.documentName || d.documentId) + '</span>' +
          '<span class="sub" style="color:var(--muted);font-size:12px;">' + metricsText + '</span>' +
          '<button class="btn ghost" style="padding:2px 8px;font-size:12px;" data-remove-doc="' + d.documentId + '">Remove</button>' +
          '</div>';
      }).join('');
      // Bind remove buttons
      listEl.querySelectorAll('[data-remove-doc]').forEach(function(btn){
        btn.addEventListener('click', function(){
          var docId = btn.getAttribute('data-remove-doc');
          if(_batchStore && _activeBatchSessionId){
            _batchStore.removeDocument(_activeBatchSessionId, docId);
            showBatchSessionDetails(_activeBatchSessionId);
            refreshBatchSessionUI();
          }
        });
      });
    }
  }

  // Show existing report if available
  if(session.stabilityReport){
    var reportEl = document.getElementById('batch-report-content');
    if(reportEl && _learningAPI && _learningAPI.formatStabilityReport){
      reportEl.textContent = _learningAPI.formatStabilityReport(session.stabilityReport);
    }
    // Show Phase 2 panel after Phase 1 has been run
    var phase2Panel = document.getElementById('batch-phase2-panel');
    if(phase2Panel) phase2Panel.style.display = 'block';
  } else {
    var phase2Panel2 = document.getElementById('batch-phase2-panel');
    if(phase2Panel2) phase2Panel2.style.display = 'none';
    // Also hide Phase 2B and 3A when Phase 2 is not available
    var phase2bPanel2 = document.getElementById('batch-phase2b-panel');
    if(phase2bPanel2) phase2bPanel2.style.display = 'none';
    var phase3aPanel2 = document.getElementById('batch-phase3a-panel');
    if(phase3aPanel2) phase3aPanel2.style.display = 'none';
  }

  // Show existing correspondence result if available
  if(session.correspondenceResult){
    _renderCorrespondenceResult(session.correspondenceResult);
  } else {
    // No correspondence result: hide Phase 2B, 3A and clear dropdown
    var phase2bPanel3 = document.getElementById('batch-phase2b-panel');
    if(phase2bPanel3) phase2bPanel3.style.display = 'none';
    var phase2bSelect = document.getElementById('batch-phase2b-doc-select');
    if(phase2bSelect) phase2bSelect.innerHTML = '<option value="">— Select a document —</option>';
    var phase3aPanel3 = document.getElementById('batch-phase3a-panel');
    if(phase3aPanel3) phase3aPanel3.style.display = 'none';
  }
}

