// Add documents via file input — sequential processing with PDF + image support
(function(){
  var fileInput = document.getElementById('batch-file-input');
  if(!fileInput) return;
  fileInput.addEventListener('change', function(e){
    if(!_batchStore || !_activeBatchSessionId || !_learningAPI) return;
    var files = e.target.files;
    if(!files || !files.length) return;
    var fileList = Array.prototype.slice.call(files);
    e.target.value = '';
    _batchProcessQueue(fileList);
  });
})();

/**
 * Sequential batch file processor.  Processes one file at a time so the
 * async PDF.js → canvas → WrokitVision pipeline is reliable and debuggable.
 * Each file goes through:  queued → loading → rendering → extracting_tokens
 *   → analyzing → extracting_summary → valid/invalid/error
 */
function _batchProcessQueue(fileList){
  if(!_batchStore || !_activeBatchSessionId || !_learningAPI) return;

  var precompute = window.WrokitVisionPrecompute || null;
  var hasPipeline = !!(precompute && precompute.buildPrecomputedStructuralMap);

  var totalFiles = fileList.length;
  var statusEl   = document.getElementById('batch-session-status');
  var docListEl  = document.getElementById('batch-doc-list');

  function updateGlobalStatus(msg){ if(statusEl) statusEl.textContent = msg; }

  // Per-file status tracking — renders live progress in the doc list panel
  var statusMap = {};
  function renderDocStatus(){
    if(!docListEl) return;
    var html = '';
    for(var k = 0; k < fileList.length; k++){
      var fn = fileList[k].name;
      var st = statusMap[fn] || { state: 'queued', detail: '' };
      var color = {
        queued:'var(--muted,#888)', loading:'#b87e0a', rendering:'#b87e0a',
        extracting_tokens:'#b87e0a', analyzing:'#2a7', extracting_summary:'#2a7',
        valid:'#2a7', invalid:'#c44', error:'#c44', skipped:'#888'
      }[st.state] || 'var(--muted)';
      html += '<div style="padding:3px 0;font-size:13px;border-bottom:1px solid var(--border,#eee);">' +
        '<span style="display:inline-block;min-width:24px;text-align:right;color:var(--muted);">' + (k+1) + '.</span> ' +
        '<span style="color:' + color + ';font-weight:600;font-size:11px;min-width:140px;display:inline-block;">' +
          st.state.replace(/_/g,' ') + '</span> ' +
        '<span>' + fn + '</span>' +
        (st.detail ? ' <span style="color:var(--muted);font-size:12px;"> — ' + st.detail + '</span>' : '') +
        '</div>';
    }
    docListEl.innerHTML = html;
  }
  function setFileStatus(fileName, state, detail){
    statusMap[fileName] = { state: state, detail: detail || '' };
    console.log('[BatchLearning][' + state + '] ' + fileName + (detail ? ' — ' + detail : ''));
    renderDocStatus();
  }

  // Initialise all files as queued
  for(var qi = 0; qi < fileList.length; qi++) statusMap[fileList[qi].name] = { state: 'queued', detail: '' };
  renderDocStatus();
  updateGlobalStatus('Processing 0/' + totalFiles + '...');

  // Open the doc list details panel so user can see progress
  var docListPanel = document.getElementById('batch-doc-list-panel');
  if(docListPanel) docListPanel.open = true;

  function processNext(idx){
    if(idx >= fileList.length){
      updateGlobalStatus('');
      showBatchSessionDetails(_activeBatchSessionId);
      refreshBatchSessionUI();
      return;
    }
    var file = fileList[idx];
    var fileName = file.name;
    updateGlobalStatus('Processing ' + (idx+1) + '/' + totalFiles + ': ' + fileName);

    if(!hasPipeline){
      setFileStatus(fileName, 'skipped', 'WrokitVisionPrecompute not available');
      _batchStore.addDocument(_activeBatchSessionId,
        _learningAPI.extractDocumentSummary({}, {documentName: fileName}));
      processNext(idx + 1);
      return;
    }

    var isPdf = /\.pdf$/i.test(fileName) || file.type === 'application/pdf';
    setFileStatus(fileName, 'loading', isPdf ? 'PDF document' : 'image file');

    var reader = new FileReader();
    reader.onerror = function(){
      setFileStatus(fileName, 'error', 'Failed to read file');
      _batchStore.addDocument(_activeBatchSessionId,
        _learningAPI.extractDocumentSummary({}, {documentName: fileName}));
      processNext(idx + 1);
    };
    reader.onload = function(){
      var arrayBuffer = reader.result;
      if(isPdf){
        _batchProcessPdf(fileName, arrayBuffer, function(){ processNext(idx + 1); });
      } else {
        _batchProcessImage(fileName, arrayBuffer, function(){ processNext(idx + 1); });
      }
    };
    reader.readAsArrayBuffer(file);
  }

  processNext(0);

  /* ── PDF processing path ─────────────────────────────────────────────── */
  /* Renders page 1 via pdf.js, extracts text tokens via getTextContent,   */
  /* and imageData via canvas — same pipeline the main system uses.        */

  function _batchProcessPdf(fileName, arrayBuffer, done){
    if(!pdfjsLibRef || !pdfjsLibRef.getDocument){
      setFileStatus(fileName, 'error', 'pdf.js not available — cannot process PDF');
      _batchStore.addDocument(_activeBatchSessionId,
        _learningAPI.extractDocumentSummary({}, {documentName: fileName}));
      done(); return;
    }

    setFileStatus(fileName, 'loading', 'parsing PDF with pdf.js');
    var pdfData = new Uint8Array(arrayBuffer);
    var loadingTask = pdfjsLibRef.getDocument({ data: pdfData });

    loadingTask.promise.then(function(pdfDoc){
      setFileStatus(fileName, 'rendering', 'page 1 of ' + pdfDoc.numPages);
      return pdfDoc.getPage(1).then(function(page){
        // Use same scale as the main document pipeline
        var scale = (window.devicePixelRatio || 1) * 1.5;  // matches BASE_PDF_SCALE
        var vp = page.getViewport({ scale: scale });
        var viewport = { width: Math.round(vp.width), height: Math.round(vp.height) };

        console.log('[BatchLearning] PDF viewport for ' + fileName + ':',
          viewport.width + 'x' + viewport.height, '(scale=' + scale + ')');

        // Render page 1 to an off-screen canvas
        var cvs = document.createElement('canvas');
        cvs.width = viewport.width;
        cvs.height = viewport.height;
        var ctx = cvs.getContext('2d', { willReadFrequently: true });
        var renderTask = page.render({ canvasContext: ctx, viewport: vp });

        return renderTask.promise.then(function(){
          setFileStatus(fileName, 'extracting_tokens', 'reading PDF text content');

          // Extract text tokens via pdf.js getTextContent — same method as readTokensForPage
          return page.getTextContent().then(function(content){
            var tokens = [];
            for(var ci = 0; ci < content.items.length; ci++){
              var item = content.items[ci];
              var tx = pdfjsLibRef.Util.transform(vp.transform, item.transform);
              var x = tx[4], yTop = tx[5], w = item.width, h = item.height;
              var text = item.str;
              // Apply the same OCR corrections used by the main pipeline
              if(typeof applyOcrCorrections === 'function'){
                try {
                  var corrResult = applyOcrCorrections(text);
                  text = corrResult.text || corrResult.corrected || text;
                } catch(_){}
              }
              tokens.push({ text: text, confidence: 1, x: x, y: yTop - h, w: w, h: h, page: 1 });
            }
            console.log('[BatchLearning] PDF text extraction for ' + fileName + ': ' + tokens.length + ' tokens');

            // Extract imageData (gray + RGB channels) from the rendered canvas
            var imageData = _batchExtractImageData(cvs);
            console.log('[BatchLearning] imageData for ' + fileName + ':',
              imageData ? imageData.width + 'x' + imageData.height : 'null');

            // Store canvas image for Phase 2B viewport
            try { _batchCanvasStore[fileName] = cvs.toDataURL('image/png'); } catch(_e){}

            // Run WrokitVision structural analysis
            _batchRunAnalysis(fileName, tokens, viewport, imageData, done);
          });
        });
      });
    }).catch(function(err){
      console.error('[BatchLearning] PDF processing failed for ' + fileName + ':', err);
      setFileStatus(fileName, 'error', 'PDF processing failed: ' + (err.message || String(err)));
      _batchStore.addDocument(_activeBatchSessionId,
        _learningAPI.extractDocumentSummary({}, {documentName: fileName}));
      done();
    });
  }

  /* ── Image processing path ───────────────────────────────────────────── */

  function _batchProcessImage(fileName, arrayBuffer, done){
    setFileStatus(fileName, 'loading', 'decoding image');
    var blob = new Blob([arrayBuffer]);
    var url = URL.createObjectURL(blob);
    var img = new Image();
    img.onload = function(){
      URL.revokeObjectURL(url);
      var viewport = { width: img.naturalWidth, height: img.naturalHeight };
      console.log('[BatchLearning] Image viewport for ' + fileName + ':',
        viewport.width + 'x' + viewport.height);

      setFileStatus(fileName, 'rendering', viewport.width + 'x' + viewport.height);
      var cvs = document.createElement('canvas');
      cvs.width = img.naturalWidth;
      cvs.height = img.naturalHeight;
      var ctx = cvs.getContext('2d', { willReadFrequently: true });
      ctx.drawImage(img, 0, 0);

      var imageData = _batchExtractImageData(cvs);

      // Store canvas image for Phase 2B viewport
      try { _batchCanvasStore[fileName] = cvs.toDataURL('image/png'); } catch(_e){}

      // OCR via Tesseract if available
      if(window.Tesseract && window.Tesseract.recognize){
        setFileStatus(fileName, 'extracting_tokens', 'running Tesseract OCR');
        window.Tesseract.recognize(img, 'eng', {}).then(function(result){
          var toks = [];
          if(result && result.data && result.data.words){
            toks = result.data.words.map(function(w){
              return {
                x: w.bbox.x0, y: w.bbox.y0,
                w: w.bbox.x1 - w.bbox.x0, h: w.bbox.y1 - w.bbox.y0,
                text: w.text, confidence: (w.confidence || 0) / 100
              };
            });
          }
          console.log('[BatchLearning] Tesseract OCR for ' + fileName + ': ' + toks.length + ' tokens');
          _batchRunAnalysis(fileName, toks, viewport, imageData, done);
        }).catch(function(err){
          console.warn('[BatchLearning] OCR failed for ' + fileName + ', using visual-only analysis:', err);
          _batchRunAnalysis(fileName, [], viewport, imageData, done);
        });
      } else {
        console.log('[BatchLearning] No OCR engine, visual-only for ' + fileName);
        _batchRunAnalysis(fileName, [], viewport, imageData, done);
      }
    };
    img.onerror = function(){
      URL.revokeObjectURL(url);
      setFileStatus(fileName, 'error', 'Failed to decode image');
      _batchStore.addDocument(_activeBatchSessionId,
        _learningAPI.extractDocumentSummary({}, {documentName: fileName}));
      done();
    };
    img.src = url;
  }

  /* ── Shared: extract imageData channels from canvas ──────────────────── */

  function _batchExtractImageData(canvas){
    try {
      var ctx = canvas.getContext('2d', { willReadFrequently: true });
      var raw = ctx.getImageData(0, 0, canvas.width, canvas.height);
      var px = canvas.width * canvas.height;
      var gray = new Uint8Array(px);
      var rCh = new Uint8Array(px);
      var gCh = new Uint8Array(px);
      var bCh = new Uint8Array(px);
      for(var i = 0, j = 0; j < px; i += 4, j++){
        var rv = raw.data[i] || 0, gv = raw.data[i+1] || 0, bv = raw.data[i+2] || 0;
        gray[j] = Math.round(rv * 0.299 + gv * 0.587 + bv * 0.114);
        rCh[j] = rv; gCh[j] = gv; bCh[j] = bv;
      }
      return { gray: gray, r: rCh, g: gCh, b: bCh, width: canvas.width, height: canvas.height };
    } catch(ex){
      console.warn('[BatchLearning] Failed to extract imageData from canvas:', ex);
      return null;
    }
  }

  /* ── Shared: run WrokitVision analysis and extract summary ───────────── */

  function _batchRunAnalysis(fileName, tokens, viewport, imageData, done){
    setFileStatus(fileName, 'analyzing',
      tokens.length + ' tokens, ' + viewport.width + 'x' + viewport.height +
      (imageData ? ', imageData=' + imageData.width + 'x' + imageData.height : ', no imageData'));
    try {
      var structuralMap = precompute.buildPrecomputedStructuralMap({
        tokens: tokens,
        viewport: viewport,
        page: 1,
        geometryId: 'batch-learning',
        imageData: imageData
      });

      var analysisResult = (structuralMap && structuralMap.uploadedImageAnalysis) || {};
      if(!analysisResult.viewport) analysisResult.viewport = viewport;

      var regionCount  = (analysisResult.regionNodes || []).length;
      var blockCount   = (analysisResult.textBlocks || []).length;
      var lineCount    = (analysisResult.textLines || []).length;
      var surfaceCount = (analysisResult.surfaceCandidates || []).length;
      var edgeCount    = ((analysisResult.regionGraph || {}).edges || []).length;

      console.log('[BatchLearning] Pipeline output for ' + fileName + ':',
        'regions=' + regionCount, 'blocks=' + blockCount,
        'lines=' + lineCount, 'surfaces=' + surfaceCount, 'edges=' + edgeCount);

      setFileStatus(fileName, 'extracting_summary',
        regionCount + ' regions, ' + blockCount + ' blocks, ' + edgeCount + ' edges');

      var summary = _learningAPI.extractDocumentSummary(analysisResult, {
        documentName: fileName,
        viewport: viewport
      });

      console.log('[BatchLearning] Summary for ' + fileName + ':',
        'structurallyValid=' + summary.structurallyValid,
        'regionCount=' + summary.metrics.regionCount,
        'blockCount=' + summary.metrics.textBlockCount,
        'edgeCount=' + summary.metrics.edgeCount,
        'avgConfidence=' + (summary.metrics.avgConfidence || 0).toFixed(3),
        'reason=' + (summary.validationReason || 'none'));

      _batchStore.addDocument(_activeBatchSessionId, summary);

      // Store tokens in memory for Phase 2B extraction
      _storeBatchTokens(_activeBatchSessionId, summary.documentId, tokens, viewport);

      if(summary.structurallyValid){
        setFileStatus(fileName, 'valid',
          summary.metrics.regionCount + ' regions, ' +
          summary.metrics.textBlockCount + ' blocks, ' +
          summary.metrics.edgeCount + ' edges');
      } else {
        setFileStatus(fileName, 'invalid', summary.validationReason || 'No structural outputs');
      }
    } catch(err){
      console.error('[BatchLearning] Pipeline error for ' + fileName + ':', err);
      setFileStatus(fileName, 'error', err.message || 'Pipeline error');
      _batchStore.addDocument(_activeBatchSessionId,
        _learningAPI.extractDocumentSummary({}, {documentName: fileName}));
    }
    done();
  }
}

// Analyze batch stability
(function(){
  var btn = document.getElementById('batch-analyze-btn');
  if(!btn) return;
  btn.addEventListener('click', function(){
    if(!_batchStore || !_activeBatchSessionId || !_learningAPI) return;
    var session = _batchStore.getSession(_activeBatchSessionId);
    if(!session || session.documents.length < 2){
      alert('Need at least 2 documents for batch stability analysis.');
      return;
    }
    var report = _learningAPI.analyzeBatchStability(session.documents);

    // Show report
    var reportEl = document.getElementById('batch-report-content');
    var metricsEl = document.getElementById('batch-metrics-content');

    var exportBtn = document.getElementById('batch-export-btn');

    if(report.status === 'insufficient_valid_data'){
      if(reportEl) reportEl.textContent = report.message;
      if(metricsEl) metricsEl.innerHTML = '<p style="color:#c44;">Batch analysis cannot proceed. ' +
        'Ensure documents have been processed through the WrokitVision analysis pipeline.</p>';
      if(exportBtn){ exportBtn.disabled = true; exportBtn.style.display = 'none'; }
      // Do not save a misleading report
      return;
    }

    _batchStore.saveStabilityReport(_activeBatchSessionId, report);

    if(reportEl) reportEl.textContent = _learningAPI.formatStabilityReport(report);
    if(metricsEl && report.stabilityMetrics){
      metricsEl.innerHTML = '<pre class="code" style="white-space:pre-wrap;">' +
        JSON.stringify(report.stabilityMetrics, null, 2).replace(/</g, '&lt;') + '</pre>';
    }

    // Show export button after successful analysis
    if(exportBtn){ exportBtn.disabled = false; exportBtn.style.display = ''; }

    // Show Phase 2 panel after successful Phase 1 analysis
    var phase2Panel = document.getElementById('batch-phase2-panel');
    if(phase2Panel) phase2Panel.style.display = 'block';

    // Show existing correspondence result if available
    _showExistingCorrespondenceResult();
  });
})();

/* ── Phase 2: Structural Correspondence Analysis ───────────────────────── */

function _showExistingCorrespondenceResult(){
  if(!_batchStore || !_activeBatchSessionId) return;
  var session = _batchStore.getSession(_activeBatchSessionId);
  if(!session || !session.correspondenceResult) return;
  _renderCorrespondenceResult(session.correspondenceResult);
}

function _renderCorrespondenceResult(result){
  if(!result) return;

  // Reference document panel
  var refPanel = document.getElementById('batch-reference-panel');
  var refContent = document.getElementById('batch-reference-content');
  if(refPanel && refContent && result.referenceDocument){
    refPanel.style.display = '';
    var refDoc = result.referenceDocument;
    var refHtml = '<div style="padding:4px 0;">';
    refHtml += '<div style="margin-bottom:8px;"><strong>' + (refDoc.documentName || refDoc.documentId) + '</strong></div>';
    if(refDoc.centralityScore != null){
      refHtml += '<div class="sub" style="color:var(--muted);">Centrality Score: <strong>' + (refDoc.centralityScore * 100).toFixed(1) + '%</strong>';
      refHtml += ' — This document is most structurally similar to the rest of the batch.</div>';
    }
    if(refDoc.centralityScores && refDoc.centralityScores.length > 1){
      refHtml += '<details style="margin-top:8px;"><summary class="sub" style="cursor:pointer;">All document centrality scores</summary>';
      refHtml += '<div style="margin-top:4px;">';
      for(var ci = 0; ci < refDoc.centralityScores.length; ci++){
        var cs = refDoc.centralityScores[ci];
        var barW = Math.round((cs.avgSimilarity || 0) * 100);
        refHtml += '<div style="display:flex;align-items:center;gap:8px;padding:2px 0;font-size:13px;">';
        refHtml += '<span style="min-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + (cs.documentName || cs.documentId) + '</span>';
        refHtml += '<div style="flex:1;background:var(--border,#eee);height:8px;border-radius:4px;overflow:hidden;">';
        refHtml += '<div style="width:' + barW + '%;height:100%;background:' + (ci === 0 ? '#2a7' : '#69b') + ';border-radius:4px;"></div></div>';
        refHtml += '<span class="sub" style="min-width:50px;text-align:right;">' + (cs.avgSimilarity * 100).toFixed(1) + '%</span>';
        refHtml += '</div>';
      }
      refHtml += '</div></details>';
    }
    refHtml += '</div>';
    refContent.innerHTML = refHtml;
  }

  // Anchors panel
  var anchorsPanel = document.getElementById('batch-anchors-panel');
  var anchorsContent = document.getElementById('batch-anchors-content');
  var anchorCountEl = document.getElementById('batch-anchor-count');
  if(anchorsPanel && anchorsContent && result.anchors){
    anchorsPanel.style.display = '';
    if(anchorCountEl) anchorCountEl.textContent = result.anchors.length;

    if(result.anchors.length === 0){
      anchorsContent.innerHTML = '<p class="sub" style="color:var(--muted);">No recurring structural anchors discovered.</p>';
    } else {
      var anchHtml = '';
      for(var ai = 0; ai < result.anchors.length; ai++){
        var a = result.anchors[ai];
        var confPct = (a.confidence * 100).toFixed(1);
        var freqPct = (a.frequency * 100).toFixed(0);
        var confColor = a.confidence >= 0.7 ? '#2a7' : a.confidence >= 0.5 ? '#b87e0a' : '#c44';
        anchHtml += '<div style="padding:8px;margin-bottom:8px;border:1px solid var(--border,#eee);border-radius:6px;border-left:3px solid ' + confColor + ';">';
        anchHtml += '<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;">';
        anchHtml += '<strong style="font-size:13px;">Anchor ' + (ai + 1) + '</strong>';
        anchHtml += '<span style="font-size:12px;color:' + confColor + ';font-weight:600;">' + confPct + '% confidence</span>';
        anchHtml += '</div>';
        anchHtml += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:4px 16px;margin-top:6px;font-size:12px;color:var(--muted);">';
        anchHtml += '<span>Position: (' + (a.normalizedPosition.x * 100).toFixed(1) + '%, ' + (a.normalizedPosition.y * 100).toFixed(1) + '%)</span>';
        anchHtml += '<span>Size: ' + (a.normalizedArea * 100).toFixed(2) + '% of page</span>';
        anchHtml += '<span>Type: ' + a.surfaceType + '</span>';
        anchHtml += '<span>Frequency: ' + a.matchCount + '/' + a.totalDocuments + ' (' + freqPct + '%)</span>';
        anchHtml += '<span>Avg Similarity: ' + (a.avgSimilarity * 100).toFixed(1) + '%</span>';
        anchHtml += '</div>';
        // Confidence bar
        var barW = Math.round(a.confidence * 100);
        anchHtml += '<div style="margin-top:6px;background:var(--border,#eee);height:6px;border-radius:3px;overflow:hidden;">';
        anchHtml += '<div style="width:' + barW + '%;height:100%;background:' + confColor + ';border-radius:3px;"></div></div>';
        anchHtml += '</div>';
      }
      anchorsContent.innerHTML = anchHtml;
    }
  }

  // Full report panel
  var reportPanel = document.getElementById('batch-correspondence-report-panel');
  var reportContent = document.getElementById('batch-correspondence-report-content');
  if(reportPanel && reportContent && _learningAPI && _learningAPI.formatCorrespondenceReport){
    reportPanel.style.display = '';
    reportContent.textContent = _learningAPI.formatCorrespondenceReport(result);
  }

  // Alignment model panel
  var alignPanel = document.getElementById('batch-alignment-panel');
  var alignContent = document.getElementById('batch-alignment-content');
  if(alignPanel && alignContent && result.alignmentModel){
    alignPanel.style.display = '';
    var am = result.alignmentModel;
    var amHtml = '<div style="padding:4px 0;">';
    amHtml += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:8px 16px;margin-bottom:12px;">';
    amHtml += '<div class="panel minimal" style="padding:8px;text-align:center;"><div class="sub" style="font-size:11px;color:var(--muted);">Anchors</div><strong style="font-size:18px;">' + am.anchorCount + '</strong><div class="sub" style="font-size:11px;color:var(--muted);">of ' + am.totalRegionsInReference + ' regions</div></div>';
    amHtml += '<div class="panel minimal" style="padding:8px;text-align:center;"><div class="sub" style="font-size:11px;color:var(--muted);">Coverage</div><strong style="font-size:18px;">' + (am.anchorCoverage * 100).toFixed(1) + '%</strong></div>';
    amHtml += '<div class="panel minimal" style="padding:8px;text-align:center;"><div class="sub" style="font-size:11px;color:var(--muted);">Avg Confidence</div><strong style="font-size:18px;">' + (am.avgAnchorConfidence * 100).toFixed(1) + '%</strong></div>';
    amHtml += '<div class="panel minimal" style="padding:8px;text-align:center;"><div class="sub" style="font-size:11px;color:var(--muted);">Avg Frequency</div><strong style="font-size:18px;">' + (am.avgAnchorFrequency * 100).toFixed(1) + '%</strong></div>';
    amHtml += '</div>';
    amHtml += '<details><summary class="sub" style="cursor:pointer;">Raw alignment model data</summary>';
    amHtml += '<pre class="code" style="white-space:pre-wrap;margin-top:8px;font-size:12px;">' +
      JSON.stringify(am, null, 2).replace(/</g, '&lt;') + '</pre></details>';
    amHtml += '</div>';
    alignContent.innerHTML = amHtml;
  }

  // Status
  var statusEl = document.getElementById('batch-phase2-status');
  if(statusEl) statusEl.textContent = result.status === 'complete'
    ? 'Analysis complete'
    : result.status.replace(/_/g, ' ');

  // Export button
  var exportBtn = document.getElementById('batch-correspondence-export-btn');
  if(exportBtn && result.status !== 'insufficient_data' && result.status !== 'insufficient_valid_data'){
    exportBtn.disabled = false;
    exportBtn.style.display = '';
  }

  // Show Phase 2B panel after successful Phase 2
  if(result.status === 'complete' || result.status === 'low_confidence'){
    var phase2bPanel = document.getElementById('batch-phase2b-panel');
    if(phase2bPanel) phase2bPanel.style.display = 'block';
    _populatePhase2BDocSelect();
  }
}

// Run Correspondence Analysis button
(function(){
  var btn = document.getElementById('batch-correspondence-btn');
  if(!btn) return;
  btn.addEventListener('click', function(){
    if(!_batchStore || !_activeBatchSessionId || !_learningAPI || !_learningAPI.analyzeCorrespondence) return;
    var session = _batchStore.getSession(_activeBatchSessionId);
    if(!session || session.documents.length < 2){
      alert('Need at least 2 documents for correspondence analysis.');
      return;
    }

    var statusEl = document.getElementById('batch-phase2-status');
    if(statusEl) statusEl.textContent = 'Analyzing correspondences...';
    btn.disabled = true;

    // Use setTimeout to let the UI update before the synchronous computation
    setTimeout(function(){
      try {
        var result = _learningAPI.analyzeCorrespondence(session.documents);

        if(result.status === 'insufficient_valid_data'){
          if(statusEl) statusEl.textContent = 'Insufficient data';
          alert(result.message);
          btn.disabled = false;
          return;
        }

        // Save result to session
        if(_batchStore.saveCorrespondenceResult){
          _batchStore.saveCorrespondenceResult(_activeBatchSessionId, result);
        }

        // Render the result
        _renderCorrespondenceResult(result);
      } catch(err){
        console.error('[BatchLearning] Correspondence analysis failed:', err);
        if(statusEl) statusEl.textContent = 'Analysis failed';
        alert('Correspondence analysis failed: ' + (err.message || String(err)));
      }
      btn.disabled = false;
    }, 50);
  });
})();

// Export correspondence report as .txt
(function(){
  var exportBtn = document.getElementById('batch-correspondence-export-btn');
  if(!exportBtn) return;
  exportBtn.addEventListener('click', function(){
    var reportEl = document.getElementById('batch-correspondence-report-content');
    var reportText = reportEl ? reportEl.textContent : '';
    if(!reportText || reportText.indexOf('[No correspondence') === 0){
      alert('No correspondence report available. Run analysis first.');
      return;
    }
    var timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    var filename = 'wrokit-correspondence-' + timestamp + '.txt';
    var blob = new Blob([reportText], { type: 'text/plain' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = filename;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a); URL.revokeObjectURL(url);
  });
})();

/* ── Export stability report as .txt ─────────────────────────────────── */
(function(){
  var exportBtn = document.getElementById('batch-export-btn');
  if(!exportBtn) return;
  exportBtn.addEventListener('click', function(){
    var reportEl = document.getElementById('batch-report-content');
    var metricsEl = document.getElementById('batch-metrics-content');
    var reportText = reportEl ? reportEl.textContent : '';
    var metricsText = metricsEl ? metricsEl.textContent : '';

    if(!reportText || reportText.indexOf('No analysis run yet') === 0){
      alert('No stability report available. Run an analysis first.');
      return;
    }

    var output = '--------------------------------\n' +
      'WrokitVision Batch Stability Report\n' +
      '--------------------------------\n' +
      reportText + '\n' +
      '--------------------------------\n' +
      'Stability Metrics Detail\n' +
      '--------------------------------\n' +
      metricsText + '\n';

    var timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    var filename = 'wrokit-batch-stability-' + timestamp + '.txt';

    var blob = new Blob([output], { type: 'text/plain' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  });
})();

/* ── Phase 2B: Refine Anchors + BBOX-Guided Extraction ─────────────────── */

var _phase2bState = {
  selectedDocId: null,
  selectedDocName: null,
  canvasDataUrl: null,
  drawingFieldIdx: -1,   // which field is currently being drawn (-1 = none)
  extractionTargets: [null, null, null],  // 3 normBox targets
  pendingDraw: null,     // { startX, startY } during drag
  refinementResult: null,
  extractionResult: null,
  correspondenceResult: null
};

/** Populate the document selector for Phase 2B from the current batch session. */
function _populatePhase2BDocSelect(){
  var select = document.getElementById('batch-phase2b-doc-select');
  if(!select || !_batchStore || !_activeBatchSessionId) return;
  var session = _batchStore.getSession(_activeBatchSessionId);
  if(!session) return;
  select.innerHTML = '<option value="">— Select a document —</option>';
  for(var i = 0; i < session.documents.length; i++){
    var d = session.documents[i];
    if(!d.structurallyValid) continue;
    var opt = document.createElement('option');
    opt.value = d.documentId;
    opt.textContent = d.documentName || d.documentId;
    select.appendChild(opt);
  }
}

/** Load a document image into the Phase 2B viewport canvas. */
function _loadPhase2BDocument(docId){
  if(!_batchStore || !_activeBatchSessionId) return;
  var session = _batchStore.getSession(_activeBatchSessionId);
  if(!session) return;
  var doc = session.documents.find(function(d){ return d.documentId === docId; });
  if(!doc){
    alert('Document not found in session.');
    return;
  }

  _phase2bState.selectedDocId = docId;
  _phase2bState.selectedDocName = doc.documentName || docId;
  _phase2bState.extractionTargets = [null, null, null];
  _phase2bState.refinementResult = null;
  _phase2bState.extractionResult = null;

  // Find canvas data URL by document name
  var dataUrl = _batchCanvasStore[doc.documentName];
  if(!dataUrl){
    alert('Document image not available in memory. Documents must be uploaded in this session for the Phase 2B viewport to work.');
    return;
  }

  _phase2bState.canvasDataUrl = dataUrl;

  // Show wizard and viewport
  var wizard = document.getElementById('batch-phase2b-wizard');
  if(wizard) wizard.style.display = 'block';
  var viewport = document.getElementById('batch-phase2b-viewport');
  if(viewport) viewport.style.display = 'block';

  // Load image into canvas
  var canvas = document.getElementById('batch-phase2b-canvas');
  var overlay = document.getElementById('batch-phase2b-overlay');
  if(!canvas) return;

  var img = new Image();
  img.onload = function(){
    // Scale down for display — max 700px wide
    var maxW = 700;
    var scale = img.width > maxW ? maxW / img.width : 1;
    canvas.width = Math.round(img.width * scale);
    canvas.height = Math.round(img.height * scale);
    canvas.style.width = canvas.width + 'px';
    canvas.style.height = canvas.height + 'px';
    var ctx = canvas.getContext('2d');
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

    // Sync overlay
    if(overlay){
      overlay.width = canvas.width;
      overlay.height = canvas.height;
      overlay.style.width = canvas.width + 'px';
      overlay.style.height = canvas.height + 'px';
    }

    _resetPhase2BFields();
    console.log('[Phase2B] Loaded document:', doc.documentName, canvas.width + 'x' + canvas.height);
  };
  img.src = dataUrl;
}

function _resetPhase2BFields(){
  _phase2bState.extractionTargets = [null, null, null];
  _phase2bState.drawingFieldIdx = -1;
  _phase2bState.pendingDraw = null;
  _phase2bState.refinementResult = null;
  _phase2bState.extractionResult = null;

  for(var fi = 0; fi < 3; fi++){
    var indicator = document.getElementById('batch-phase2b-field-' + (fi+1) + '-indicator');
    var statusEl = document.getElementById('batch-phase2b-field-' + (fi+1) + '-status');
    if(indicator) indicator.style.background = 'var(--border,#ccc)';
    if(statusEl) statusEl.textContent = 'not drawn';
  }

  var stepEl = document.getElementById('batch-phase2b-wizard-step');
  if(stepEl) stepEl.textContent = 'Step 1 of 3';

  var refineBtn = document.getElementById('batch-phase2b-refine-btn');
  if(refineBtn) refineBtn.disabled = true;

  var resultsDiv = document.getElementById('batch-phase2b-results');
  if(resultsDiv) resultsDiv.style.display = 'none';
  var extractionDiv = document.getElementById('batch-phase2b-extraction');
  if(extractionDiv) extractionDiv.style.display = 'none';

  _drawPhase2BOverlay();
}

/** Draw all BBOX overlays on the Phase 2B canvas. */
function _drawPhase2BOverlay(){
  var overlay = document.getElementById('batch-phase2b-overlay');
  if(!overlay) return;
  var ctx = overlay.getContext('2d');
  ctx.clearRect(0, 0, overlay.width, overlay.height);

  var colors = ['#2a7', '#e67e22', '#3498db'];

  for(var fi = 0; fi < 3; fi++){
    var target = _phase2bState.extractionTargets[fi];
    if(!target) continue;
    var nb = target.normBox;
    var x = nb.x0n * overlay.width;
    var y = nb.y0n * overlay.height;
    var w = nb.wN * overlay.width;
    var h = nb.hN * overlay.height;

    ctx.strokeStyle = colors[fi];
    ctx.lineWidth = 2;
    ctx.strokeRect(x, y, w, h);
    ctx.fillStyle = colors[fi] + '22';
    ctx.fillRect(x, y, w, h);

    // Label
    ctx.fillStyle = colors[fi];
    ctx.font = '11px sans-serif';
    var label = target.label || ('Field ' + (fi + 1));
    ctx.fillText(label, x + 3, y - 4 > 12 ? y - 4 : y + 12);
  }

  // Draw pending selection
  if(_phase2bState.pendingDraw && _phase2bState.drawingFieldIdx >= 0){
    var pd = _phase2bState.pendingDraw;
    if(pd.endX !== undefined){
      var dx = Math.min(pd.startX, pd.endX);
      var dy = Math.min(pd.startY, pd.endY);
      var dw = Math.abs(pd.endX - pd.startX);
      var dh = Math.abs(pd.endY - pd.startY);
      ctx.strokeStyle = colors[_phase2bState.drawingFieldIdx];
      ctx.lineWidth = 2;
      ctx.setLineDash([4, 3]);
      ctx.strokeRect(dx, dy, dw, dh);
      ctx.setLineDash([]);
    }
  }
}

/** Enter drawing mode for a specific field index (0, 1, 2). */
function _startPhase2BDraw(fieldIdx){
  if(!_phase2bState.canvasDataUrl) return;
  _phase2bState.drawingFieldIdx = fieldIdx;
  _phase2bState.pendingDraw = null;

  var hint = document.getElementById('batch-phase2b-drawing-hint');
  var names = ['Field 1', 'Field 2', 'Field 3'];
  var nameInput = document.getElementById('batch-phase2b-field-' + (fieldIdx+1) + '-name');
  var fieldName = (nameInput && nameInput.value.trim()) || names[fieldIdx];
  if(hint) hint.textContent = 'Draw a box around: ' + fieldName;

  // Enable pointer events on overlay for drawing
  var overlay = document.getElementById('batch-phase2b-overlay');
  if(overlay) overlay.style.pointerEvents = 'auto';

  // Update button states
  var buttons = document.querySelectorAll('.batch-phase2b-draw-btn');
  buttons.forEach(function(btn){
    btn.disabled = parseInt(btn.getAttribute('data-field-idx')) !== fieldIdx;
  });
}

/** Finalize a drawn BBOX for the current field. */
function _finishPhase2BDraw(x0, y0, x1, y1){
  var overlay = document.getElementById('batch-phase2b-overlay');
  if(!overlay) return;

  var fieldIdx = _phase2bState.drawingFieldIdx;
  if(fieldIdx < 0 || fieldIdx > 2) return;

  // Normalize to 0-1
  var nx = Math.min(x0, x1) / overlay.width;
  var ny = Math.min(y0, y1) / overlay.height;
  var nw = Math.abs(x1 - x0) / overlay.width;
  var nh = Math.abs(y1 - y0) / overlay.height;

  if(nw < 0.005 || nh < 0.005) return; // too small

  var nameInput = document.getElementById('batch-phase2b-field-' + (fieldIdx+1) + '-name');
  var label = (nameInput && nameInput.value.trim()) || ('Field ' + (fieldIdx+1));
  var fieldKey = 'field_' + (fieldIdx+1);

  _phase2bState.extractionTargets[fieldIdx] = {
    fieldKey: fieldKey,
    label: label,
    normBox: {
      x0n: Math.round(nx * 10000) / 10000,
      y0n: Math.round(ny * 10000) / 10000,
      wN: Math.round(nw * 10000) / 10000,
      hN: Math.round(nh * 10000) / 10000
    },
    fieldType: 'static'
  };

  // Update UI
  var indicator = document.getElementById('batch-phase2b-field-' + (fieldIdx+1) + '-indicator');
  var statusEl = document.getElementById('batch-phase2b-field-' + (fieldIdx+1) + '-status');
  var colors = ['#2a7', '#e67e22', '#3498db'];
  if(indicator) indicator.style.background = colors[fieldIdx];
  if(statusEl) statusEl.textContent = 'drawn';

  _phase2bState.drawingFieldIdx = -1;
  _phase2bState.pendingDraw = null;

  // Disable drawing on overlay
  if(overlay) overlay.style.pointerEvents = 'none';
  var hint = document.getElementById('batch-phase2b-drawing-hint');
  if(hint) hint.textContent = '';

  // Re-enable draw buttons
  var buttons = document.querySelectorAll('.batch-phase2b-draw-btn');
  buttons.forEach(function(btn){ btn.disabled = false; });

  // Update step indicator
  var drawnCount = _phase2bState.extractionTargets.filter(function(t){ return t !== null; }).length;
  var stepEl = document.getElementById('batch-phase2b-wizard-step');
  if(stepEl) stepEl.textContent = drawnCount >= 3 ? 'All fields drawn' : 'Step ' + (drawnCount + 1) + ' of 3';

  // Enable refine button if at least 1 target drawn
  var refineBtn = document.getElementById('batch-phase2b-refine-btn');
  if(refineBtn) refineBtn.disabled = drawnCount === 0;

  _drawPhase2BOverlay();
}

/* ── Phase 2B: Pointer event handlers for BBOX drawing ─────────────────── */

(function(){
  var overlay = document.getElementById('batch-phase2b-overlay');
  if(!overlay) return;

  overlay.addEventListener('pointerdown', function(e){
    if(_phase2bState.drawingFieldIdx < 0) return;
    e.preventDefault();
    var rect = overlay.getBoundingClientRect();
    _phase2bState.pendingDraw = {
      startX: e.clientX - rect.left,
      startY: e.clientY - rect.top
    };
    overlay.setPointerCapture(e.pointerId);
  });

  overlay.addEventListener('pointermove', function(e){
    if(!_phase2bState.pendingDraw || _phase2bState.drawingFieldIdx < 0) return;
    var rect = overlay.getBoundingClientRect();
    _phase2bState.pendingDraw.endX = e.clientX - rect.left;
    _phase2bState.pendingDraw.endY = e.clientY - rect.top;
    _drawPhase2BOverlay();
  });

  overlay.addEventListener('pointerup', function(e){
    if(!_phase2bState.pendingDraw || _phase2bState.drawingFieldIdx < 0) return;
    var rect = overlay.getBoundingClientRect();
    var endX = e.clientX - rect.left;
    var endY = e.clientY - rect.top;
    var pd = _phase2bState.pendingDraw;
    overlay.releasePointerCapture(e.pointerId);
    _finishPhase2BDraw(pd.startX, pd.startY, endX, endY);
  });
})();

/* ── Phase 2B: Button event handlers ───────────────────────────────────── */

// Load Document button
(function(){
  var btn = document.getElementById('batch-phase2b-load-doc-btn');
  if(!btn) return;
  btn.addEventListener('click', function(){
    var select = document.getElementById('batch-phase2b-doc-select');
    if(!select || !select.value){
      alert('Please select a document first.');
      return;
    }
    _loadPhase2BDocument(select.value);
  });
})();

// Draw BBOX buttons
(function(){
  var buttons = document.querySelectorAll('.batch-phase2b-draw-btn');
  buttons.forEach(function(btn){
    btn.addEventListener('click', function(){
      var idx = parseInt(btn.getAttribute('data-field-idx'));
      _startPhase2BDraw(idx);
    });
  });
})();

// Reset button
(function(){
  var btn = document.getElementById('batch-phase2b-reset-btn');
  if(!btn) return;
  btn.addEventListener('click', function(){
    _resetPhase2BFields();
  });
})();

// Refine Anchors button
(function(){
  var btn = document.getElementById('batch-phase2b-refine-btn');
  if(!btn) return;
  btn.addEventListener('click', function(){
    if(!_batchStore || !_activeBatchSessionId || !_learningAPI) return;
    var session = _batchStore.getSession(_activeBatchSessionId);
    if(!session || !session.correspondenceResult) {
      alert('Run Phase 2 correspondence analysis first.');
      return;
    }

    // Collect drawn targets
    var targets = _phase2bState.extractionTargets.filter(function(t){ return t !== null; });
    if(targets.length === 0){
      alert('Draw at least one extraction target first.');
      return;
    }

    // Find reference document (use the one selected in Phase 2B, or Phase 2 reference)
    var refDocId = _phase2bState.selectedDocId || session.correspondenceResult.referenceDocument.documentId;
    var refDoc = session.documents.find(function(d){ return d.documentId === refDocId; });
    if(!refDoc || refDoc._compact){
      alert('Selected document does not have full structural data. Choose a different document.');
      return;
    }

    var statusEl = document.getElementById('batch-phase2b-status');
    if(statusEl) statusEl.textContent = 'Refining anchors...';
    btn.disabled = true;

    setTimeout(function(){
      try {
        var result = _learningAPI.refineAnchors(
          session.correspondenceResult,
          targets,
          refDoc
        );

        _phase2bState.refinementResult = result;
        _phase2bState.correspondenceResult = session.correspondenceResult;
        _renderPhase2BRefinementResult(result);

        if(statusEl) statusEl.textContent = result.status === 'refined' ? 'Refinement complete' : result.status.replace(/_/g, ' ');
      } catch(err){
        console.error('[Phase2B] Refinement failed:', err);
        if(statusEl) statusEl.textContent = 'Refinement failed';
        alert('Anchor refinement failed: ' + (err.message || String(err)));
      }
      btn.disabled = false;
    }, 50);
  });
})();

function _renderPhase2BRefinementResult(result){
  var resultsDiv = document.getElementById('batch-phase2b-results');
  if(resultsDiv) resultsDiv.style.display = 'block';

  // Anchor counts
  var keptEl = document.getElementById('batch-phase2b-anchor-kept');
  var removedEl = document.getElementById('batch-phase2b-anchor-removed');
  if(keptEl) keptEl.textContent = result.refinedAnchors.length;
  if(removedEl) removedEl.textContent = result.removedAnchors.length;

  // Refined anchors list
  var anchorsContent = document.getElementById('batch-phase2b-refined-anchors-content');
  if(anchorsContent){
    if(result.refinedAnchors.length === 0){
      anchorsContent.innerHTML = '<p class="sub" style="color:#c44;">No anchors are relevant to the extraction targets.</p>';
    } else {
      var html = '';
      for(var ai = 0; ai < result.refinedAnchors.length; ai++){
        var a = result.refinedAnchors[ai];
        var relPct = (a.relevanceScore * 100).toFixed(1);
        var confPct = (a.confidence * 100).toFixed(1);
        var relColor = a.relevanceScore >= 0.5 ? '#2a7' : a.relevanceScore >= 0.3 ? '#b87e0a' : '#c44';
        html += '<div style="padding:6px 8px;margin-bottom:6px;border:1px solid var(--border,#eee);border-radius:6px;border-left:3px solid ' + relColor + ';font-size:13px;">';
        html += '<div style="display:flex;justify-content:space-between;flex-wrap:wrap;gap:4px;">';
        html += '<span><strong>' + a.anchorId + '</strong></span>';
        html += '<span style="color:' + relColor + ';font-weight:600;">relevance ' + relPct + '%</span>';
        html += '</div>';
        html += '<div class="sub" style="color:var(--muted);font-size:12px;margin-top:2px;">';
        html += 'conf=' + confPct + '%  target=' + (a.bestTargetKey || 'none');
        html += '  pos=(' + (a.normalizedPosition.x * 100).toFixed(0) + '%, ' + (a.normalizedPosition.y * 100).toFixed(0) + '%)';
        html += '  type=' + a.surfaceType;
        html += '</div></div>';
      }
      anchorsContent.innerHTML = html;
    }
  }

  // Refined alignment model
  var modelContent = document.getElementById('batch-phase2b-refinement-model-content');
  if(modelContent && result.refinedAlignmentModel){
    var m = result.refinedAlignmentModel;
    var mHtml = '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:8px;margin-bottom:8px;">';
    mHtml += '<div class="panel minimal" style="padding:6px;text-align:center;"><div class="sub" style="font-size:11px;">Kept</div><strong>' + m.anchorCount + '</strong></div>';
    mHtml += '<div class="panel minimal" style="padding:6px;text-align:center;"><div class="sub" style="font-size:11px;">Removed</div><strong>' + m.removedCount + '</strong></div>';
    mHtml += '<div class="panel minimal" style="padding:6px;text-align:center;"><div class="sub" style="font-size:11px;">Retention</div><strong>' + (m.anchorRetentionRate * 100).toFixed(0) + '%</strong></div>';
    mHtml += '<div class="panel minimal" style="padding:6px;text-align:center;"><div class="sub" style="font-size:11px;">Avg Relevance</div><strong>' + (m.avgRelevanceScore * 100).toFixed(1) + '%</strong></div>';
    mHtml += '</div>';
    mHtml += '<p class="sub" style="margin:4px 0;color:var(--muted);">' + result.message + '</p>';
    modelContent.innerHTML = mHtml;
  }
}

// Extract button (async — supports OCR fallback for scanned documents)
(function(){
  var btn = document.getElementById('batch-phase2b-extract-btn');
  if(!btn) return;

  /** Crop a normalized box region from a data-URL image and return the cropped canvas. */
  function _cropNormBoxFromDataUrl(dataUrl, normBox){
    return new Promise(function(resolve, reject){
      var img = new Image();
      img.onload = function(){
        var sx = Math.round(normBox.x0n * img.width);
        var sy = Math.round(normBox.y0n * img.height);
        var sw = Math.max(1, Math.round(normBox.wN * img.width));
        var sh = Math.max(1, Math.round(normBox.hN * img.height));
        // Clamp to image bounds
        sx = Math.max(0, Math.min(sx, img.width - 1));
        sy = Math.max(0, Math.min(sy, img.height - 1));
        sw = Math.min(sw, img.width - sx);
        sh = Math.min(sh, img.height - sy);
        var cvs = document.createElement('canvas');
        cvs.width = sw; cvs.height = sh;
        var ctx = cvs.getContext('2d');
        ctx.drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);
        resolve(cvs);
      };
      img.onerror = function(){ reject(new Error('Failed to load image for OCR crop')); };
      img.src = dataUrl;
    });
  }

  /** Run Tesseract OCR on a cropped canvas, try PSM 6 and 7, pick best. */
  async function _ocrCrop(cropCanvas){
    if(!window.Tesseract || !window.Tesseract.recognize){
      return { text: '', confidence: 0, psmUsed: null };
    }
    var best = { text: '', confidence: 0, tokenCount: 0, psmUsed: null };
    var psms = [6, 7];
    for(var pi = 0; pi < psms.length; pi++){
      try {
        var res = await window.Tesseract.recognize(cropCanvas, 'eng', { tessedit_pageseg_mode: psms[pi] });
        var words = (res.data && res.data.words) || [];
        var toks = words.map(function(w){ return w.text.trim(); }).filter(Boolean);
        var meanConf = toks.length > 0
          ? words.reduce(function(s,w){ return s + w.confidence; }, 0) / toks.length / 100
          : 0;
        var text = toks.join(' ').trim();
        if(toks.length > best.tokenCount || (toks.length === best.tokenCount && meanConf > best.confidence)){
          best = { text: text, confidence: meanConf, tokenCount: toks.length, psmUsed: psms[pi] };
        }
      } catch(e){
        console.warn('[Phase2B] OCR probe PSM ' + psms[pi] + ' failed:', e);
      }
    }
    return best;
  }

  var MIN_TOKEN_THRESHOLD = 2; // Below this, trigger OCR fallback

  btn.addEventListener('click', async function(){
    if(!_phase2bState.refinementResult || !_phase2bState.correspondenceResult) {
      alert('Run anchor refinement first.');
      return;
    }
    if(!_batchStore || !_activeBatchSessionId) return;
    var session = _batchStore.getSession(_activeBatchSessionId);
    if(!session) return;

    var refDocId = _phase2bState.correspondenceResult.referenceDocument.documentId;
    var refDoc = session.documents.find(function(d){ return d.documentId === refDocId; });
    if(!refDoc) {
      alert('Reference document not found.');
      return;
    }

    var batchTokens = _getBatchTokens(_activeBatchSessionId);
    var statusEl = document.getElementById('batch-phase2b-extraction-status');
    if(statusEl) statusEl.textContent = 'Extracting...';
    btn.disabled = true;

    try {
      // Step 1: Run structure-first extraction with landmark supplementation
      var extractionTargets = _phase2bState.extractionTargets.filter(function(t){ return t !== null; });
      var result = _learningAPI.extractWithLandmarkFallback(
        _phase2bState.refinementResult,
        _phase2bState.correspondenceResult,
        refDoc,
        session.documents,
        batchTokens,
        extractionTargets
      );

      // Step 2: OCR fallback for fields with insufficient tokens
      var ocrNeeded = [];
      for(var di = 0; di < result.results.length; di++){
        var docResult = result.results[di];
        var docDataUrl = _batchCanvasStore[docResult.documentName];
        for(var fi = 0; fi < docResult.fields.length; fi++){
          var f = docResult.fields[fi];
          if(f.tokenCount < MIN_TOKEN_THRESHOLD && docDataUrl){
            ocrNeeded.push({ di: di, fi: fi, normBox: f.transferredNormBox, dataUrl: docDataUrl, field: f });
          }
        }
      }

      if(ocrNeeded.length > 0){
        if(statusEl) statusEl.textContent = 'Extracting... OCR fallback for ' + ocrNeeded.length + ' field(s)';
        for(var oi = 0; oi < ocrNeeded.length; oi++){
          var item = ocrNeeded[oi];
          try {
            var cropCvs = await _cropNormBoxFromDataUrl(item.dataUrl, item.normBox);
            var ocrResult = await _ocrCrop(cropCvs);
            if(ocrResult.text){
              item.field.extractedText = ocrResult.text;
              item.field.textConfidence = Math.round(ocrResult.confidence * 1000) / 1000;
              item.field.textSource = 'ocr_fallback';
            } else {
              item.field.textSource = 'no_text';
            }
          } catch(ocrErr){
            console.warn('[Phase2B] OCR fallback failed for doc ' + item.di + ' field ' + item.fi + ':', ocrErr);
            item.field.textSource = 'no_text';
          }
        }
      }

      _phase2bState.extractionResult = result;
      _renderPhase2BExtractionResult(result);
      if(statusEl) statusEl.textContent = result.status === 'complete' ? 'Extraction complete' : result.status;

      // Show Phase 3A panel after successful extraction
      if(result.status === 'complete' && result.results && result.results.length > 0){
        var p3aPanel = document.getElementById('batch-phase3a-panel');
        if(p3aPanel) p3aPanel.style.display = 'block';
        _initPhase3ACorrections(result);
      }
    } catch(err){
      console.error('[Phase2B] Extraction failed:', err);
      if(statusEl) statusEl.textContent = 'Extraction failed';
      alert('Extraction failed: ' + (err.message || String(err)));
    }
    btn.disabled = false;
  });
})();

function _renderPhase2BExtractionResult(result){
  var container = document.getElementById('batch-phase2b-extraction');
  var content = document.getElementById('batch-phase2b-extraction-content');
  if(!container || !content) return;
  container.style.display = 'block';

  if(!result || !result.results || result.results.length === 0){
    content.innerHTML = '<p class="sub" style="color:var(--muted);">No extraction results.</p>';
    return;
  }

  // Build extraction results table/cards
  var targets = result.extractionTargets || [];
  var html = '';

  // Header row
  html += '<div style="display:grid;grid-template-columns:180px ' + targets.map(function(){ return '1fr'; }).join(' ') + ';gap:1px;background:var(--border,#ddd);border-radius:6px;overflow:hidden;margin-bottom:12px;">';
  html += '<div style="padding:8px;background:var(--surface,#f5f5f5);font-weight:600;font-size:12px;">Document</div>';
  for(var ti = 0; ti < targets.length; ti++){
    var colors = ['#2a7', '#e67e22', '#3498db'];
    html += '<div style="padding:8px;background:var(--surface,#f5f5f5);font-weight:600;font-size:12px;border-left:3px solid ' + colors[ti] + ';">' + targets[ti].label + '</div>';
  }

  // Data rows
  for(var di = 0; di < result.results.length; di++){
    var docResult = result.results[di];
    var bgColor = di % 2 === 0 ? '#fff' : 'var(--surface,#fafafa)';
    var nameStyle = docResult.isReference ? 'font-weight:600;' : '';

    html += '<div style="padding:8px;background:' + bgColor + ';' + nameStyle + 'font-size:13px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="' + docResult.documentName + '">';
    html += docResult.documentName;
    if(docResult.isReference) html += ' <span style="font-size:10px;color:#2a7;">(ref)</span>';
    html += '</div>';

    for(var fi = 0; fi < docResult.fields.length; fi++){
      var f = docResult.fields[fi];
      var textDisplay = f.extractedText || '<span style="color:var(--muted);font-style:italic;">—</span>';
      var confColor = f.transferConfidence >= 0.7 ? '#2a7' : f.transferConfidence >= 0.4 ? '#b87e0a' : '#c44';

      html += '<div style="padding:8px;background:' + bgColor + ';font-size:13px;">';
      html += '<div style="margin-bottom:2px;">' + textDisplay + '</div>';
      html += '<div class="sub" style="font-size:10px;color:var(--muted);">';
      html += '<span style="color:' + confColor + ';">' + f.transferMethod.replace(/_/g, ' ') + '</span>';
      // Text source indicator (separate from transfer method)
      var ts = f.textSource || (f.tokenCount > 0 ? 'tokens' : 'no_tokens');
      var tsColor = ts === 'tokens' ? '#2a7' : ts === 'ocr_fallback' ? '#e67e22' : ts === 'tokens_sparse' ? '#b87e0a' : '#999';
      var tsLabel = ts === 'tokens' ? 'tokens' : ts === 'ocr_fallback' ? 'OCR fallback' : ts === 'tokens_sparse' ? 'sparse tokens' : 'no text';
      html += ' · <span style="color:' + tsColor + ';">' + tsLabel + '</span>';
      if(f.tokenCount > 0 && ts !== 'ocr_fallback') html += ' (' + f.tokenCount + ')';
      html += '</div></div>';
    }
  }
  html += '</div>';

  // Strategy and summary
  var strategy = result.extractionStrategy || 'unknown';
  var stratLabel = strategy === 'structure_based' ? 'Structure-Based (Primary)'
    : strategy === 'text_landmarks_fallback' ? 'Text Landmarks (Fallback)'
    : strategy.replace(/_/g, ' ');
  html += '<p class="sub" style="color:var(--muted);margin:4px 0;"><strong>Strategy:</strong> ' + stratLabel;
  if(result.landmarkSupplementApplied) html += ' + landmark supplement (' + (result.landmarkCount || 0) + ' landmarks)';
  html += '</p>';
  html += '<p class="sub" style="color:var(--muted);margin:4px 0;">' + result.message + '</p>';

  content.innerHTML = html;
}

// Export refinement report
(function(){
  var btn = document.getElementById('batch-phase2b-export-btn');
  if(!btn) return;
  btn.addEventListener('click', function(){
    if(!_phase2bState.refinementResult || !_learningAPI || !_learningAPI.formatRefinementReport){
      alert('No refinement data to export.');
      return;
    }
    var text = _learningAPI.formatRefinementReport(_phase2bState.refinementResult);
    var timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    var filename = 'wrokit-refinement-' + timestamp + '.txt';
    var blob = new Blob([text], { type: 'text/plain' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = filename;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a); URL.revokeObjectURL(url);
  });
})();

/* ── Phase 3A: Field Intelligence ─────────────────────────────────────── */

var _phase3aState = {
  corrections: [],       // Array of { documentId, documentName, fields: [{ fieldKey, correctedText, datatype }] }
  learningResult: null,  // Output from learnFieldGeometry
  extractionResult: null // Reference to Phase 2B extraction result
};

/** Populate the Phase 3A correction UI from extraction results. */
function _initPhase3ACorrections(extractionResult) {
  _phase3aState.extractionResult = extractionResult;
  _phase3aState.corrections = [];
  _phase3aState.learningResult = null;

  // Populate document selector
  var sel = document.getElementById('batch-phase3a-doc-select');
  if (!sel) return;
  sel.innerHTML = '<option value="">— Select a document —</option>';
  var results = extractionResult.results || [];
  for (var di = 0; di < results.length; di++) {
    var dr = results[di];
    var opt = document.createElement('option');
    opt.value = dr.documentId;
    opt.textContent = dr.documentName + (dr.isReference ? ' (ref)' : '');
    sel.appendChild(opt);
  }

  // Clear previous state
  var fieldsContainer = document.getElementById('batch-phase3a-fields-container');
  if (fieldsContainer) fieldsContainer.innerHTML = '';
  var corrFields = document.getElementById('batch-phase3a-correction-fields');
  if (corrFields) corrFields.style.display = 'none';
  var savedEl = document.getElementById('batch-phase3a-saved-corrections');
  if (savedEl) savedEl.innerHTML = '';
  var resultsPanel = document.getElementById('batch-phase3a-results');
  if (resultsPanel) resultsPanel.style.display = 'none';
  var learnBtn = document.getElementById('batch-phase3a-learn-btn');
  if (learnBtn) learnBtn.disabled = true;

  _renderPhase3ASavedCorrections();
}

/** Load correction fields for a selected document. */
function _loadPhase3ACorrectionFields(documentId) {
  var corrFields = document.getElementById('batch-phase3a-correction-fields');
  var container = document.getElementById('batch-phase3a-fields-container');
  var docLabel = document.getElementById('batch-phase3a-doc-label');
  if (!corrFields || !container || !_phase3aState.extractionResult) return;

  var docResult = _phase3aState.extractionResult.results.find(function (r) { return r.documentId === documentId; });
  if (!docResult) { corrFields.style.display = 'none'; return; }

  corrFields.style.display = 'block';
  if (docLabel) docLabel.textContent = docResult.documentName;

  var colors = ['#2a7', '#e67e22', '#3498db'];
  var datatypes = ['text', 'number', 'date', 'currency', 'identifier'];
  var html = '';

  for (var fi = 0; fi < docResult.fields.length; fi++) {
    var f = docResult.fields[fi];
    var color = colors[fi % colors.length];
    html += '<div class="batch-phase3a-field-row" data-field-key="' + f.fieldKey + '" style="margin-bottom:10px;padding:8px;border-left:3px solid ' + color + ';background:var(--surface,#fafafa);border-radius:0 6px 6px 0;">';
    html += '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">';
    html += '<strong style="font-size:13px;min-width:100px;">' + f.label + '</strong>';
    html += '<span class="sub" style="font-size:12px;color:var(--muted);min-width:120px;" title="Extracted value">Extracted: <em>' + (f.extractedText || '—') + '</em></span>';
    html += '</div>';
    html += '<div style="display:flex;gap:8px;align-items:center;margin-top:6px;flex-wrap:wrap;">';
    html += '<input type="text" class="batch-phase3a-correction-input" data-field-key="' + f.fieldKey + '" placeholder="Corrected value" value="" style="flex:1;min-width:150px;max-width:280px;font-size:13px;" />';
    html += '<select class="batch-phase3a-datatype-select" data-field-key="' + f.fieldKey + '" style="font-size:12px;max-width:120px;">';
    for (var dti = 0; dti < datatypes.length; dti++) {
      html += '<option value="' + datatypes[dti] + '">' + datatypes[dti] + '</option>';
    }
    html += '</select>';
    html += '</div>';
    html += '</div>';
  }

  container.innerHTML = html;

  // Add hover highlight behavior for correction fields
  var rows = container.querySelectorAll('.batch-phase3a-field-row');
  for (var ri = 0; ri < rows.length; ri++) {
    rows[ri].addEventListener('mouseenter', function () { this.style.outline = '2px solid #2a7'; });
    rows[ri].addEventListener('mouseleave', function () { this.style.outline = ''; });
  }
}

/** Render saved corrections list. */
function _renderPhase3ASavedCorrections() {
  var el = document.getElementById('batch-phase3a-saved-corrections');
  if (!el) return;

  if (_phase3aState.corrections.length === 0) {
    el.innerHTML = '<p class="sub" style="color:var(--muted);font-size:12px;margin:4px 0;">No corrections saved yet. Select documents and correct their extracted values.</p>';
    return;
  }

  var html = '<div style="font-size:12px;margin-bottom:8px;">';
  html += '<strong>Saved Corrections (' + _phase3aState.corrections.length + ' document(s)):</strong>';
  html += '</div>';

  for (var ci = 0; ci < _phase3aState.corrections.length; ci++) {
    var c = _phase3aState.corrections[ci];
    html += '<div style="padding:6px 8px;margin-bottom:4px;background:var(--surface,#f5f5f5);border-radius:4px;font-size:12px;display:flex;justify-content:space-between;align-items:center;">';
    html += '<span>' + c.documentName + ' — ' + c.fields.length + ' field(s) corrected</span>';
    html += '<button class="btn ghost batch-phase3a-remove-correction" data-doc-id="' + c.documentId + '" style="font-size:11px;padding:2px 6px;" type="button">Remove</button>';
    html += '</div>';
  }

  el.innerHTML = html;

  // Bind remove buttons
  var removeBtns = el.querySelectorAll('.batch-phase3a-remove-correction');
  for (var ri = 0; ri < removeBtns.length; ri++) {
    removeBtns[ri].addEventListener('click', function () {
      var docId = this.getAttribute('data-doc-id');
      _phase3aState.corrections = _phase3aState.corrections.filter(function (c) { return c.documentId !== docId; });
      _renderPhase3ASavedCorrections();
      var learnBtn = document.getElementById('batch-phase3a-learn-btn');
      if (learnBtn) learnBtn.disabled = _phase3aState.corrections.length === 0;
    });
  }
}

/** Render Phase 3A geometry learning results. */
function _renderPhase3AResults(result) {
  var panel = document.getElementById('batch-phase3a-results');
  var statusEl = document.getElementById('batch-phase3a-results-status');
  var profileCountEl = document.getElementById('batch-phase3a-profile-count');
  var profilesContent = document.getElementById('batch-phase3a-profiles-content');
  var detailsContent = document.getElementById('batch-phase3a-details-content');
  if (!panel) return;

  panel.style.display = 'block';
  if (statusEl) statusEl.textContent = result.status === 'improved' ? 'Geometry improved' : 'No improvement';
  if (profileCountEl) profileCountEl.textContent = result.fieldProfiles.length;

  // Render field profiles
  if (profilesContent) {
    var html = '';
    for (var pi = 0; pi < result.fieldProfiles.length; pi++) {
      var p = result.fieldProfiles[pi];
      var statusColor = p.improvedCount > 0 ? '#2a7' : '#999';
      html += '<div style="padding:8px;margin-bottom:8px;border:1px solid var(--border,#ddd);border-radius:6px;background:#fff;">';
      html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;">';
      html += '<strong style="font-size:13px;">' + p.label + '</strong>';
      html += '<span style="font-size:11px;color:' + statusColor + ';">' + p.improvedCount + '/' + p.correctionCount + ' improved</span>';
      html += '</div>';
      html += '<div class="sub" style="font-size:11px;color:var(--muted);">';
      html += 'Offset: dx=' + (p.preferredOffset.dx * 100).toFixed(2) + '%, dy=' + (p.preferredOffset.dy * 100).toFixed(2) + '% · ';
      html += 'Expansion: dw=' + (p.preferredExpansion.dw * 100).toFixed(2) + '%, dh=' + (p.preferredExpansion.dh * 100).toFixed(2) + '% · ';
      html += 'Confidence: ' + (p.geometryConfidence * 100).toFixed(1) + '% · ';
      html += 'Best: ' + p.dominantFamily.replace(/_/g, ' ');
      html += '</div>';
      html += '</div>';
    }
    profilesContent.innerHTML = html || '<p class="sub" style="color:var(--muted);">No profiles generated.</p>';
  }

  // Render per-document details
  if (detailsContent) {
    var dhtml = '';
    for (var di = 0; di < result.perDocumentResults.length; di++) {
      var dr = result.perDocumentResults[di];
      dhtml += '<div style="margin-bottom:8px;">';
      dhtml += '<strong style="font-size:12px;">' + dr.documentName + '</strong>';
      for (var fi = 0; fi < dr.fields.length; fi++) {
        var f = dr.fields[fi];
        var fColor = f.improved ? '#2a7' : '#999';
        dhtml += '<div class="sub" style="font-size:11px;margin-left:12px;color:var(--muted);">';
        dhtml += f.label + ': <span style="color:' + fColor + ';">';
        if (f.improved) {
          dhtml += 'improved +' + (f.improvement * 100).toFixed(1) + '% → ' + (f.bestCandidate ? f.bestCandidate.family.replace(/_/g, ' ') : '');
        } else {
          dhtml += 'original optimal';
        }
        dhtml += '</span>';
        dhtml += '</div>';
      }
      dhtml += '</div>';
    }
    detailsContent.innerHTML = dhtml || '<p class="sub" style="color:var(--muted);">No details available.</p>';
  }
}

// Phase 3A: Document selector
(function () {
  var sel = document.getElementById('batch-phase3a-doc-select');
  if (!sel) return;
  sel.addEventListener('change', function () {
    var docId = sel.value;
    if (docId) {
      _loadPhase3ACorrectionFields(docId);
    } else {
      var corrFields = document.getElementById('batch-phase3a-correction-fields');
      if (corrFields) corrFields.style.display = 'none';
    }
  });
})();

// Phase 3A: View Document button
(function () {
  var btn = document.getElementById('batch-phase3a-view-doc-btn');
  if (!btn) return;
  btn.addEventListener('click', function () {
    var sel = document.getElementById('batch-phase3a-doc-select');
    if (!sel || !sel.value) { alert('Select a document first.'); return; }
    var docId = sel.value;
    var dataUrl = null;
    // Find document name from extraction result
    if (_phase3aState.extractionResult) {
      var dr = _phase3aState.extractionResult.results.find(function (r) { return r.documentId === docId; });
      if (dr) dataUrl = _batchCanvasStore[dr.documentName];
    }
    if (!dataUrl) { alert('Document image not available.'); return; }
    // Open image in new window with BBOX overlay
    var win = window.open('', '_blank', 'width=800,height=1000');
    if (!win) return;
    var fields = _phase3aState.extractionResult.results.find(function (r) { return r.documentId === docId; });
    var colors = ['#2a7', '#e67e22', '#3498db'];
    var svgOverlays = '';
    if (fields) {
      for (var fi = 0; fi < fields.fields.length; fi++) {
        var f = fields.fields[fi];
        var nb = f.transferredNormBox;
        var c = colors[fi % colors.length];
        svgOverlays += '<rect x="' + (nb.x0n * 100) + '%" y="' + (nb.y0n * 100) + '%" width="' + (nb.wN * 100) + '%" height="' + (nb.hN * 100) + '%" fill="' + c + '" fill-opacity="0.15" stroke="' + c + '" stroke-width="2" />';
        svgOverlays += '<text x="' + (nb.x0n * 100) + '%" y="' + (nb.y0n * 100 - 0.5) + '%" fill="' + c + '" font-size="12" font-weight="bold">' + f.label + '</text>';
      }
    }
    win.document.write('<!DOCTYPE html><html><head><title>Document Viewer</title></head><body style="margin:0;background:#222;display:flex;justify-content:center;align-items:flex-start;">' +
      '<div style="position:relative;display:inline-block;max-width:100%;">' +
      '<img src="' + dataUrl + '" style="max-width:100%;display:block;" />' +
      '<svg style="position:absolute;top:0;left:0;width:100%;height:100%;">' + svgOverlays + '</svg>' +
      '</div></body></html>');
    win.document.close();
  });
})();

// Phase 3A: Save Correction button
(function () {
  var btn = document.getElementById('batch-phase3a-save-correction-btn');
  if (!btn) return;
  btn.addEventListener('click', function () {
    var sel = document.getElementById('batch-phase3a-doc-select');
    if (!sel || !sel.value) { alert('Select a document first.'); return; }
    var docId = sel.value;
    var docResult = _phase3aState.extractionResult && _phase3aState.extractionResult.results.find(function (r) { return r.documentId === docId; });
    if (!docResult) return;

    var inputs = document.querySelectorAll('.batch-phase3a-correction-input');
    var datatypeSelects = document.querySelectorAll('.batch-phase3a-datatype-select');
    var correctedFields = [];

    for (var i = 0; i < inputs.length; i++) {
      var fieldKey = inputs[i].getAttribute('data-field-key');
      var correctedText = inputs[i].value.trim();
      if (!correctedText) continue; // Skip empty corrections
      var datatype = 'text';
      for (var dsi = 0; dsi < datatypeSelects.length; dsi++) {
        if (datatypeSelects[dsi].getAttribute('data-field-key') === fieldKey) {
          datatype = datatypeSelects[dsi].value;
          break;
        }
      }
      correctedFields.push({ fieldKey: fieldKey, correctedText: correctedText, datatype: datatype });
    }

    if (correctedFields.length === 0) {
      alert('Enter at least one correction.');
      return;
    }

    // Remove existing correction for this doc if any, then add new
    _phase3aState.corrections = _phase3aState.corrections.filter(function (c) { return c.documentId !== docId; });
    _phase3aState.corrections.push({
      documentId: docId,
      documentName: docResult.documentName,
      fields: correctedFields
    });

    _renderPhase3ASavedCorrections();

    var learnBtn = document.getElementById('batch-phase3a-learn-btn');
    if (learnBtn) learnBtn.disabled = _phase3aState.corrections.length === 0;

    var statusEl = document.getElementById('batch-phase3a-correction-status');
    if (statusEl) statusEl.textContent = 'Saved ' + correctedFields.length + ' correction(s)';
    setTimeout(function () { if (statusEl) statusEl.textContent = ''; }, 3000);
  });
})();

// Phase 3A: Clear Corrections button
(function () {
  var btn = document.getElementById('batch-phase3a-clear-corrections-btn');
  if (!btn) return;
  btn.addEventListener('click', function () {
    _phase3aState.corrections = [];
    _renderPhase3ASavedCorrections();
    var learnBtn = document.getElementById('batch-phase3a-learn-btn');
    if (learnBtn) learnBtn.disabled = true;
    var resultsPanel = document.getElementById('batch-phase3a-results');
    if (resultsPanel) resultsPanel.style.display = 'none';
  });
})();

// Phase 3A: Learn Geometry button
(function () {
  var btn = document.getElementById('batch-phase3a-learn-btn');
  if (!btn) return;
  btn.addEventListener('click', function () {
    if (!_phase3aState.corrections.length || !_phase3aState.extractionResult) {
      alert('Save corrections for at least one document first.');
      return;
    }
    if (!_learningAPI || !_learningAPI.learnFieldGeometry) {
      alert('Learning API not available.');
      return;
    }
    if (!_batchStore || !_activeBatchSessionId) return;
    var session = _batchStore.getSession(_activeBatchSessionId);
    if (!session) return;

    var refDocId = _phase2bState.correspondenceResult && _phase2bState.correspondenceResult.referenceDocument.documentId;
    var refDoc = refDocId ? session.documents.find(function (d) { return d.documentId === refDocId; }) : null;

    var batchTokens = _getBatchTokens(_activeBatchSessionId);
    var statusEl = document.getElementById('batch-phase3a-status');
    if (statusEl) statusEl.textContent = 'Learning geometry...';
    btn.disabled = true;

    setTimeout(function () {
      try {
        var result = _learningAPI.learnFieldGeometry(
          _phase3aState.extractionResult,
          _phase3aState.corrections,
          batchTokens,
          refDoc
        );

        _phase3aState.learningResult = result;
        _renderPhase3AResults(result);

        // Save geometry profiles to session store
        if (result.fieldProfiles && result.fieldProfiles.length > 0 && _batchStore.saveGeometryProfiles) {
          _batchStore.saveGeometryProfiles(_activeBatchSessionId, result.fieldProfiles);
        }

        if (statusEl) statusEl.textContent = result.status === 'improved' ? 'Geometry improved' : 'No improvement found';
      } catch (err) {
        console.error('[Phase3A] Geometry learning failed:', err);
        if (statusEl) statusEl.textContent = 'Learning failed';
        alert('Geometry learning failed: ' + (err.message || String(err)));
      }
      btn.disabled = false;
    }, 50);
  });
})();

// Phase 3A: Export Geometry Report
(function () {
  var btn = document.getElementById('batch-phase3a-export-btn');
  if (!btn) return;
  btn.addEventListener('click', function () {
    if (!_phase3aState.learningResult || !_learningAPI || !_learningAPI.formatGeometryReport) {
      alert('No geometry learning data to export.');
      return;
    }
    var text = _learningAPI.formatGeometryReport(_phase3aState.learningResult);
    var timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
    var filename = 'wrokit-geometry-' + timestamp + '.txt';
    var blob = new Blob([text], { type: 'text/plain' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = filename;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a); URL.revokeObjectURL(url);
  });
})();

